-- Poems batch 353
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('93a1fe2c-bafa-475c-8e22-0be7d0335982','晨至石碣院時喪女殯此院二首  其一','周行己','宋','宋诗','song-poetry','','[]','蕭寺來人少，祇林過雨清。',48,'全唐诗/poet.song.71000.json','["蕭寺來人少，祇林過雨清。", "日光微破影，雲色未全晴。", "久客嗟殊俗，中年哭後生。", "庭前空柏子，此意復誰明。"]'),
('e8e4bb8a-d9ef-43d1-8c15-2f052a2aeda0','晨至石碣院時喪女殯此院二首  其二','周行己','宋','宋诗','song-poetry','','[]','曉色初明野，雲容尚隠林。',48,'全唐诗/poet.song.71000.json','["曉色初明野，雲容尚隠林。", "蒿萊三徑拙，鳥雀一枝深。", "憂患他鄉淚，淹留故國心。", "平生丘壑趣，衰謝媿同襟。"]'),
('3b7e5c88-d56c-4ac6-8579-d51f4414bde2','送王天粹登第歸','周行己','宋','宋诗','song-poetry','','[]','王氏青箱學，名家千里駒。',48,'全唐诗/poet.song.71000.json','["王氏青箱學，名家千里駒。", "朝廷求士急，吾子應時須。", "上第人皆有，高才世久虛。", "別君誰暖眼，書信莫令疏。"]'),
('5072bc7d-e036-4981-815c-92de51e6c0a2','奉和林惠叔  其一','周行己','宋','宋诗','song-poetry','','[]','攝邑聊觀政，無才可及人。',48,'全唐诗/poet.song.71000.json','["攝邑聊觀政，無才可及人。", "案書捐吏役，簷日遂吾真。", "聽說桑麻好，懽言雨露新。", "貧居願時熟，聊試甑中塵。"]'),
('fa18d3ff-cdec-4ce5-8a0f-257b47ede97f','奉和林惠叔  其二','周行己','宋','宋诗','song-poetry','','[]','世間同大宅，何處是安居。',48,'全唐诗/poet.song.71000.json','["世間同大宅，何處是安居。", "卧地有知足，棲巢亦晏如。", "松楸懷舊隠，城市遠先廬。", "衰病難堪責，交遊喜漸疏。"]'),
('7866cf40-1b21-42fa-b728-b84fddea6722','書王仲元都巡城上小亭','周行己','宋','宋诗','song-poetry','','[]','王子吹簫處，孤城城上臺。',48,'全唐诗/poet.song.71000.json','["王子吹簫處，孤城城上臺。", "回回衆山入，隠隠一川來。", "花草三春合，軒窗四面開。", "得官兼吏隠，端復謝塵埃。"]'),
('5e1f08eb-fb56-492b-b0fc-1cc62369503a','原武喪女有感  其一','周行己','宋','宋诗','song-poetry','','[]','人世剎那頃，汝身能幾秋。',48,'全唐诗/poet.song.71000.json','["人世剎那頃，汝身能幾秋。", "一生如夢了，萬事蓋棺休。", "年老不禁哭，夜長都是愁。", "棄置復棄置，千古共山丘。"]'),
('4e23356c-6364-49ea-8535-578435744061','原武喪女有感  其二','周行己','宋','宋诗','song-poetry','','[]','飄零同逆旅，生死異前途。',48,'全唐诗/poet.song.71000.json','["飄零同逆旅，生死異前途。", "恩愛此生斷，聲容昨夢餘。", "幻身今墮甑，戲事已陳芻。", "寂滅真爲樂，勞勞得爾如。"]'),
('ebdf727f-84a7-4532-baf5-1430e23b19fc','秋霽分韵得中字','周行己','宋','宋诗','song-poetry','','[]','清晚搔頭望，晴天已不同。',48,'全唐诗/poet.song.71000.json','["清晚搔頭望，晴天已不同。", "霽烟才冉冉，雨意却濛濛。", "爲客艱難裏，思親涕淚中。", "獨憑心事在，倚杖看秋鴻。"]'),
('10eb7815-1a71-47c0-93b9-d6c597dee584','春日郊行','周行己','宋','宋诗','song-poetry','','[]','野步春郊浄，佳遊病眼開。',48,'全唐诗/poet.song.71000.json','["野步春郊浄，佳遊病眼開。", "風流可憐柳，零落不堪梅。", "水接仙舟泛，山紆俗駕回。", "歸歟月已沒，餘興更登臺。"]'),
('2a87833d-4bdd-4f44-9828-f172ca790f37','聞官軍捷報呈彥升時仲','周行己','宋','宋诗','song-poetry','','[]','滯雨春惟冷，端憂夜更長。',48,'全唐诗/poet.song.71000.json','["滯雨春惟冷，端憂夜更長。", "曲肱思已亂，如面世難防。", "捷報聞平寇，安書喜到鄉。", "鹿門心未遂，誰與論行藏。"]'),
('3122d0c6-b97e-4924-b24c-54db6ec5b7a2','壽郡守','周行己','宋','宋诗','song-poetry','','[]','仙系蘇門遠，英流富緒長。',192,'全唐诗/poet.song.71000.json','["仙系蘇門遠，英流富緒長。", "胚胎潜間氣，庭玉煥祥光。", "永日輝南陸，融風麗北堂。", "綵餘長命縷，香剩浴蘭湯。", "丹穴皆威鳳，荆山必豫章。", "精神森秀發，器質儼溫良。", "懿學傳經濟，嘉猷合贊襄。", "慶流多顯赫，筮仕早騰驤。", "遊刃無間劇，提衡絕否臧。", "高情薰愛日，勁節肅清霜。", "暫借朱轓出，行看皂纛揚。", "頌聲喧道路，輿望屬巖廊。", "時遇生申旦，官臨指李鄉。", "衆真金闕奏，滿郡玉爐香。", "强仕春秋富，昌朝事業芳。", "臣千君萬壽，賡載濟時芳。"]'),
('529b0152-4787-4d78-a74a-7f9e000b9e1f','原武祈雨有應呈諸同僚','周行己','宋','宋诗','song-poetry','','[]','嗷嗷憂旱魃，懇懇叩神祠。',120,'全唐诗/poet.song.71000.json','["嗷嗷憂旱魃，懇懇叩神祠。", "自疏官多曠，無辜歲莫饑。", "奇峰俄變黑，甘液遽如篩。", "雷電寧無物，風雲自有師。", "荒郊回沃壤，榮穗發萎枝。", "攝邑乖爲政，同僚實副時。", "民心惟禮義，邦本繫安危。", "食足無他事，恩餘及我私。", "白看雲子粒，滑想杜陵匙。", "拂拭萊蕪甑，香炊定可期。"]'),
('229be6ee-c850-4a72-9436-dc5119ec2780','壽沈守','周行己','宋','宋诗','song-poetry','','[]','三甲三壬五福俱，胸中落落貯瓊琚。',64,'全唐诗/poet.song.71000.json','["三甲三壬五福俱，胸中落落貯瓊琚。", "池塘芳草詩情遠，富貴浮雲世事疏。", "一郡壽爐薰愛日，層霄仙籍寄真書。", "君王萬億臣千億，永作天官拱帝居。"]'),
('fffde8ff-b321-4a8d-b733-ef3b01d69db0','壽時相三首  其一','周行己','宋','宋诗','song-poetry','','[]','皇天祐德必生賢，尊主功高五帝前。',64,'全唐诗/poet.song.71000.json','["皇天祐德必生賢，尊主功高五帝前。", "嶽骨昴精來間氣，彭齡聃壽與遐年。", "遠無憂患身先退，近有湖山樂更全。", "祇恐蒼生須謝傅，每聞人誦衮衣篇。"]'),
('80a32684-ebdf-47cd-91b4-7b1254b09265','壽時相三首  其二','周行己','宋','宋诗','song-poetry','','[]','每聞人誦衮衣篇，又值君臣慶會年。',64,'全唐诗/poet.song.71000.json','["每聞人誦衮衣篇，又值君臣慶會年。", "臘雪已先調鼎實，春風還是作霖天。", "經綸道自心源出，損益時隨世變遷。", "當宁旰宵懷舊德，非公誰與濟商川。"]'),
('376d39ed-fbfa-437a-97df-547ee63117d1','壽時相三首  其三','周行己','宋','宋诗','song-poetry','','[]','非公誰與濟商川，年德俱隆文武全。',64,'全唐诗/poet.song.71000.json','["非公誰與濟商川，年德俱隆文武全。", "省事省官民自定，足兵足食務當先。", "烹鮮取治惟無擾，置器期安在不偏。", "公壽且千君且萬，四方永永樂堯年。"]'),
('c963c4fd-8929-4f14-9046-c1466f5f8c0b','次僧曇隠謝見臨韵二首  其一','周行己','宋','宋诗','song-poetry','','[]','倦雲小息五公山，來往扁舟勝據鞍。',64,'全唐诗/poet.song.71000.json','["倦雲小息五公山，來往扁舟勝據鞍。", "强飯未能追馬革，寄餐端恐識豬肝。", "山泉周匝流清泚，古木森羅照屈蟠。", "獨卧北窗懷太古，元無一物到門闌。"]'),
('941addc5-f177-4c6a-92cd-113a42872c08','次僧曇隠謝見臨韵二首  其二','周行己','宋','宋诗','song-poetry','','[]','隱跡僧居無所爲，蒲團曲几面清池。',64,'全唐诗/poet.song.71000.json','["隱跡僧居無所爲，蒲團曲几面清池。", "一身有累須三逕，萬物無私各四時。", "心與溪山相宛轉，事隨塵世漫紛披。", "山中不用詩招隠，已約施巖采紫芝。"]'),
('100703e6-a027-4954-83df-dbec2688b153','几山出示陽橋唱和諸什竊慨英才之沈寂光景之流邁因兩次其韵皆以少日爲篇首一以贈監鎮孫和仲一以贈知丞苗几山云  其一','周行己','宋','宋诗','song-poetry','','[]','少日稱豪弓馬場，時平不復戍漁陽。',64,'全唐诗/poet.song.71000.json','["少日稱豪弓馬場，時平不復戍漁陽。", "引杯看劍夜雲黑，橫槊賦詩寒日黄。", "霜落草枯閒戰騎，位卑祿薄困征商。", "白頭未試吳王妓，楊柳蕭蕭古道傍。"]'),
('0275f13e-e683-4637-826b-76939ae8d573','几山出示陽橋唱和諸什竊慨英才之沈寂光景之流邁因兩次其韵皆以少日爲篇首一以贈監鎮孫和仲一以贈知丞苗几山云  其二','周行己','宋','宋诗','song-poetry','','[]','少日稱豪筆硯場，一官家近住河陽。',64,'全唐诗/poet.song.71000.json','["少日稱豪筆硯場，一官家近住河陽。", "人情易變春雲薄，世故飽諳秋鬢黄。", "寒日蒼凉臨迥野，浩歌悲壯激哀商。", "時平民樂官無事，醉倒題詩舞袖傍。"]'),
('2b113424-d702-40ed-8a07-263484539ea5','子固嘉夫相過觀几山唱和','周行己','宋','宋诗','song-poetry','','[]','萬事都將笑一場，不如載酒訪高陽。',64,'全唐诗/poet.song.71000.json','["萬事都將笑一場，不如載酒訪高陽。", "凍消地面可憐綠，日暖楊枝無奈黄。", "尚德久從君子魯，言詩仍有起予商。", "太平無事閒居樂，且醉高樓大道傍。"]'),
('b1ab2b85-91d0-4cde-995f-376da46a101d','再和子固','周行己','宋','宋诗','song-poetry','','[]','老年不入少年場，不似當時在洛陽。',64,'全唐诗/poet.song.71000.json','["老年不入少年場，不似當時在洛陽。", "福善坡頭回曳練，石家寺裏看姚黄。", "春風楊柳東西陌，古道樓臺南北商。", "流落如今歸未得，白頭憔悴卷城傍。"]'),
('9725084b-5360-499d-ba1d-c51c87ace14a','嘉夫再有冰玉交輝佳句復和酬報','周行己','宋','宋诗','song-poetry','','[]','爛爛雙瞳掣電光，照人皮裏有秋陽。',64,'全唐诗/poet.song.71000.json','["爛爛雙瞳掣電光，照人皮裏有秋陽。", "誰將鼠腊同蒼璧，枉把鹽車服乘黄。", "合有猷謀陳稷契，即看灝噩繼周商。", "近來佳句驚人甚，敢竝蒹葭玉樹傍。"]'),
('b16a20ad-7280-404a-8b1c-ac724c4f807e','和李文叔見招','周行己','宋','宋诗','song-poetry','','[]','杜曲林泉可寄年，功名富貴有危顛。',64,'全唐诗/poet.song.71000.json','["杜曲林泉可寄年，功名富貴有危顛。", "囊中佳句渾輕與，海內名方莫浪傳。", "赤脚拏舟能楚些，明眸度曲解回旋。", "且過叔度留終日，未問他年騎錦韉。"]'),
('303b2368-69d4-44a8-a4fc-60ce802dd07e','再和文叔','周行己','宋','宋诗','song-poetry','','[]','事業功名看百年，千杯醉墨謾張顛。',64,'全唐诗/poet.song.71000.json','["事業功名看百年，千杯醉墨謾張顛。", "關西夫子時方棄，稷下諸儒誰與傳。", "契闊十年纔道舊，間關千里又言旋。", "飄萍斷梗無根柢，愁喚羸童理破韉。"]'),
('1b19b173-746b-45fe-9ace-2b36e46fece2','病中思歸呈千之十七兄','周行己','宋','宋诗','song-poetry','','[]','白首遑遑謾世憂，我今問米下揚州。',64,'全唐诗/poet.song.71000.json','["白首遑遑謾世憂，我今問米下揚州。", "支離病骨難堪暑，浩蕩歸心不待秋。", "兵火彫零餘故里，功名衰謝獨扁舟。", "腐儒老死終無用，收拾綸竿好去休。"]'),
('9780ae15-bf44-4016-903e-221427d6e6d9','再用前韵趣歸','周行己','宋','宋诗','song-poetry','','[]','故鄉何處海東頭，地盡東南最勝州。',64,'全唐诗/poet.song.71000.json','["故鄉何處海東頭，地盡東南最勝州。", "水陸歸程幾百驛，風塵回首恰三秋。", "無才北使能降敵，决意東歸已辦舟。", "去國不緣明主棄，只緣多病更宜休。"]'),
('c6452013-22ff-4c1d-901c-3bce5ea336a4','和孫德平病秋思歸','周行己','宋','宋诗','song-poetry','','[]','春雨秋風無盡期，鳶飛魚躍各天機。',64,'全唐诗/poet.song.71000.json','["春雨秋風無盡期，鳶飛魚躍各天機。", "年光逝水催前浪，世事浮雲換白衣。", "草木變衰知節改，田園蕪沒要吾歸。", "人生萬事惟心可，真處何妨世俗譏。"]'),
('06bf93bc-8d8f-43d5-9671-2b3229850674','奉和知丞苗几山','周行己','宋','宋诗','song-poetry','','[]','陸沈僚底惘騤瞿，玩世滑稽常自如。',64,'全唐诗/poet.song.71000.json','["陸沈僚底惘騤瞿，玩世滑稽常自如。", "鞍馬猶堪供矍鑠，功名誰復念居諸。", "胸懷金玉天知我，仕宦風波丞負予。", "尊酒夜闌聽軟語，清談笑謔極羣書。"]'),
('9238f5ad-50db-4bc0-b7f4-ba200cf5f11b','和使君閔雨','周行己','宋','宋诗','song-poetry','','[]','布穀催耕候已深，驕陽未肯化爲霖。',64,'全唐诗/poet.song.71000.json','["布穀催耕候已深，驕陽未肯化爲霖。", "一年鈴閣傳齋禁，三月花時負賞心。", "空谷靈湫能奮響，叢祠古木已成陰。", "侏儒飽死渾無計，屬耳頹牆聽雨音。"]'),
('cadf9b47-cdbf-45a5-845f-bc917962bf96','次胡志衡韵','周行己','宋','宋诗','song-poetry','','[]','城北城南春渺然，幅巾藜杖望晴天。',64,'全唐诗/poet.song.71000.json','["城北城南春渺然，幅巾藜杖望晴天。", "何須多事途窮哭，莫倚高才甕下眠。", "渭水來從鳥鼠穴，隴山真接首陽巔。", "登臨未盡牛羊下，安得羲和叱馭旋。"]'),
('7fe19218-3a19-4aeb-b0aa-6682a4463c22','和蔡八十約同歸','周行己','宋','宋诗','song-poetry','','[]','十年塵土送春衣，每見春風憶翠微。',64,'全唐诗/poet.song.71000.json','["十年塵土送春衣，每見春風憶翠微。", "射策决科知已誤，求田問舍早須歸。", "人生豈料長身健，行李還應與願違。", "遥望故山心獨往，杖藜三嘆暮雲飛。"]'),
('51e23eff-f47e-4daf-ace3-9c7c5f3a9415','再和蔡八十約歸','周行己','宋','宋诗','song-poetry','','[]','聞說尋山意已清，况逢佳客作山行。',64,'全唐诗/poet.song.71000.json','["聞說尋山意已清，况逢佳客作山行。", "百年心事同杯酒，萬里春風出帝城。", "秋燕欲歸棲集穩，春鷗無事往來輕。", "風流定是輸陶謝，應笑癡人似步兵。"]'),
('e8cf1205-2b5b-4bdd-ad1a-3ce3e9b1c706','蘭溪驛','周行己','宋','宋诗','song-poetry','','[]','小雨滋春態，餘花落晚香。',24,'全唐诗/poet.song.71000.json','["小雨滋春態，餘花落晚香。", "扁舟還獨往，誰與論行藏。"]'),
