('c52516f3-b298-4710-8410-2cd9cdb16adc','示提壺','周行己','宋','宋诗','song-poetry','','[]','藜杖芒鞋一幅巾，翛然無事可關身。',32,'全唐诗/poet.song.71000.json','["藜杖芒鞋一幅巾，翛然無事可關身。", "一壺任醉春長在，南北東西作主人。"]'),
('85f93bdc-5b41-40da-a043-ec955a326f65','武陵烟雨','周行己','宋','宋诗','song-poetry','','[]','桃花流水武陵源，烟雨冥冥暗一川。',32,'全唐诗/poet.song.71000.json','["桃花流水武陵源，烟雨冥冥暗一川。", "試問山中避秦者，不知此景是何年。"]'),
('49a95295-7801-448d-876e-32b5c04a8741','次邢元輔知府韵二首  其一','周行己','宋','宋诗','song-poetry','','[]','飄零南北道，祇爲草堂留。',48,'全唐诗/poet.song.71000.json','["飄零南北道，祇爲草堂留。", "佳句堪排悶，端居正復愁。", "何年尋舊壑，無路借前籌。", "擬訪乘槎客，真仙不可求。"]'),
('2248d28a-1628-4aca-af39-29ea95c604d4','次邢元輔知府韵二首  其二','周行己','宋','宋诗','song-poetry','','[]','高齋連大厦，安隠客心舒。',48,'全唐诗/poet.song.71000.json','["高齋連大厦，安隠客心舒。", "每發難逢笑，時翻未見書。", "艱難恩意重，零落舊游疏。", "欲買西河地，終焉此荷鋤。"]'),
('0c0eb109-b0fa-4fda-8dbe-9556bd907474','香爐峰','周行己','宋','宋诗','song-poetry','','[]','護國門前似匡阜，雲峰路上認香爐。',32,'全唐诗/poet.song.71000.json','["護國門前似匡阜，雲峰路上認香爐。", "重重妄想雖堪嘆，也勝塵埃看畫圖。"]'),
('58990c28-f0f4-42dd-af82-e92ad7692231','坡南塘','周行己','宋','宋诗','song-poetry','','[]','滎陽居士居罕出，高堂華厦安於山。',64,'全唐诗/poet.song.71000.json','["滎陽居士居罕出，高堂華厦安於山。", "人自墊溺豈關我，乃復辛苦事所難。", "徒杠未成天欲寒，風吹溱洧波漫漫。", "安得亟語賢刺史，刺史愛民如赤子。"]'),
('37d6fd24-058f-4d46-87e3-9567b931b655','古意','周行己','宋','宋诗','song-poetry','','[]','南山有玄豹，七日不下食。',48,'全唐诗/poet.song.71000.json','["南山有玄豹，七日不下食。", "欲澤雨露潔，成彼文章飾。", "皮成爲身菑，不如生羽翼。", "只愁羽翼成，復遭羅且弋。"]'),
('69b6fc84-1f50-4e2d-a1c4-2e11685ecfc5','鍾離中散草書','周行己','宋','宋诗','song-poetry','','[]','學書如學禪，心悟筆自到。',144,'全唐诗/poet.song.71000.json','["學書如學禪，心悟筆自到。", "若非賢達人，安能字畫妙。", "鳥跡不必傳，篆籀亦異好。", "草聖實奇偉，變化不可料。", "張顛號神特，酒酣一脫帽。", "要識善用心，乃知皆同調。", "近世有鍾離，筆力絕能紹。", "不必衛夫人，自是過逸少。", "浩如觀波瀾，劃見鯨尾掉。", "宛轉或游龍，突兀忽峰峭。", "精逸一何有，信是得其奧。", "豈但揮端毫，亦足見風操。"]'),
('8edaf19f-394a-4c1c-b06e-4b3ed9a82d0c','出都門','周行己','宋','宋诗','song-poetry','','[]','攘攘宇宙內，經營固多端。',144,'全唐诗/poet.song.71000.json','["攘攘宇宙內，經營固多端。", "有求皆勞生，此身豈能安。", "艱難出都門，所歷百辛酸。", "秣馬臨遠道，欲去復盤桓。", "久客人情深，决別淚汍瀾。", "親知無別語，勸我但加餐。", "去去忍回首，西望路漫漫。", "緬懷白雲下，矯首時獨看。", "平生扁舟興，來此事征鞍。", "來時顔色好，歸時衣裳寬。", "上馬不能恨，下馬不敢嘆。", "但願還家樂，不辭行路難。"]'),
('9cf2fc2e-18ab-4eb8-aba4-b75509d89d45','題永寧傳舍','周行己','宋','宋诗','song-poetry','','[]','浩浩車馬迹，往來各有求。',168,'全唐诗/poet.song.71000.json','["浩浩車馬迹，往來各有求。", "而我亦何爲，行役不得休。", "驚風吹沙礫，草木春不柔。", "荒山相經互，渭水日悠悠。", "下馬古驛亭，開軒竹修修。", "颯颯爽氣入，得慰征途憂。", "移床取一息，摵摵如清秋。", "永願息鞍馬，何當具扁舟。", "我生湖海間，築居必清幽。", "城南五畝宅，山高水亦流。", "家園千木奴，不貴萬戶侯。", "既輸東皋稅，一飽亦易謀。", "藐然塵囂外，榮貴如浮漚。", "咄咄狂癡子，胡爲此淹留。"]'),
('21e61bfc-ac09-4d2b-829c-5f8029c8341f','謝黄襲明吳君寶見訪','周行己','宋','宋诗','song-poetry','','[]','平生敬愛人，經月不一面。',96,'全唐诗/poet.song.71000.json','["平生敬愛人，經月不一面。", "出處各有道，淡泊終所願。", "避喧繁臺寺，稍息奔走賤。", "豈是蔣詡人，佳客來不倦。", "不責禮數優，草草具盤饌。", "爲歌朱絲弦，知音我所戀。", "日暮翩然去，思君情如綫。", "乘興還一來，慎莫比秋扇。"]'),
('5e688fd2-3ec5-4c7f-86ea-caafad4e1996','送王六簿康朝之長安','周行己','宋','宋诗','song-poetry','','[]','君官洛水北，門前是官路。',72,'全唐诗/poet.song.71000.json','["君官洛水北，門前是官路。", "官路塵土多，君行向何處。", "晨朝束行李，西望長安樹。", "慘慘寒風吹，行人不敢顧。", "古來行路難，君行慎許與。", "故人日已新，新人即復故。"]'),
('110b5bb9-fdf8-40bf-a7c4-83f1973dda57','次韵張才叔蔡天復詹持國二月一日同步城南','周行己','宋','宋诗','song-poetry','','[]','人生本自得，苦爲百慮疚。',192,'全唐诗/poet.song.71000.json','["人生本自得，苦爲百慮疚。", "窮年燈火窗，鬰沒令人瘦。", "方春萬物作，欣欣共晴晝。", "步履聊出郭，疏散忘隘陋。", "當時二三子，來往心疏透。", "歡然共携手，住處同一簉。", "弱柳分已綠，小桃紅欲溜。", "細草軟宜籍，急流清可潄。", "杯傾野橋邊，酒從村店售。", "脫帽看晴雲，擊木雜鳴咮。", "或靜欲寂默，或狂忽騰蹂。", "野老愕僵仆，村童怪驚走。", "恐是天上仙，無乃人間秀。", "瀟洒羲皇上，磊落漢庭右。", "日暮欲返步，已行更引脰。", "此會得真率，他時渙邂逅。"]'),
('930d81cc-2db4-4680-94c4-b630e2b5ee53','次韵林千之秋夜見懷','周行己','宋','宋诗','song-poetry','','[]','清夜炯不寐，虛窗入圓璧。',120,'全唐诗/poet.song.71000.json','["清夜炯不寐，虛窗入圓璧。", "鴻雁正南飛，庭柯已改色。", "四運無停景，欻見節序隔。", "百物自穰穰，吾心自寂寂。", "秋物本何悲，君悲當自適。", "楚玉非達士，淚苦爲秋滴。", "不如陶淵明，濁醪度晨夕。", "以茲俟君子，須要生理得。", "一飲置君憂，再飲□君□。", "我感知己分，爲子豁丹臆。"]'),
('2dc51687-85a6-4500-a61e-63876f7922e0','述憶二十韵奉贈段公度歐陽元老','周行己','宋','宋诗','song-poetry','','[]','少小從結髮，讀書懷古人。',216,'全唐诗/poet.song.71000.json','["少小從結髮，讀書懷古人。", "年未十四五，出走京洛塵。", "當時黌堂士，教我文章新。", "氣格一入俗，至今不復振。", "病驥思逸足，鞭策傷苦辛。", "切雲漫崔嵬，慚愧席上珍。", "邇來二三子，論交偶情親。", "以我忘疵賤，所得皆鳳麟。", "念我勤服義，嘉我能仁親。", "故此傾丹臆，誨我日諄諄。", "論詩到平淡，文師韓子純。", "學道貴能行，卓爾非因循。", "生平志已定，不復顧狺狺。", "脫略塵累縶，逝將游廣津。", "一披霧豹姿，豁然開我神。", "人生貴相知，願言結近賓。", "頗恨相得晚，甚知二子真。", "樂此臭味同，締好期終身。"]'),
('c6a80da6-7000-44b0-bd0f-5c054f555601','巫山高','周行己','宋','宋诗','song-poetry','','[]','誰謂巫山高，朝言暮可期。',48,'全唐诗/poet.song.71000.json','["誰謂巫山高，朝言暮可期。", "而我有所思，邂逅藐無時。", "誰能心似石，見此月如眉。", "款款琴上聲，此意人詎知。"]'),
('86c33184-d84a-48fa-9178-baee28b9231b','有所思','周行己','宋','宋诗','song-poetry','','[]','春風應應至，寸草亦知時。',48,'全唐诗/poet.song.71000.json','["春風應應至，寸草亦知時。", "人生非木石，誰能無所思。", "桃花亂愁眼，柳葉憶蛾眉。", "所思良不遂，願言何可期。"]'),
('312fc651-44ee-426a-9d15-19c6b8f18362','重游仙巖','周行己','宋','宋诗','song-poetry','','[]','此地一爲別，風塵歧路賒。',48,'全唐诗/poet.song.71000.json','["此地一爲別，風塵歧路賒。", "登臨原有待，巖谷更重華。", "石竇寒凝髓，虹梁迥綴霞。", "仙源端可狎，飛轡繞林涯。"]'),
('694bb08c-d312-4a20-ad6e-ddbd650431b9','美人曲','周行己','宋','宋诗','song-poetry','','[]','美人娟娟似秋月，宮中女兒嫉欲殺。',64,'全唐诗/poet.song.71000.json','["美人娟娟似秋月，宮中女兒嫉欲殺。", "惡言忽入恩愛移，自是君王不情察。", "深宮夜冷調秦箏，曲曲翻成哀怨聲。", "願得風吹落君耳，回心照妾相思情。"]'),
('30bcf1f7-bb61-4662-8b2e-4fcd6e56da05','石橋','周之深','宋','宋诗','song-poetry','','[]','地險知人特地來，猿禽意思也徘徊。',32,'全唐诗/poet.song.71000.json','["地險知人特地來，猿禽意思也徘徊。", "遥瞻聖境真如在，休問石門開未開。"]'),
('fcfe65d3-13cd-4619-b899-2339f5f8cb46','遊清果寺','周之深','宋','宋诗','song-poetry','','[]','西郊出郭未十里，寺在白雲深處藏。',64,'全唐诗/poet.song.71000.json','["西郊出郭未十里，寺在白雲深處藏。", "僧爲愛閑長閉戶，客來無路自迴廊。", "近松古瓦落夜子，傍水小池生暮光。", "指點依稀飯籮水，不知何處問興亡。"]'),
('01b52d7e-6bdc-4ce5-b635-ebcb465b5751','遊虎丘','閻與道','宋','宋诗','song-poetry','','[]','高僧足一丘，門外漫維舟。',48,'全唐诗/poet.song.71000.json','["高僧足一丘，門外漫維舟。", "車馬倦塵境，林泉清晚秋。", "石分秦劍利，雲伴女墳愁。", "回首羣鴉暮，飛鳴丈室頭。"]'),
('a39baa39-82fd-4941-ad1c-75c6d628e1e4','白雲亭','鄭道','宋','宋诗','song-poetry','','[]','天風吹我上齊雲，小澗清從石乳分。',32,'全唐诗/poet.song.71000.json','["天風吹我上齊雲，小澗清從石乳分。", "濯罷塵纓吾欲忘，白雲滿地未斜曛。"]'),
('7a61c50f-e8d2-4f52-8d71-fa4a17d82683','同太守遊東湖','劉棠','宋','宋诗','song-poetry','','[]','兀兀塵編日自迷，怪來春色轉芳菲。',64,'全唐诗/poet.song.71000.json','["兀兀塵編日自迷，怪來春色轉芳菲。", "吹噓氣象湖山遠，點綴工夫草木微。", "挈榼不辭傾美酒，揮戈寧解住殘暉。", "身閑官冷何欣幸，秉燭長隨五馬歸。"]'),
('9cbeb0c9-f3d7-43ae-8c0b-364ea32f3aac','寄張貺','傅求','宋','宋诗','song-poetry','','[]','利鎖名韁脫者希，鐘鳴漏盡尚忘歸。',64,'全唐诗/poet.song.71000.json','["利鎖名韁脫者希，鐘鳴漏盡尚忘歸。", "獨全至樂能齊物，未達高年遂拂衣。", "明月數聲仙鶴唳，秋風一尺鱠鱸肥。", "賞心樂事知多少，只恐蒲輪到釣磯。"]'),
('bfb474bc-fb81-471f-aac2-a67c501a0134','傲暑棲霞洞','李彥弼','宋','宋诗','song-poetry','','[]','嵌竇栖霞，𠿕𧇠轉杓。',40,'全唐诗/poet.song.71000.json','["嵌竇栖霞，𠿕𧇠轉杓。", "左驂鸞翼，右耳鳳簫。", "爽排酷烈，境邈氛囂。", "靜者多妙，於焉消摇。"]'),
('ebdb7121-5e5f-4b2d-acce-ec163043c1b4','與曹聖延遊風洞及七星觀遂成長句','李彥弼','宋','宋诗','song-poetry','','[]','文英子建聲華烜，少陵嘗詠波瀾闊。',384,'全唐诗/poet.song.71000.json','["文英子建聲華烜，少陵嘗詠波瀾闊。", "遐流亹亹鍾宜春，觀君紫芝真秀拔。", "華山騄耳汗血孫，奚取王良手芻秣。", "駸駸凌厲追遺風，胡爲頓纓馳駱越。", "誰嗟長庚有老裔，壯齡直欲排紫闥。", "初從附鳳矯飛翔，晚乃射虎耽疏豁。", "强顔方喜安斗筲，稟分何能愧圭撮。", "胸中琳琅茀埃𡏖，自恧鉛鋒乏破割。", "時過西鄰蘄發藥，霤引玉泉澆胏渴。", "新商執矩早威令，甘霔騰虛摧虐魃。", "約君飄鳬泛滄漪，背負青天□夭閼。", "風來空穴襲髮毛，刷腋凉飆振絺葛。", "泠然便擬子列遊，不待別起青蘋末。", "徐躋七星跐山椒，杓魁歊虛狀旋斡。", "近君白雪熱何有，高談一激錐囊脫。", "扳肩作者古蹊徑，餘事篇章隨擊鉢。", "盤趺不減二華君，妙閱枯棋戰挑捾。", "光騶摇縱莫可留，四序翩翩幾箭筈。", "頃看金柳流鶑鳴，俄聽玉露叢蟬聒。", "清輝默韵無弦琴，烏用檀槽揮一抹。", "我方騷愁愁到骨，潜睨蠹蟫眉目繓。", "徒操詩窮擁鼻吟，□或酒酣將月喝。", "生平剛腸久已屈，頼爾匹夫難志奪。", "故交紛紜翱赤霄，大鈞播物昭窮達。"]'),
('31a6d0cb-2ca5-4e9a-b892-682adb6ba4dc','閨怨二首  其一','司馬槱','宋','宋诗','song-poetry','','[]','銷盡輕寒不自禁，新愁唯向靜中深。',64,'全唐诗/poet.song.71000.json','["銷盡輕寒不自禁，新愁唯向靜中深。", "尋常曾入三更夢，咫尺空論萬里心。", "人去鳳幃雲漠漠，雁回珠箔日沈沈。", "春風洞口花長在，只許劉郎一度尋。"]'),
('6a92eb7a-b36e-4563-a110-2768cb2e8b3d','閨怨二首  其二','司馬槱','宋','宋诗','song-poetry','','[]','繡簾珠箔一重重，十里香風入眼濃。',64,'全唐诗/poet.song.71000.json','["繡簾珠箔一重重，十里香風入眼濃。", "鏡合紫鸞來有信，雲深青鳥去無蹤。", "楚王臺下尋常見，宋玉牆頭取次逢。", "可惜好花攀折盡，飄零芳蕊付游蜂。"]'),
('59a844f5-b6b6-4f43-a2a5-fdce8c8fb0ed','和上元日遊南園賞梅花','司馬槱','宋','宋诗','song-poetry','','[]','梅簇荒臺自可羞，相君愛賞忘宵遊。',32,'全唐诗/poet.song.71000.json','["梅簇荒臺自可羞，相君愛賞忘宵遊。", "未言美實和羹味，且薦清香泛酒甌。"]'),
('c527133f-4463-413e-a853-d2b9f3d885be','千頃山  其一','司馬槱','宋','宋诗','song-poetry','','[]','瓊葉半開童女頰，蕨芽初長小兒拳。',32,'全唐诗/poet.song.71000.json','["瓊葉半開童女頰，蕨芽初長小兒拳。", "山中雲雨雖無味，何似山河走暮烟。"]'),
('a7155fe4-172a-4ffd-ba87-f28ca99eca31','千頃山  其二','司馬槱','宋','宋诗','song-poetry','','[]','一池春水應江潮，中起沙鷗數尺高。',32,'全唐诗/poet.song.71000.json','["一池春水應江潮，中起沙鷗數尺高。", "誰謂風雲遠朝市，亂山深處亦波濤。"]'),
('17bce05b-994a-45f1-a724-a95a5c1a8aaa','千頃山  其三','司馬槱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','欲爲龍池游，束裝戒蓐食。',168,'全唐诗/poet.song.71000.json','["欲爲龍池游，束裝戒蓐食。", "雞鳴天未曙，呼兒重蠟屐。", "縈回遡寒溪，确犖疲亂石。", "迢迢萬丈嶺，宛轉蒼龍脊。", "山高吐朝氣，恍不辨咫尺。", "俯聽雷雨聲，仰逐猿猱跡。", "委蛇度花塢，綠靜草可席。", "喜如出籠檻，身輕飛鳥擲。", "不辭雙足繭，遠探蛟龍客。", "傳聞此山頂，舊有滄海色。", "爾來三十年，潭湫變枯荻。", "至今應江潮，尚浮鷗鷺集。", "至理竟未解，對之空太息。", "不如西湖遊，揮篙泛瑶碧。"]'),
('bb79edec-25f8-4beb-8019-a84259eed651','風水洞','司馬槱','宋','宋诗','song-poetry','','[]','藤梢蔓荒寒，蘚花陰空青。',132,'全唐诗/poet.song.71000.json','["藤梢蔓荒寒，蘚花陰空青。", "窈窕石竇中，兩耳風雨并。", "初聞聲蕭騷，活火急銅瓶。", "再聽逗餘響，萬羽起寒汀。", "我疑此山空，石脚連滄溟。", "中有蛟龍蟄，鼻息隠雷霆。", "又迓仙翁去，丹竈留巖扃。", "至今爐鼎中，水火爭不停。", "山前老比丘，霜眉眼如螢。", "能傳古老語，濯我耳昕醒。", "便欲慰塵凡，脫我隨爽靈。"]'),
('d4e4399d-8dc6-43e8-9339-f4aba9e601a4','蛻龍洞  其一','司馬槱','宋','宋诗','song-poetry','','[]','雷雨何時起蟄龍，蒼痕夭矯石巖空。',32,'全唐诗/poet.song.71000.json','["雷雨何時起蟄龍，蒼痕夭矯石巖空。", "不綠嗜好尋劉累，定向人閒試葉公。"]'),
('79346b74-52fa-4c8e-9aa9-6972f98bbd56','蛻龍洞  其二','司馬槱','宋','宋诗','song-poetry','','[]','梅萼春前破，松髯雨後滋。',48,'全唐诗/poet.song.71000.json','["梅萼春前破，松髯雨後滋。", "石崖鳴野鶴，竹塢竄香狸。", "山脚重重轉，溪流泯泯遲。", "慇懃窺洞府，又得濯龍池。"]'),
('83d63a55-9eea-48b3-9365-97d043a0e550','題清泠軒','司馬槱','宋','宋诗','song-poetry','','[]','石冷苔生暈，風高竹度凉。',24,'全唐诗/poet.song.71000.json','["石冷苔生暈，風高竹度凉。", "道人何處去，春色半滄浪。"]'),
('1b2df644-55b5-4bc7-8b86-d70e9991b586','遊九鎖','司馬槱','宋','宋诗','song-poetry','','[]','撩花踏水細尋香，閒逐孤雲入翠岡。',64,'全唐诗/poet.song.71000.json','["撩花踏水細尋香，閒逐孤雲入翠岡。", "九鎖已深看更好，七人相對話應長。", "百年空向塵埃老，五月聊乘洞府凉。", "可笑潜川狂道士，未逢玉室與金堂。"]'),
('934083d9-7d43-4714-92fc-04b3f0a9bb93','洛春謠','司馬槱','宋','宋诗','song-poetry','','[]','洛陽碧水揚春風，銅駝陌上桃花紅。',163,'全唐诗/poet.song.71000.json','["洛陽碧水揚春風，銅駝陌上桃花紅。", "高樓疊柳綠相向，綃帳金鑾香霧濃。", "龍裘公子五陵客，拳毛赤兔雙蹄白。", "金鈎寶玦逐飛香，醉入花叢惱花魄。", "青娥皓齒列吳娼，梅粉粧成半額黄。", "羅屏繡幕圍寒玉，帳裏吹笙學鳳凰。", "細綠圍紅曉烟濕，車馬騑騑雲櫛櫛。", "瓊蕊杯深琥珀濃，鴛鴦枕鏤珊瑚澀。", "吹龍笛，歌白紵，蘭席淋漓日將暮。", "君不見灞陵岸上楊柳枝，青青送別傷南浦。"]'),
('98c4bc24-ac07-40f3-b5d2-d3b0c48514fc','句','司馬槱','宋','宋诗','song-poetry','','[]','身既事十主，女亦妃九龍。',12,'全唐诗/poet.song.71000.json','["身既事十主，女亦妃九龍。"]'),
('a74be278-d886-450e-87e1-dfd1c622e7fc','江干小雪','司馬棫','宋','宋诗','song-poetry','','[]','楓落吳江小雪天，三三兩兩捕魚船。',32,'全唐诗/poet.song.71000.json','["楓落吳江小雪天，三三兩兩捕魚船。", "蹇馿瘦馬何方客，眼看風波不著鞭。"]'),
('da4b0453-149b-4a20-8f30-d907af0dbc6c','妾薄命','司馬棫','宋','宋诗','song-poetry','','[]','二月春風初不惡，後園桃李先春落。',163,'全唐诗/poet.song.71000.json','["二月春風初不惡，後園桃李先春落。", "高堂去婦對花愁，君恩非輕妾命薄。", "憶昔三星光在天，煌煌車馬朱門前。", "結褵幸得事君子，願託絲蘿千萬年。", "履痕纔徧君家地，相看已覺君心異。", "門外新懽一破顔，室中舊愛雙垂淚。", "妾心比玉自堅貞，君眼如星到處明。", "女子睽離太山重，丈夫棄置鴻毛輕。", "莫誇綠髮紅顔好，女色由來何可保。", "君不見灞上鑾輿祓禊回，阿嬌已向長門老。"]'),
('6af95c59-aef4-4acc-89cb-7d15326eda5c','春晚獨游鳳林園','司馬棫','宋','宋诗','song-poetry','','[]','紅英亂點綠苔錢，林影扶疏翠可憐。',64,'全唐诗/poet.song.71000.json','["紅英亂點綠苔錢，林影扶疏翠可憐。", "飛蝶惹殘花上露，戲魚摇碎水中天。", "金羈不見尋芳馬，蘭櫂空停載酒船。", "送盡春歸人未老，鶑啼花發又明年。"]'),
('8d447d56-5c8f-4d67-9a7d-29b4ad49e46b','茅齋','司馬棫','宋','宋诗','song-poetry','','[]','坐見茅齋一葉秋，小山叢桂鳥聲幽。',32,'全唐诗/poet.song.71000.json','["坐見茅齋一葉秋，小山叢桂鳥聲幽。", "不知疊嶂夜來雨，清曉石楠花亂流。"]'),
('edd7f5a9-2298-4479-8a68-5e8e2ce877ef','哭兄','司馬棫','宋','宋诗','song-poetry','','[]','誰教作雁破羣飛，一舸南遊遂不歸。',64,'全唐诗/poet.song.71000.json','["誰教作雁破羣飛，一舸南遊遂不歸。", "乍見音容悲且喜，不知魂夢是邪非。", "陟岡望遠心猶在，携幼還家意已違。", "淚眼重尋丘壑去，可堪猶采故山薇。"]'),
('190b7ea0-e9a3-4bba-9167-ea7f3abcbb85','華亭峽道中','司馬棫','宋','宋诗','song-poetry','','[]','山似九折坂，河非八節灘。',24,'全唐诗/poet.song.71000.json','["山似九折坂，河非八節灘。", "躋攀復揭厲，奈此行路難。"]'),
('f46a3c7c-226b-4703-8c0c-009ad40bfa0a','題鳳棲寺','陳希伋','宋','宋诗','song-poetry','','[]','千載傳聞孰是非，高梧脩竹晚風微。',32,'全唐诗/poet.song.71000.json','["千載傳聞孰是非，高梧脩竹晚風微。", "欲知古寺曾棲鳳，樓殿今無燕雀飛。"]'),
('3b9f376f-96cf-46ec-be8d-50e716612655','句','吳習禮','宋','宋诗','song-poetry','','[]','湖北封疆最上游，荆門中有惠泉流。',16,'全唐诗/poet.song.71000.json','["湖北封疆最上游，荆門中有惠泉流。"]'),
('96024dab-132b-48fb-b5ef-936d62667840','句','范溫','宋','宋诗','song-poetry','','[]','夷甫雌黄須倚閣，君卿唇舌要施行。',16,'全唐诗/poet.song.71000.json','["夷甫雌黄須倚閣，君卿唇舌要施行。"]'),
('06fecc2e-7c1a-46d2-9207-12faeaece5a3','句','朴景綽','宋','宋诗','song-poetry','','[]','勝事年年傳習久，盛觀全屬遠方賓。',16,'全唐诗/poet.song.71000.json','["勝事年年傳習久，盛觀全屬遠方賓。"]'),
('5adb91aa-f870-42bb-9311-15815116d0c4','句','羅可','宋','宋诗','song-poetry','','[]','斜侵潘岳鬢，橫上馬良眉。',12,'全唐诗/poet.song.71000.json','["斜侵潘岳鬢，橫上馬良眉。"]'),
('581e4cd9-30e1-4171-956c-c5664fec4b31','紫竹','張重','宋','宋诗','song-poetry','','[]','顔色耐雪霜，桃李不能妬。',24,'全唐诗/poet.song.71000.json','["顔色耐雪霜，桃李不能妬。", "但取節操高，莫起奪朱惡。"]'),
('ad1d635b-e258-458d-aa04-6ecef9789b70','宣妙院上方','劉正夫','宋','宋诗','song-poetry','','[]','水定浮春岫，鴉盤落遠林。',24,'全唐诗/poet.song.71000.json','["水定浮春岫，鴉盤落遠林。", "上方鐘送夕，隠几興何深。"]'),
('367d27b5-fbec-4a42-b3a1-4929364017e9','句','劉正夫','宋','宋诗','song-poetry','','[]','紫宸朝罷衮衣閑。',8,'全唐诗/poet.song.71000.json','["紫宸朝罷衮衣閑。"]'),
('3150870f-81b4-469e-bce1-6945f42ed307','謁真如悟法述偈','釋道平','宋','宋诗','song-poetry','','[]','七顛八倒，業識忙忙。',22,'全唐诗/poet.song.71000.json','["七顛八倒，業識忙忙。", "螺江回首處，笑殺謝三郎。"]'),
('d688c737-4dba-4b63-948c-89e9a235daae','偈二首  其一','釋道平','宋','宋诗','song-poetry','','[]','山僧不會佛法，爲人總沒來由。',56,'全唐诗/poet.song.71000.json','["山僧不會佛法，爲人總沒來由。", "或時半開半合，或時全放全收。", "還如萬人叢裏，冷地掉箇石頭。", "忽然打著一箇，方知觸處周流。"]'),
('4dc51975-8687-40ac-8e01-790603c4889b','偈二首  其二','釋道平','宋','宋诗','song-poetry','','[]','趙州有四門，門門通大道。',60,'全唐诗/poet.song.71000.json','["趙州有四門，門門通大道。", "玉泉有四路，路路透長安。", "門門通大道，畢竟誰親到。", "路路透長安，分明進步看。", "歲晚未歸客，西鳳門外寒。"]'),
('b6aea086-9144-4c96-9177-d4fb813fd9e6','舉盤山示衆偈','釋道平','宋','宋诗','song-poetry','','[]','似地擎山，不知山之孤峻。',90,'全唐诗/poet.song.71000.json','["似地擎山，不知山之孤峻。", "如石含玉，不知玉之無暇。", "古人恁麽說話，大似抱賊叫屈。", "普融門下，人人慷慨。", "生擒虎兕，活捉獰龍。", "眼裏著得須彌山，耳裏著得大海水。", "不是向人誇伎倆，丈夫標致合如斯。"]'),
('b011237a-6758-4173-acbf-23bea1ea9ce8','偈','釋景祥','宋','宋诗','song-poetry','','[]','靈山話，曹溪指，放過初生斫額底。',32,'全唐诗/poet.song.71000.json','["靈山話，曹溪指，放過初生斫額底。", "未問龍眠老古錐，昨夜三更轉向西。"]'),
('fea692a2-d664-405a-8fb2-9bc8c03f0414','陝府鐵牛','釋景祥','宋','宋诗','song-poetry','','[]','尾在黄河北，頭枕黄河南。',24,'全唐诗/poet.song.71000.json','["尾在黄河北，頭枕黄河南。", "善財無鼻孔，依舊向南參。"]'),
('e04fbc2d-32d6-4f3e-99da-2807d903b8db','偈','釋寘','宋','宋诗','song-poetry','','[]','福巖山上雲，舒卷任朝昏。',24,'全唐诗/poet.song.71000.json','["福巖山上雲，舒卷任朝昏。", "忽爾落平地，客來難討門。"]'),
('86d21f62-b35d-4918-81ee-f45c5dea9f2a','臨終與蔡氏甥','周濱','宋','宋诗','song-poetry','','[]','三舅報無常，諸甥脚手忙。',48,'全唐诗/poet.song.71000.json','["三舅報無常，諸甥脚手忙。", "熟搥三挺皂，爛煮一鍋湯。", "垢膩從君洗，形骸任爾扛。", "六釘聲寂寂，千古路茫茫。"]'),
('51b76821-0262-446a-a44d-70a615d97034','答沂州吏','王老志','宋','宋诗','song-poetry','','[]','多年退罷老公人，手種桑麻數百根。',32,'全唐诗/poet.song.71000.json','["多年退罷老公人，手種桑麻數百根。", "盡是筆頭挼撚得，一枝枝上有冤魂。"]'),
('89b33b70-5530-4a5c-a2f5-b1b8156da1f0','釣臺','余闢','宋','宋诗','song-poetry','','[]','不誇長揖出宮闈，不重爲漁老釣磯。',32,'全唐诗/poet.song.71000.json','["不誇長揖出宮闈，不重爲漁老釣磯。", "最愛清宵銀漢上，客星時共帝星輝。"]'),
('275b60c4-38ee-4fb6-8ec7-a896a5e0ff0b','題太平興國宮','傅謙受','宋','宋诗','song-poetry','','[]','仙家樓閣靄清芬，倦客停驂日欲曛。',32,'全唐诗/poet.song.71000.json','["仙家樓閣靄清芬，倦客停驂日欲曛。", "爭得便如陶靖節，拂衣來此看孤雲。"]'),
('b39304da-b494-4dcf-b314-b3a820e5fdf4','別友人','陸字','宋','宋诗','song-poetry','','[]','園花今爛漫，一一手親栽。',24,'全唐诗/poet.song.71000.json','["園花今爛漫，一一手親栽。", "惟有新離恨，東風吹不開。"]'),
('c82c9701-ff08-4535-aff4-cb0fa72ccdb9','戲馬巨濟','李作乂','宋','宋诗','song-poetry','','[]','太學有馬涓，南省無馬涓。',24,'全唐诗/poet.song.71000.json','["太學有馬涓，南省無馬涓。", "秋榜有馬涓，春榜無馬涓。"]'),
('8560296e-458b-4259-b426-39df17201b74','題白蓮堂','徐評','宋','宋诗','song-poetry','','[]','一法圓融萬法該，白蓮香社應時開。',32,'全唐诗/poet.song.71000.json','["一法圓融萬法該，白蓮香社應時開。", "淵明不解同方便，何事攢眉不肯來。"]'),
('94e43bd4-f88d-43c6-9067-b879c14a5cbb','題蛻龍洞','徐評','宋','宋诗','song-poetry','','[]','薈蔚蒼巖下，靈蹤此暫蟠。',48,'全唐诗/poet.song.71000.json','["薈蔚蒼巖下，靈蹤此暫蟠。", "雲雷一夜起，風雨滿山寒。", "骨腐苔方綠，涎餘石未乾。", "試憑圖畫去，聊羨葉公看。"]'),
('c693bf98-06db-4605-a9c0-c7f0d36ccbbe','寧國院','徐評','宋','宋诗','song-poetry','','[]','岑寂千山曲，縈紆一徑微。',48,'全唐诗/poet.song.71000.json','["岑寂千山曲，縈紆一徑微。", "樓臺青嶂合，窗戶亂雲飛。", "野色侵僧衲，池光射客衣。", "偶來修吏隠，到此益忘機。"]'),
('de355936-799b-4474-983f-e610f605737e','中秋月集句  其一','葛次仲','宋','宋诗','song-poetry','','[]','玉露中秋夜，亭亭月正圓。',48,'全唐诗/poet.song.71000.json','["玉露中秋夜，亭亭月正圓。", "一霄當皎潔，萬象共澄解。", "送別高臺上，添愁野帳前。", "無因駐清景，歌舞入明年。"]'),
('af3547d0-8766-4962-b191-3cd3a9391956','中秋月集句  其二','葛次仲','宋','宋诗','song-poetry','','[]','凉夜清秋半，常娥照玉輪。',48,'全唐诗/poet.song.71000.json','["凉夜清秋半，常娥照玉輪。", "九霄微有露，萬里正無塵。", "氣射繁星滅，明翻宿鳥頻。", "寥寥天地內，風景一時新。"]'),
('1a37e974-754a-418c-8bbf-729a59fcf1be','崑山慧聚寺集句','葛次仲','宋','宋诗','song-poetry','','[]','全吳臨巨溟，青山天一隅。',264,'全唐诗/poet.song.71000.json','["全吳臨巨溟，青山天一隅。", "靜境林麓好，勝槩凌方壺。", "泓泓野泉潔，曖曖烟谷虛。", "攀雲造禪扃，躋險築幽居。", "道人刺猛虎，復來薙榛蕪。", "咄嗟檀施開，以有此屋廬。", "側疊萬古石，功就豈斯須。", "磥砢成廣殿，鬼工不可圖。", "有窮者孟郊，過此亦躊躇。", "賦詩留巖屏，詞律響瓊琚。", "我訪岑寂境，幸與高士俱。", "時升翠微上，凉閣對紅蕖。", "岸幘偃東齋，果藥雜紛敷。", "上方風景清，華敞綽有餘。", "高窗瞰遠郊，萬壑明晴初。", "賞愛未能去，頳霞照桑榆。", "老僧道機熟，閑持貝葉書。", "秉心識本源，高談出有無。", "茗酌待幽客，頓令煩抱舒。", "儒道雖異門，意合不爲殊。", "抖擻垢穢衣，惟有牟尼珠。", "餘生願休止，投策謝歸塗。"]'),
('d89a7039-cf25-4b9d-8a0d-3c10d31c4a9e','詩一首','葛次仲','宋','宋诗','song-poetry','','[]','萬里清江萬里天，一村桑柘一村烟。',32,'全唐诗/poet.song.71000.json','["萬里清江萬里天，一村桑柘一村烟。", "漁翁醉睡又醒睡，高唱夕陽孤島邊。"]'),
('ae99b8dc-cd52-42e6-b23f-58739a128ad6','句','葛次仲','宋','宋诗','song-poetry','','[]','榮枯不經意。',6,'全唐诗/poet.song.71000.json','["榮枯不經意。"]'),
('f801e3c9-c458-4275-ad14-e6e3ef829ada','嵩山二十四詠 青童峰','樓异','宋','宋诗','song-poetry','','[]','斬新高髻掠雲開，翠色羅衣一樣裁。',32,'全唐诗/poet.song.71000.json','["斬新高髻掠雲開，翠色羅衣一樣裁。", "知有真仙此中住，故命天女捧書來。"]'),
('d7d54727-4008-4c2e-9148-9788d261017e','嵩山二十四詠 黄蓋峰','樓异','宋','宋诗','song-poetry','','[]','一片黄雲駐不飛，中天帝子欲何知。',32,'全唐诗/poet.song.71000.json','["一片黄雲駐不飛，中天帝子欲何知。", "不須更問玉人事，自有嵩高峻極詩。"]'),
('f7f68df7-858d-4920-91b5-12ad52c66f39','嵩山二十四詠 浮邱峰','樓异','宋','宋诗','song-poetry','','[]','誰知方丈與瀛洲，塵世紛紛漫白頭。',32,'全唐诗/poet.song.71000.json','["誰知方丈與瀛洲，塵世紛紛漫白頭。", "不到嵩山最高處，世人容易揖浮邱。"]'),
('a5294b10-3403-4fdd-90be-6f4299371c3b','嵩山二十四詠 三鶴峰','樓异','宋','宋诗','song-poetry','','[]','昔有仙翁住此間，煉成青髮與朱顔。',32,'全唐诗/poet.song.71000.json','["昔有仙翁住此間，煉成青髮與朱顔。", "一朝跨鶴昇天去，澗草巖花豈復攀。"]'),
('a83381d5-35a8-4021-bdf6-28cb3d71eb33','嵩山二十四詠 遇聖峰','樓异','宋','宋诗','song-poetry','','[]','漢家天子學神仙，曾遇真人耳過肩。',32,'全唐诗/poet.song.71000.json','["漢家天子學神仙，曾遇真人耳過肩。", "不待菖蒲長黑髮，須知逸樂自延年。"]'),
('6da85144-23b4-4479-9a60-6595dc0bcd0f','嵩山二十四詠 萬歲峰','樓异','宋','宋诗','song-poetry','','[]','仙仗西來感百神，泥金檢玉尚如新。',32,'全唐诗/poet.song.71000.json','["仙仗西來感百神，泥金檢玉尚如新。", "山靈知是真天子，萬歲聲中第一人。"]'),
('76728823-3510-4f9e-ad60-269bb292dc35','嵩山二十四詠 玉鏡峰','樓异','宋','宋诗','song-poetry','','[]','皎皎冰盤瑩百圍，廣寒宮殿見依稀。',32,'全唐诗/poet.song.71000.json','["皎皎冰盤瑩百圍，廣寒宮殿見依稀。", "青山萬疊渾如洗，浮翠光中一鏡飛。"]'),
('5abf7f7f-5c3c-4611-a18f-1c1f61367f8e','嵩山二十四詠 獅子峰','樓异','宋','宋诗','song-poetry','','[]','蒼苔藤蔓飾鬚眉，獅子標形是與非。',32,'全唐诗/poet.song.71000.json','["蒼苔藤蔓飾鬚眉，獅子標形是與非。", "果解嚬呻作哮吼，窟中狐兔定魂飛。"]'),
('59f84a0c-9c41-4e70-ad5c-c33ddbef61b1','嵩山二十四詠 虎頭峰','樓异','宋','宋诗','song-poetry','','[]','萬里封侯相不如，道人曾此獲陰符。',32,'全唐诗/poet.song.71000.json','["萬里封侯相不如，道人曾此獲陰符。", "軒牙露舌驚樵採，猛士還當捋爾鬚。"]'),
('539fd5f7-147b-42ab-b7e8-610584e06f24','嵩山二十四詠 起雲峰','樓异','宋','宋诗','song-poetry','','[]','觸石孤飛一葉蓬，雷公電母晝鞭龍。',32,'全唐诗/poet.song.71000.json','["觸石孤飛一葉蓬，雷公電母晝鞭龍。", "但知四海爲霖雨，不道中天第幾峰。"]'),
('9ded1494-2a66-4c5d-84dd-b4b4bafbe22c','嵩山二十四詠 鳳凰峰','樓异','宋','宋诗','song-poetry','','[]','當年翔鳳此徘徊，曾爲真人覽德來。',32,'全唐诗/poet.song.71000.json','["當年翔鳳此徘徊，曾爲真人覽德來。", "今日飛鳴天外過，紛紛燕雀不須猜。"]'),
('4756bb35-d3d1-4890-b455-8af6031f0053','嵩山二十四詠 金壺峰','樓异','宋','宋诗','song-poetry','','[]','想見金壺瀉墨河，皂林餘潤鬰嵯峨。',32,'全唐诗/poet.song.71000.json','["想見金壺瀉墨河，皂林餘潤鬰嵯峨。", "伯陽當日傳經後，肯向山陰與換鵝。"]'),
('a16ebddc-6365-4054-b9a0-4e9c322f95bb','嵩山二十四詠 華蓋峰','樓异','宋','宋诗','song-poetry','','[]','華蓋峰高未易窮，捫參歷井到天中。',32,'全唐诗/poet.song.71000.json','["華蓋峰高未易窮，捫參歷井到天中。", "回頭却顧人間世，但見羣青似小童。"]'),
('1c484e50-9c12-46fd-bb76-4ade6d12242a','嵩山二十四詠 玄龜峰','樓异','宋','宋诗','song-poetry','','[]','玄武名峰古所傳，晨昏吐氣作雲烟。',32,'全唐诗/poet.song.71000.json','["玄武名峰古所傳，晨昏吐氣作雲烟。", "雖無鑽灼刳腸患，歲晚風霜亦可憐。"]'),
('5cd562f1-e1bd-4617-87b9-d445fa10e7fb','嵩山二十四詠 卧龍峰','樓异','宋','宋诗','song-poetry','','[]','頭角低回蘚蔓封，蜿蜒端似卧真龍。',32,'全唐诗/poet.song.71000.json','["頭角低回蘚蔓封，蜿蜒端似卧真龍。", "旱乾歲禱多靈應，時見油雲出此峰。"]'),
('4d399e91-d863-4b46-b440-bcd39559090b','嵩山二十四詠 會仙峰','樓异','宋','宋诗','song-poetry','','[]','鶴乘雲軿下九天，玉盤星子竟誰先。',32,'全唐诗/poet.song.71000.json','["鶴乘雲軿下九天，玉盤星子竟誰先。", "相應漢武題花品，留作人間聚八仙。"]'),
('70120939-4ffe-4102-b7e3-ebe8bda6db5c','嵩山二十四詠 子晉峰','樓异','宋','宋诗','song-poetry','','[]','當年曾悟鏡中形，道骨仙風擬紫冥。',32,'全唐诗/poet.song.71000.json','["當年曾悟鏡中形，道骨仙風擬紫冥。", "二十四峰明月夜，玉笙須向揖仙聽。"]'),
('6de26900-9f21-4ca3-9830-ab79eba3a842','嵩山二十四詠 玉柱峰','樓异','宋','宋诗','song-poetry','','[]','丹楹未羨人間侈，玉柱一峰天外高。',32,'全唐诗/poet.song.71000.json','["丹楹未羨人間侈，玉柱一峰天外高。", "自古大材須大用，扶持廣厦豈辭勞。"]'),
('2d5ed962-8291-4963-9d06-7c52c1536491','嵩山二十四詠 老翁峰','樓异','宋','宋诗','song-poetry','','[]','翳霧埋雲皓首翁，難將書傳考前蹤。',32,'全唐诗/poet.song.71000.json','["翳霧埋雲皓首翁，難將書傳考前蹤。", "商山羽翼朝天後，化作中天一石峰。"]'),
('c46bfa1e-80c5-44d7-b1ae-5dd0a78ecb67','嵩山二十四詠 玉人峰','樓异','宋','宋诗','song-poetry','','[]','漢武求仙未得仙，玉人何事落峰前。',32,'全唐诗/poet.song.71000.json','["漢武求仙未得仙，玉人何事落峰前。", "故知帝子乘雲下，神蓋峰頭啟洞天。"]'),
('a5ac20e3-f43c-4a7a-85ba-a48cd8f3fcca','嵩山二十四詠 玉女峰','樓异','宋','宋诗','song-poetry','','[]','玉仙曾此駐雲車，日薄窗紗映雪膚。',32,'全唐诗/poet.song.71000.json','["玉仙曾此駐雲車，日薄窗紗映雪膚。", "七字天書人不辨，定知玄女手中符。"]'),
('31bb7b3d-72ee-4f07-a941-c14ee4768b86','嵩山二十四詠 獨秀峰','樓异','宋','宋诗','song-poetry','','[]','孕玉懷金不待媒，蓊然佳氣罩崔嵬。',32,'全唐诗/poet.song.71000.json','["孕玉懷金不待媒，蓊然佳氣罩崔嵬。", "天教秀拔諸峰上，未信狂飈解折摧。"]'),
('b92979ba-f5ab-4c9a-aa4d-4aea77ea7915','嵩山二十四詠 積翠峰','樓异','宋','宋诗','song-poetry','','[]','翠幄籠雲自一家，蘿梯夜碾七香車。',32,'全唐诗/poet.song.71000.json','["翠幄籠雲自一家，蘿梯夜碾七香車。", "舉頭雨過餘霞散，綠芰池開菡萏花。"]'),
('3ae5bcd1-6f20-4b07-aac2-e5c080faf1cc','嵩山二十四詠 太白峰','樓异','宋','宋诗','song-poetry','','[]','仰攀日月風雲近，俯瞰岡巒培塿低。',32,'全唐诗/poet.song.71000.json','["仰攀日月風雲近，俯瞰岡巒培塿低。", "絕頂光芒長不斷，人言太白此中棲。"]'),
('120fadb9-62a1-4730-896e-df0b0f4b742d','存目','樓异','宋','宋诗','song-poetry','','[]','詩題：宿少林寺首句：六六仙峰繞佛居。',18,'全唐诗/poet.song.71000.json','["詩題：宿少林寺首句：六六仙峰繞佛居。"]'),
('17f31ace-4b6a-4346-892c-388f9c305d63','中秋','李朴','宋','宋诗','song-poetry','','["\u6708\u4eae", "\u4e2d\u79cb\u8282"]','皓魄當天曉鏡升，雲間仙籟寂無聲。',64,'全唐诗/poet.song.71000.json','["皓魄當天曉鏡升，雲間仙籟寂無聲。", "平分秋色一輪滿，長伴雲衢千里明。", "狡兔空從弦外落，妖蟆休向眼前生。", "靈槎擬約同携手，更待銀河徹底清。"]'),
('8900f6d5-9bd6-46d2-85de-eb3a302dfc91','次韵玉巖應詔  其一','李朴','宋','宋诗','song-poetry','','[]','天書遠下事徵求，鄉里同推馬少遊。',64,'全唐诗/poet.song.71000.json','["天書遠下事徵求，鄉里同推馬少遊。", "世事已非三不可，年華却是一宜休。", "豈緣薄祿貽身累，祇爲當時分主憂。", "筇杖芒鞋留我伴，佇聞談笑即封侯。"]'),
('f4174f7b-475b-4b47-9829-fe5c8b2016e0','次韵玉巖應詔  其二','李朴','宋','宋诗','song-poetry','','[]','擲餌求魚計亦難，長鯨摇曳海波寬。',64,'全唐诗/poet.song.71000.json','["擲餌求魚計亦難，長鯨摇曳海波寬。", "狂風有待三秋起，健翮須教萬里摶。", "直以逸民朝聖主，不隨計吏上春官。", "庖刀休用援尸祝，巾笥寧封貢禹冠。"]'),
('e8e1c5ad-b5a5-493f-b2bf-c15bf29d1dee','憶玉巖  其一','李朴','宋','宋诗','song-poetry','','[]','阿閣曾看紫鳳棲，暮年江國擁旌麾。',64,'全唐诗/poet.song.71000.json','["阿閣曾看紫鳳棲，暮年江國擁旌麾。", "孤雲南北本無定，浮世悲歡那可期。", "鶴頂丹砂埋藥竈，鴨頭綠水浸春陂。", "待公踏遍紅塵地，景物歸來似舊時。"]'),
('834d1973-839e-46b0-b71a-c52fba295d0b','憶玉巖  其二','李朴','宋','宋诗','song-poetry','','[]','秋風燕雀正關關，忽見籬邊菊又斑。',64,'全唐诗/poet.song.71000.json','["秋風燕雀正關關，忽見籬邊菊又斑。", "寒雁自知霜露重，海鷗常伴水雲閒。", "百年往事丹心裏，千古聲名直道間。", "此意屬公須慷慨，晚雲成雨便歸山。"]'),
('799c258c-8ab2-49d3-a69d-b1b7bfebdf1d','崆峒山','李朴','宋','宋诗','song-poetry','','[]','雲根秀出碧芙蓉，烟晃霞飛瑞靄中。',32,'全唐诗/poet.song.71000.json','["雲根秀出碧芙蓉，烟晃霞飛瑞靄中。", "地脈九枝龍奮蟄，天河一派練橫空。"]'),
('c6240637-e333-437d-8010-dbf6952b879c','天竺山','李朴','宋','宋诗','song-poetry','','[]','天竺崎嶇絕海邊，何人分作贛江禪。',64,'全唐诗/poet.song.71000.json','["天竺崎嶇絕海邊，何人分作贛江禪。", "鷲山巧疊三峰石，葛塢深疏兩派泉。", "一醉風光能幾許，十年塵跡尚依然。", "欲題豹隠還相笑，盼斷長空簇暝烟。"]'),
('4d509b96-b706-4903-a9b3-b4e25592d9a3','馬祖巖','李朴','宋','宋诗','song-poetry','','[]','踏盡層巒上小亭，日華初泛曉烟清。',32,'全唐诗/poet.song.71000.json','["踏盡層巒上小亭，日華初泛曉烟清。", "塵埃不到門常靜，身世相忘性自靈。"]'),
('2fa2971f-cce0-4170-9149-ee14781b731c','乞巧','李朴','宋','宋诗','song-poetry','','[]','處處香筵拂綺羅，爲傳神女渡天河。',64,'全唐诗/poet.song.71000.json','["處處香筵拂綺羅，爲傳神女渡天河。", "休嫌天上佳期少，已恨人間巧態多。", "齚舌自應工嫵媚，方心誰更苦鎸磨。", "獨收至拙爲吾事，笑指雙針一縷過。"]'),
('37555067-76b1-47c7-9b10-162d7d7835e9','八境臺','李朴','宋','宋诗','song-poetry','','[]','金弋百戰古虔州，滾滾雙江日夜流。',32,'全唐诗/poet.song.71000.json','["金弋百戰古虔州，滾滾雙江日夜流。", "杯酒登臺同極目，夕陽漁唱起沙鷗。"]'),
('635d4924-1533-476d-abda-1f261546222e','遊通天巖','李朴','宋','宋诗','song-poetry','','[]','春烟澄霽色，杖策出郊坰。',48,'全唐诗/poet.song.71000.json','["春烟澄霽色，杖策出郊坰。", "疊嶂浮空翠，孤雲罨斷青。", "燕銜泥作壘，僧結草爲亭。", "萬樹山風裏，鐘聲下界聽。"]'),
('3efe071a-2638-4cc2-a2c8-58037a825b47','和張祜韵','蔣瑎','宋','宋诗','song-poetry','','[]','野曠吳天杳，江浮楚夢吞。',48,'全唐诗/poet.song.71000.json','["野曠吳天杳，江浮楚夢吞。", "桂香飄露葉，松古兀霜根。", "碧薺他州樹，黄蘆何處村。", "世塵飛不到，清磬落空門。"]'),
('49ec2f10-ad05-411a-9407-454a32574e57','和孟郊韵','蔣瑎','宋','宋诗','song-poetry','','[]','依崖架僧坊，微雲冒經床。',48,'全唐诗/poet.song.71000.json','["依崖架僧坊，微雲冒經床。", "闊睨滄海潮，幽聆諸天香。", "遠水瀉空碧，層軒逗寒光。", "願言寄暮齒，永訣聲利場。"]'),
('05ac4c25-36fb-410c-8e4d-97eb7a8dfcfb','句','蔣瑎','宋','宋诗','song-poetry','','[]','誰知清淡者，冬月亦登臨。',12,'全唐诗/poet.song.71000.json','["誰知清淡者，冬月亦登臨。"]'),
('2a67580d-4014-488c-96fa-80b19b8bbb86','駕幸太學','李師德','宋','宋诗','song-poetry','','[]','墜典遺經已表章，又傳清蹕幸膠庠。',64,'全唐诗/poet.song.71000.json','["墜典遺經已表章，又傳清蹕幸膠庠。", "黄龍繞駕天移仗，白雪分袍士綴行。", "况是體元能作聖，更歡稽古效規王。", "太平盛世文明遠，萬國儒風自一堂。"]'),
('34f59b7f-7552-4e6e-b73c-4893825ce309','四頂山','張彥修','宋','宋诗','song-poetry','','[]','翠巒齊聳壓平湖，晚綠朝紅畫不如。',32,'全唐诗/poet.song.71000.json','["翠巒齊聳壓平湖，晚綠朝紅畫不如。", "寄語商山閑四皓，好來各占一峰居。"]'),
('6209c32e-0022-499a-8c57-2ad73ae98a8d','偈','都貺','宋','宋诗','song-poetry','','[]','不可思議，是大火聚。',20,'全唐诗/poet.song.71000.json','["不可思議，是大火聚。", "便恁麽去，不離當處。"]'),
('a63950c9-2ed9-4cae-a6e1-466f55a502be','三高堂','黄潛','宋','宋诗','song-poetry','','[]','三賢同一隠，所遇時則異。',24,'全唐诗/poet.song.71000.json','["三賢同一隠，所遇時則異。", "不居雲水鄉，詎泄英雄氣。"]'),
('4d74412d-934a-4a43-8b1c-5e6be6451032','九仙巖','阮之武','宋','宋诗','song-poetry','','[]','野老相傳有九仙，嘗遊此地忽昇天。',32,'全唐诗/poet.song.71000.json','["野老相傳有九仙，嘗遊此地忽昇天。", "霓旌鶴馭今何在，千古空巖鎖暮烟。"]'),
('49394057-d5a9-4534-a9e1-c3d76e40f0ab','漢遺愛廟碑','阮之武','宋','宋诗','song-poetry','','[]','楚續光輝存簡策，漢碑突兀鎖期思。',64,'全唐诗/poet.song.71000.json','["楚續光輝存簡策，漢碑突兀鎖期思。", "風雲會合當年事，簫鼓喧闐此日祠。", "弱嗣負薪廉節著，怪蛇膏劍德名垂。", "廟封又見標遺愛，子産英靈想已知。"]'),
('043b8400-9493-4cf1-b164-1de73b8f2b74','愚溪','阮之武','宋','宋诗','song-poetry','','[]','亭溪山號悉從吾，占得聲光萬古無。',32,'全唐诗/poet.song.71000.json','["亭溪山號悉從吾，占得聲光萬古無。", "不似零陵柳司馬，貶他好景亂名愚。"]'),
('218eaec8-ef18-418b-9cc9-54e0e42b3bb0','夕陽巖','阮之武','宋','宋诗','song-poetry','','[]','晉人僊去莫知春，依舊空巖鎖暮雲。',32,'全唐诗/poet.song.71000.json','["晉人僊去莫知春，依舊空巖鎖暮雲。", "西照滿前無限景，有誰能此憶瞿君。"]'),
('b36499d6-378f-4302-8a61-35f68b3f94e1','紫雲巖','阮之武','宋','宋诗','song-poetry','','[]','石磴蘿梯隠翠微，坐間時有紫雲飛。',32,'全唐诗/poet.song.71000.json','["石磴蘿梯隠翠微，坐間時有紫雲飛。", "紛紛郁郁來還去，難問瞿仙幾日歸。"]'),
('6bb6be6b-5c1e-423e-b815-be647a404cb1','石塘寺','阮之武','宋','宋诗','song-poetry','','[]','洗開無用木，放出自然屏。',48,'全唐诗/poet.song.71000.json','["洗開無用木，放出自然屏。", "一簇岡巒勢，多般人物形。", "金堅性難壞，玉潤色常青。", "得地生禪剎，休嗟在大坰。"]'),
('003e3e4f-57e2-4316-9105-cfcbe845763d','引烟塢','杜扞','宋','宋诗','song-poetry','','[]','行愛種桃處，濛濛罩輕素。',24,'全唐诗/poet.song.71000.json','["行愛種桃處，濛濛罩輕素。", "花深人不辨，似入迷仙路。"]'),
('a73bb683-de74-4511-9811-ebbece92ad4d','天澤源','杜扞','宋','宋诗','song-poetry','','[]','湛碧一泓深，潺湲瀉不斷。',24,'全唐诗/poet.song.71000.json','["湛碧一泓深，潺湲瀉不斷。", "高穹沛四時，派別環周半。"]'),
('9abe7946-4e51-46a9-9d99-8a2e3849e08f','句  其一','杜扞','宋','宋诗','song-poetry','','[]','鐵烏老龍挺，誰爲辨雌雄。',12,'全唐诗/poet.song.71000.json','["鐵烏老龍挺，誰爲辨雌雄。"]'),
('6e0043ed-c5d4-4f01-8ed8-4c2268a77ad6','句  其二','杜扞','宋','宋诗','song-poetry','','[]','倘使在南陽，應爲孔明石。',12,'全唐诗/poet.song.71000.json','["倘使在南陽，應爲孔明石。"]'),
('3c52841d-ba99-43f0-a19c-9fdcd137d6dc','句  其三','杜扞','宋','宋诗','song-poetry','','[]','應爲覽德歸，來儀化靈迹。',12,'全唐诗/poet.song.71000.json','["應爲覽德歸，來儀化靈迹。"]'),
('2bdf6b4c-5755-48db-8bd8-de85d37a64cf','句  其四','杜扞','宋','宋诗','song-poetry','','[]','波心石船並，中載白蓮馨。',12,'全唐诗/poet.song.71000.json','["波心石船並，中載白蓮馨。"]'),
('2bcb15f4-3cf4-4eac-8392-e257cfbe7dcc','句  其五','杜扞','宋','宋诗','song-poetry','','[]','上就巾子頭，軒昂成皂蓋。',12,'全唐诗/poet.song.71000.json','["上就巾子頭，軒昂成皂蓋。"]'),
('64ba3077-a8ca-4ae7-9594-b562de5d45b6','董鳳山','韓常卿','宋','宋诗','song-poetry','','[]','丹竈棋盤去不收，未知蹤跡爲誰留。',64,'全唐诗/poet.song.71000.json','["丹竈棋盤去不收，未知蹤跡爲誰留。", "烟霞空鎖樵人徑，松檜重陰古寺樓。", "怪木化龍雲雨夜，碧波涵月鏡潭秋。", "遼東夢斷無歸鶴，山自嵯峨水自流。"]'),
('e4fab6f9-38f9-4725-bd4c-070d3630635e','句','鄭琡','宋','宋诗','song-poetry','','[]','別有丹青圖不得，數聲漁笛月明中。',16,'全唐诗/poet.song.71000.json','["別有丹青圖不得，數聲漁笛月明中。"]'),
('2d59d8a1-40a4-459f-8668-d925745f5a7c','姜相峰','郭正','宋','宋诗','song-poetry','','[]','青山爲主身爲客，主人借客青山宅。',128,'全唐诗/poet.song.71000.json','["青山爲主身爲客，主人借客青山宅。", "白雲自在千里飛，長松不換三冬碧。", "藤枯誰與寫作龍，龜老何年化爲石。", "落花流水發源深，鳴雁過江悲晚色。", "家無妻子心無累，頂冒寒霜踵藏息。", "月明舞影聊盡歡，一點塵寰不留迹。", "儻來軒冕真可嗟，朝爲公卿暮逋謫。", "屈原賈誼爾爲誰，問君何似青山客。"]'),
('575e52a3-b0ca-4924-8bd4-7d8d28f954b6','句','王祈','宋','宋诗','song-poetry','','[]','葉垂千口劍，幹聳萬條鎗。',12,'全唐诗/poet.song.71000.json','["葉垂千口劍，幹聳萬條鎗。"]'),
('b504fa02-b78d-46a7-91f8-4247e777aa9b','句','劉彥和','宋','宋诗','song-poetry','','[]','五世登科只一家。',8,'全唐诗/poet.song.71000.json','["五世登科只一家。"]'),
('1ab76b8d-0269-457f-9924-522ebb9f8181','靈巖行','杜欽况','宋','宋诗','song-poetry','','[]','山迴路疑絕，林深祕巖扃。',144,'全唐诗/poet.song.71000.json','["山迴路疑絕，林深祕巖扃。", "鑿翠出金碧，開軒列雲屏。", "希有昔成道，久矣斯巖靈。", "法定卧蒼壁，白日穿空明。", "令威指泉竇，一鑿秋寒澄。", "定水供萬衆，不縮亦不盈。", "如公禪宗秀，於世本無營。", "聊爲出山雲，乘風無縱橫。", "坐令多寶藏，百神轉雷霆。", "夜月嘯彫虎，玉匣開晶熒。", "笑指八解池，外流中不傾。", "何必空山雷，始悟物我情。"]'),
('06a1c293-61cb-42ac-94b5-544b01a32606','朱氏天和堂','徐鶚','宋','宋诗','song-poetry','','[]','先生晦跡谷水東，志趣不與晉賢同。',96,'全唐诗/poet.song.71000.json','["先生晦跡谷水東，志趣不與晉賢同。", "遥聽鶴唳笑二陸，巢傾穴碎非爲工。", "浩然養素遠聲利，脫去羈束離樊籠。", "醉隠亭中二十載，桃紅李白摇春風。", "感時嘯詠聊自適，誰知富貴爲窮通。", "羨君高操超流俗，直疑變化稱朱公。"]'),
('0e4793bb-acf7-4692-9b88-925e278b1812','福聖觀','王介之','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','奔雷漱玉向高秋，長伴神仙出衆流。',64,'全唐诗/poet.song.71000.json','["奔雷漱玉向高秋，長伴神仙出衆流。", "下得碧山終未足，待歸滄海始應休。", "雲饒浄色依依斂，猿傍寒聲歷歷愁。", "別有千尋在何處，廬山南面虎溪頭。"]'),
('f910a1b3-3501-43e2-9360-1f144a48755e','維揚曉發','樊紱','宋','宋诗','song-poetry','','[]','殘月猶懸夜，開帆風若何。',48,'全唐诗/poet.song.71000.json','["殘月猶懸夜，開帆風若何。", "鳴鷄催曉色，舟子起吳歌。", "一曲清江上，三春別興多。", "野鷗無意緒，閒卧對滄波。"]'),
('d63ad034-d7af-4c11-990f-17c12d5caccb','三友堂','楊恬','宋','宋诗','song-poetry','','[]','此君高節貫春冬，山色泉聲旦暮同。',64,'全唐诗/poet.song.71000.json','["此君高節貫春冬，山色泉聲旦暮同。", "對面便爲三益友，終朝相伴一衰翁。", "病嫌細字無心讀，老厭閑花過眼空。", "頼有堂中不言客，冷顔常共北窗風。"]'),
('8be31b56-9883-46bb-9457-342b8f9877e9','和頓公','楊恬','宋','宋诗','song-poetry','','[]','昔居山中誰見親，青山對面同笑顰。',275,'全唐诗/poet.song.71000.json','["昔居山中誰見親，青山對面同笑顰。", "引泉養竹與爲友，徜徉不覺冬復春。", "三年相看不知厭，聲音笑貌無久新。", "雖非多聞與直諒，堂堂不愧琴張仁。", "已將物我等一致，政自兀兀忘吾身。", "離群索居亦已久，昔如形影今參辰。", "强託鳴琴寫風韵，欲憑妙筆摹精神。", "繡衣使者古君子，天球大訓東序珍。", "胡爲喻蜀久持節，登車攬轡勞拊循。", "朅來堂上寓幽賞，不爲豺虎埋雙輪。", "悠然獨酌對三友，更邀風月爲嘉賓。", "謝胐忘形許入室，李白對影成三人。", "寄謝山中五賢者，德不孤立當有鄰。", "寥寥千里十餘載，乃逢青眼屈復申。", "夷齊西周兩餓叟，展禽東魯一絀臣。", "引而高之自孔子，不爾埋沒隨埃塵。", "君不見黄梅嶺上一拳石，意氣已若驕峨岷。"]'),
('b1e4d0ac-da86-4f11-8978-992861fae26c','三友堂 山','宇文紹奕','宋','宋诗','song-poetry','','[]','峭拔聳青天，巍峨鎮方國。',24,'全唐诗/poet.song.71000.json','["峭拔聳青天，巍峨鎮方國。", "願與君爲友，萬古長一色。"]'),
('0f6b1981-97f1-434b-9b67-909a63963636','三友堂 泉','宇文紹奕','宋','宋诗','song-poetry','','[]','青泉出山下，到海流不息。',24,'全唐诗/poet.song.71000.json','["青泉出山下，到海流不息。", "願與君爲友，果行而育德。"]'),
('37f0041e-a2a0-497c-8bec-63e3427aa3d7','三友堂 竹','宇文紹奕','宋','宋诗','song-poetry','','[]','清淡不媚春，挺挺凌霜雪。',24,'全唐诗/poet.song.71000.json','["清淡不媚春，挺挺凌霜雪。", "願與君爲友，虛中而勁節。"]'),
('ce59e909-c0d2-4bbe-8152-925098d47955','三友堂 風','宇文紹奕','宋','宋诗','song-poetry','','[]','清風泠然來，襟袖皆披拂。',24,'全唐诗/poet.song.71000.json','["清風泠然來，襟袖皆披拂。", "願與君爲友，相見長及物。"]'),
('af8a1fd5-73f2-4acf-a36d-1c6bfeb5edef','三友堂 月','宇文紹奕','宋','宋诗','song-poetry','','[]','明月麗青天，羣星隠晶耀。',24,'全唐诗/poet.song.71000.json','["明月麗青天，羣星隠晶耀。", "願與君爲友，容光無不照。"]'),
('c666ebf4-0e3e-4d2a-8f09-79597b96b4a6','頌','釋克勤','宋','宋诗','song-poetry','','[]','使乎不辱命，臨機貴專對。',184,'全唐诗/poet.song.71000.json','["使乎不辱命，臨機貴專對。", "安禪捋虎鬚，著著超方外。", "不唯明窗下安排，掇向繩床拶嶮崖。", "拈椎豎拂奮雄辯，金聲玉振猶奔雷。", "九旬落落提綱宗，衲子濟濟長趨風。", "解粘去縛手段辣，驅耕奪食猶雍容。", "秋風忽作要歸去，了却武陵一段事。", "勃窣理窟乃胸中，行行不患無知己。", "臨行索我送行篇，要棘蓬與金剛圈。", "短歌須要十數丈，長句只消三兩言。", "金毛獅子解翻身，箇是叢林傑出人。", "不日孤峰大哮吼，五葉一花天地春。"]'),
('e5336adc-77fb-4318-8828-ffc54d0bce6f','偈五十三首  其一','釋克勤','宋','宋诗','song-poetry','','[]','蝸牛角上三千界，雲月溪山共一家。',32,'全唐诗/poet.song.71000.json','["蝸牛角上三千界，雲月溪山共一家。", "既爾業緣無避處，不如隨分納些些。"]'),
('776c5c73-8d3a-42d6-baae-27caa2b3a51e','偈五十三首  其二','釋克勤','宋','宋诗','song-poetry','','[]','平旦清晨五月一，吹起少林無孔笛。',64,'全唐诗/poet.song.71000.json','["平旦清晨五月一，吹起少林無孔笛。", "十方沙界坦然平，大地山河印印出。", "二祖曾不往西天，達磨曾不到梁國。", "大家共賀太平歌，摩訶般若波羅蜜。"]'),
('378943fa-6cda-401a-bd74-25b9d2824d3b','偈五十三首  其三','釋克勤','宋','宋诗','song-poetry','','[]','病遇良醫，饑逢王鱔。',20,'全唐诗/poet.song.71000.json','["病遇良醫，饑逢王鱔。", "醤裏得鹽，雪中送炭。"]'),
('fd029fa2-1ca9-47b3-8237-e84f1dd2faa6','偈五十三首  其四','釋克勤','宋','宋诗','song-poetry','','[]','只這是，大似撒沙向眼中。',61,'全唐诗/poet.song.71000.json','["只這是，大似撒沙向眼中。", "只這不是，還如注水向耳裏。", "直下無事，平地陷入。", "別有機關，墮坑落塹。", "祇園屈曲流泉急，鷲嶺巍峨雲出遲。"]'),
('2c7e650c-c72c-447c-a1ff-70f14003b89f','偈五十三首  其五','釋克勤','宋','宋诗','song-poetry','','[]','雲居開大爐韝，不止烹佛烹祖。',84,'全唐诗/poet.song.71000.json','["雲居開大爐韝，不止烹佛烹祖。", "但有一切持來，烈焰堆中辨取。", "是則當處平和，不是切宜退步。", "煅出金剛眼睛，直得乾坤獨露。", "雖然到者田地，須知向上一路。", "放將三聖瞎馿，踢殺大雄猛虎。"]'),
('6b0699ca-dc72-464b-92ec-90d3b61a711f','偈五十三首  其六','釋克勤','宋','宋诗','song-poetry','','[]','五月五日天中節，萬崇千妖俱殄滅。',48,'全唐诗/poet.song.71000.json','["五月五日天中節，萬崇千妖俱殄滅。", "眼裏拈却須彌山，耳裏拔出釘根楔。", "鍾馗小妹舞三臺，八臂那吒嚼生鐵。"]'),
('390fa3fa-2e5b-4a56-a7a4-10be1486f1c9','偈五十三首  其七','釋克勤','宋','宋诗','song-poetry','','[]','萬仞崖頭撒手，要須其人。',79,'全唐诗/poet.song.71000.json','["萬仞崖頭撒手，要須其人。", "千鈞之弩發機，豈爲鼷鼠。", "雲門睦州，當面蹉過。", "德山臨濟，誑謼閻閭。", "自餘立境立機，作窠作窟，故是滅胡種族。", "萬緣遷變渾閒事，五月山房冷似冰。"]'),
('d2f2384a-2e15-4775-b82c-06b00106336e','偈五十三首  其八','釋克勤','宋','宋诗','song-poetry','','[]','曹溪路上，天高地厚。',83,'全唐诗/poet.song.72000.json','["曹溪路上，天高地厚。", "少室峰前，土曠人稀。", "孤然獨坐冷蕭蕭，大野橫身風颯颯。", "眼見則瞎，耳聽則聾，口說則啞。", "雖然不出一毫端，含吐十虛無向背。", "東海鯉魚打一棒，忙忙匝地便爲霖。"]'),
('0b94633d-bae2-4cca-bf12-0b3e38af55e2','偈五十三首  其九','釋克勤','宋','宋诗','song-poetry','','[]','釋迦慳，彌勒富，八字打開無盡庫。',40,'全唐诗/poet.song.72000.json','["釋迦慳，彌勒富，八字打開無盡庫。", "拄杖子，化爲龍，赫日光中吐雲霧，遍界滂沱注甘雨。"]'),
('1eb78920-9907-4976-9c66-ddf226820ddc','偈五十三首  其一○','釋克勤','宋','宋诗','song-poetry','','[]','一二三四五六七，眼裏瞳人吹篳觱。',52,'全唐诗/poet.song.72000.json','["一二三四五六七，眼裏瞳人吹篳觱。", "七六五四三二一，石人木人眼淚出。", "七通八達，舉著便知。", "尚在見聞，隔靴抓痒。"]'),
('e9238a9e-5d72-4621-8e5b-8ed468065bbf','偈五十三首  其一一','釋克勤','宋','宋诗','song-poetry','','[]','鶻兒未出窠，已有摩霄志。',76,'全唐诗/poet.song.72000.json','["鶻兒未出窠，已有摩霄志。", "虎子未絕乳，已有食牛氣。", "況復羽翼成，況復牙爪備。", "奮迅即驚羣，八面清風起。", "一條脊梁硬似鐵，一條白棒掀天地。", "相與建法幢，展衲僧巴鼻。"]'),
('06b62d25-1c61-46ad-9df6-70a062e983ba','偈五十三首  其一二','釋克勤','宋','宋诗','song-poetry','','[]','天上月圓，萬象歷然。',76,'全唐诗/poet.song.72000.json','["天上月圓，萬象歷然。", "地下月半，觸途成現。", "見不見，包裹十虛尚餘半。", "聞不聞，透脫圓通徹本根。", "玉漏銅壺催不得，乾坤大地一枝燈。", "一處圓融一切處，無邊剎海更稜層。"]'),
('5b272409-4e76-4221-b1ca-ddd4cc081c37','偈五十三首  其一三','釋克勤','宋','宋诗','song-poetry','','[]','有句無句，超宗越格。',61,'全唐诗/poet.song.72000.json','["有句無句，超宗越格。", "如藤倚樹，銀山鐵壁。", "及至樹倒藤枯，多少人失却鼻孔。", "直饒收拾得來，已是千里萬里。", "風暖鳥聲碎，日高花影重。"]'),
('c23b2bc1-b485-4081-933a-e419db9ef775','偈五十三首  其一四','釋克勤','宋','宋诗','song-poetry','','[]','粥足飯足，飽柴飽水。',90,'全唐诗/poet.song.72000.json','["粥足飯足，飽柴飽水。", "廬陵米價高，山前麥熟未。", "盡乾坤剎海，都盧是箇自己。", "撒放眉毛眼睫間，直得放光動地。", "不是如來禪，亦非第一義，更說什麽衲僧巴鼻。", "爭如撒手懸崖，去却藥忌，且唱箇囉囉哩。"]'),
('66a1ab36-ea52-49b8-b334-3e7c87ad9c99','偈五十三首  其一五','釋克勤','宋','宋诗','song-poetry','','[]','玄機獨唱，截斷衆流。',177,'全唐诗/poet.song.72000.json','["玄機獨唱，截斷衆流。", "擺撥不拘，更無回互。", "直饒釋迦彌勒，不敢當頭著眼。", "倚天長劍，凜凜神威。", "杲日當空，澄澄光彩。", "無物不爲妙用，無法不是真乘。", "控佛祖大機，廓人天正眼。", "當陽顯示，只貴知歸。", "纔涉思量，白雲萬里。", "今日人天普集，對衆分明剖露。", "一處真，千處百處一時真。", "一句透，千句百句一時透。", "拈起也，乾坤岌嶪。", "放下也，海晏河清。", "不拈不放，萬仞峰頭高著眼，大千世界一浮漚。"]'),
('f98bf8e3-e243-4c6f-88bd-b6b7c67d8acb','偈五十三首  其一六','釋克勤','宋','宋诗','song-poetry','','[]','眨上眉毛蹉過，大似開眼尿床。',67,'全唐诗/poet.song.72000.json','["眨上眉毛蹉過，大似開眼尿床。", "現成公案放行，正是黠兒落節。", "恁麽不恁麽，總得曳尾靈龜。", "不是心，不是佛，不是物。", "虛空釘橛，離得許多閒門破戶。"]'),
('d695ad13-6eb5-4ed4-99da-64bb7dd5f84d','偈五十三首  其一七','釋克勤','宋','宋诗','song-poetry','','[]','一即一切，實際理地。',82,'全唐诗/poet.song.72000.json','["一即一切，實際理地。", "一切即一，本來無物。", "拈起也，吒吒沙沙。", "收下也，綿綿密密。", "三界長時獨露，十方無處容身。", "孤峰頂上倒行，十字街頭橫卧。", "目視雲霄則且置，魚行酒肆作麽生。"]'),
('7ac36900-2f31-4d1e-8425-209ceb643ea9','偈五十三首  其一八','釋克勤','宋','宋诗','song-poetry','','[]','覿面見得，在聖猶虧。',53,'全唐诗/poet.song.72000.json','["覿面見得，在聖猶虧。", "才涉關津，白雲萬里。", "諦實處不思議，綿密處同真際。", "把斷世界，無絲毫透漏，萬仞峰頭獨足立。"]'),
('c1b180df-26d1-41a7-a438-57cb3c0e7451','偈五十三首  其一九','釋克勤','宋','宋诗','song-poetry','','[]','孤迥峭巍巍，始終活鱍鱍。',55,'全唐诗/poet.song.72000.json','["孤迥峭巍巍，始終活鱍鱍。", "喚作禪道，祖佛眼中著屑。", "不喚作禪道，祖佛掘地覓天。", "從他千古萬古黑漫漫，填溝塞壑無人會。"]'),
('e09939a6-67ae-4d38-9baa-0b872b8b65bb','偈五十三首  其二○','釋克勤','宋','宋诗','song-poetry','','[]','舉無遺照，十方剎海目前觀。',88,'全唐诗/poet.song.72000.json','["舉無遺照，十方剎海目前觀。", "正體堂堂，大千同一真如境。", "各守本位去，山是山，水是水。", "互換投機去，星辰易位，佛祖潜蹤。", "兩處絕聱訛，二邊純莫立。", "無可不可，悉得安居。", "隨時應緣，凝然湛寂。"]'),
('ff125e7e-6298-49b3-93b6-94d76b3b9f21','偈五十三首  其二一','釋克勤','宋','宋诗','song-poetry','','[]','國無定亂之劍，四海晏清。',88,'全唐诗/poet.song.72000.json','["國無定亂之劍，四海晏清。", "門無白澤之圖，全家吉慶。", "若道有承恩力處，正是土上加泥。", "更或削迹吞聲，亦乃持南作北。", "到這裏縱橫十字，未免誵訛。", "據位投機，猶較些子。", "寒山逢拾得，撫掌笑咍咍。"]'),
('2ea08817-0e1b-4906-bb75-32b919994621','偈五十三首  其二二','釋克勤','宋','宋诗','song-poetry','','[]','通身是眼見不及，遍身是耳聞不徹。',72,'全唐诗/poet.song.72000.json','["通身是眼見不及，遍身是耳聞不徹。", "通身是口說不著，通身是心鑑不出。", "直饒盡大地明得，無絲毫透漏。", "猶在半途，據令全提。", "域中日月縱橫掛，一亙晴空萬古春。"]'),
('ce22a5d6-f5eb-4acc-bbd9-26089630ca0f','偈五十三首  其二三','釋克勤','宋','宋诗','song-poetry','','[]','當陽有路，祖佛共知。',94,'全唐诗/poet.song.72000.json','["當陽有路，祖佛共知。", "覿面相呈，見聞不隔。", "萬象不能藏覆，千聖無以等階。", "活鱍鱍絕承當，浄裸裸無回互。", "直饒棒如雨點，喝似雷奔，猶未動著向上闕棙在。", "瞎却諸聖眼，啞却山僧口。", "日午打三更，面南看北斗。"]'),
('c6b42b28-25cb-41d1-a488-1075e20e31d7','偈五十三首  其二四','釋克勤','宋','宋诗','song-poetry','','[]','大庾嶺頭，笑却成哭。',66,'全唐诗/poet.song.72000.json','["大庾嶺頭，笑却成哭。", "崇寧門下，哭却成笑。", "喫泉水，貴地脈。", "且要正眼流通，宗風不墜。", "所謂無常生死法，與我不相干。", "若能如是見，不用哭蒼天。"]'),
('53a5f06b-3022-4467-899a-df9c1690071a','偈五十三首  其二五','釋克勤','宋','宋诗','song-poetry','','[]','點即不到，一大藏教錦上鋪花。',46,'全唐诗/poet.song.72000.json','["點即不到，一大藏教錦上鋪花。", "到即不點，祖師西來金聲玉振。", "祖意教意，是同是別，碧潭雲外不相關。"]'),
('d6a5420a-217e-4da1-926b-3c4e2e149938','偈五十三首  其二六','釋克勤','宋','宋诗','song-poetry','','[]','三轉法輪於大千，其輪本來常清浄。',65,'全唐诗/poet.song.72000.json','["三轉法輪於大千，其輪本來常清浄。", "一切諸佛，皆恁麽轉。", "若向下去，三乘五性，頓漸偏圓。", "若向上去，不唯覓下口處不得。", "臨濟德山，目瞪口呿。"]'),
('316b2a24-f528-443d-a80e-563869465784','偈五十三首  其二七','釋克勤','宋','宋诗','song-poetry','','[]','入田不揀，三千里外黑漫漫。',75,'全唐诗/poet.song.72000.json','["入田不揀，三千里外黑漫漫。", "牛頭沒，馬頭回，百億萬劫沒交涉。", "拈一放一，節外生枝。", "舉古舉今，無風起浪。", "山僧今日，一時撥斷。", "千峰勢到嶽邊止，萬派聲歸海上消。"]'),
('96cd2d74-8b2f-40e4-aa39-9504ca416caa','偈五十三首  其二八','釋克勤','宋','宋诗','song-poetry','','[]','終日相逢無半面，剛然千里有知音。',88,'全唐诗/poet.song.72000.json','["終日相逢無半面，剛然千里有知音。", "不須格外論奇特，只此全機耀古今。", "傾蓋如舊，白頭如新。", "兩鏡相照，不隔纖塵。", "徧界未嘗示相，毫端普現色身。", "止猶谷神，動若行雲。", "相見又無事，不來還憶君。"]'),
('532f4d22-d4de-4b51-bf96-91fe3bcb40a2','偈五十三首  其二九','釋克勤','宋','宋诗','song-poetry','','[]','棒頭取證，撒土撒沙。',97,'全唐诗/poet.song.72000.json','["棒頭取證，撒土撒沙。", "喝下承當，承虛接響。", "向上向下，轉見顢頇。", "說妙談玄，和泥合水。", "這一片田地，分付來多時也。", "平地欺人，盡大地撮來，如粟米粒大。", "掉棒打月，佛祖凡聖，拈向一邊。", "紅霞穿碧落，白日繞須彌。"]'),
('b879d2c6-1688-4eee-a6d6-e1039da09cf3','偈五十三首  其三○','釋克勤','宋','宋诗','song-poetry','','[]','田地穩密底，擡脚不起，探頭太過。',76,'全唐诗/poet.song.72000.json','["田地穩密底，擡脚不起，探頭太過。", "神通妙用底，放脚不下，收身未轉。", "直饒十字縱橫，朝打三千，猶較些子。", "若知有去，始見全提半提。", "儻或未知，布袋裏老鴉雖活如死。"]'),
('733ba760-e3df-4efa-bc66-9b46ac1f2fdd','偈五十三首  其三一','釋克勤','宋','宋诗','song-poetry','','[]','殺人刀，活人劍。',97,'全唐诗/poet.song.72000.json','["殺人刀，活人劍。", "上古之風規，亦是今時之樞要。", "言句上作解會，泥裏洗土塊。", "不向言句上會，方木逗圓孔。", "未擬議，已蹉過。", "正擬議，隔關山。", "擊石火，閃電光。", "搆得搆不得，未免喪身失命。", "苦瓠連根苦，甜瓜徹蒂甜。"]'),
('5f7d3982-2d23-4c88-b730-52c40b17286f','偈五十三首  其三二','釋克勤','宋','宋诗','song-poetry','','[]','雲騰致雨，世界索然。',49,'全唐诗/poet.song.72000.json','["雲騰致雨，世界索然。", "日照天臨，乾坤廓爾。", "文殊臺裏，萬菩薩縱然顯現，晴是晴，雨是雨，山是山，水是水。"]'),
('e8800b90-1663-4000-9530-77e257a666b4','偈五十三首  其三三','釋克勤','宋','宋诗','song-poetry','','[]','眨上眉毛早蹉過，塞却眼。',80,'全唐诗/poet.song.72000.json','["眨上眉毛早蹉過，塞却眼。", "更形言語轉周遮，命取口。", "盡大地都爲一塵，佛眼覷不見。", "一大藏都爲一句，海口莫能宣。", "也未提得一半在，忽然踏破化城時。", "行到水窮處，坐看雲起時。"]'),
('9d1a6168-f54d-4cb9-a6df-4697b07c24fa','偈五十三首  其三四','釋克勤','宋','宋诗','song-poetry','','[]','目前無異草，徧界絕遮攔。',154,'全唐诗/poet.song.72000.json','["目前無異草，徧界絕遮攔。", "域中日月斬新，方外乾坤獨露。", "直得龍天釋梵，動地雨花。", "妙德空生，目瞪口呿。", "行棒行喝，拈放一邊。", "雲月溪山，放過一著。", "一處透，千處萬處該通。", "一機明，千機萬機圓轉。", "碧巖不離此處，此處不離碧巖。", "攝大千於毫端，融芥塵於剎海。", "含花鳥過，抱子猿歸。", "湛寂凝然，應真不借。", "萬卉正資和氣力，碧巖先發一枝香。"]'),
('08ca9383-982c-4fa9-8ee3-e2df6184d8a0','偈五十三首  其三五','釋克勤','宋','宋诗','song-poetry','','[]','高峰突兀倚天門，青嶂虛閒可垛跟。',32,'全唐诗/poet.song.72000.json','["高峰突兀倚天門，青嶂虛閒可垛跟。", "折脚鐺兒幸然在，不妨携去隠深雲。"]'),
('aabb7795-5b5c-4a37-9cf7-6dd42642ccda','偈五十三首  其三六','釋克勤','宋','宋诗','song-poetry','','[]','箇是毗耶據坐處，正同摩竭令行時。',48,'全唐诗/poet.song.72000.json','["箇是毗耶據坐處，正同摩竭令行時。", "夾山頂𩕳通一竅，放出天彭老古錐。", "衝浪錦鱗來入罟，縵天網舉不饒伊。"]'),
('f7e49aeb-b2a2-4ee5-895d-0479a7a0895b','偈五十三首  其三七','釋克勤','宋','宋诗','song-poetry','','[]','門外青山潑黛，途中細雨如膏。',201,'全唐诗/poet.song.72000.json','["門外青山潑黛，途中細雨如膏。", "靈雲陌上桃花，處處芳菲溢目。", "香嚴巖畔翠竹，時時撼影摇風。", "直得一擊忘所知，一見絕疑惑。", "不免尚留觀聽，未透聲色。", "若能見無見之色，聞無聞之聲。", "撥轉路頭，踏翻關捩。", "句句越佛越祖，塵塵耀古騰今。", "處處離色離名，箇箇斬釘截鐵。", "心外無法，法外無心。", "用王庫刀，發千鈞弩。", "壁立萬仞，坐斷十方。", "可以入大解脫門，傳正法眼藏。", "向堯時舜日，共樂昇平。", "鼓腹謳歌，歸家穩坐。", "但願春風齊著力，一時吹入我門來。"]'),
('25eecedd-39aa-40c2-aaef-94fdc8f2ce7c','偈五十三首  其三八','釋克勤','宋','宋诗','song-poetry','','[]','無事處生事，無佛處現佛，無祖處示祖。',46,'全唐诗/poet.song.72000.json','["無事處生事，無佛處現佛，無祖處示祖。", "且貴始末相符，頭正尾正。", "莫從百草巔頭薦，覿面無私亙古今。"]'),
('fb091672-a44d-4a78-a9fc-01e8c1ad36b5','偈五十三首  其三九','釋克勤','宋','宋诗','song-poetry','','[]','言言錦綉，句句珠璣。',46,'全唐诗/poet.song.72000.json','["言言錦綉，句句珠璣。", "讚無上乘，顯正法眼。", "應須未舉已前薦取，文彩之外承當。", "苟或未然，却請宣過。"]'),
('978ce205-1557-471f-a13a-b87b1aada6b3','偈五十三首  其四○','釋克勤','宋','宋诗','song-poetry','','[]','丁一卓二，本分鉗鎚。',68,'全唐诗/poet.song.72000.json','["丁一卓二，本分鉗鎚。", "捏聚放開，作家受用。", "灰頭土面處，壁立千仞。", "壁立千仞處，土面灰頭。", "自然雙放雙收，到處爲祥爲瑞。", "掬水月在手，弄花香滿衣。"]'),
('779354cd-dfd6-4ec1-b81e-bfcc9161b968','偈五十三首  其四一','釋克勤','宋','宋诗','song-poetry','','[]','太虛寥廓，萬彙森然。',66,'全唐诗/poet.song.72000.json','["太虛寥廓，萬彙森然。", "正眼洞明，纖毫不立。", "孤峻處祖師莫近，坦夷處人天共知。", "擊開大解脫門，識取無面目漢。", "芍藥花開菩薩臉，椶櫚葉散夜叉頭。"]'),
('80ffc142-c890-4e6e-bd13-2f447fff210d','偈五十三首  其四二','釋克勤','宋','宋诗','song-poetry','','[]','一向不恁麽，目視雲漢，不徇人情。',97,'全唐诗/poet.song.72000.json','["一向不恁麽，目視雲漢，不徇人情。", "一向恁麽，灰頭土面，带水拖泥。", "恁麽中不恁麽，就下平高。", "不恁麽中却恁麽，從空放下。", "或有箇恁麽不恁麽，總不管，亦無明，亦無暗，亦不放，亦不收。", "到頭霜夜月，任運落前溪。"]'),
('2ff0e3a6-76e7-4406-84a9-b25e58e004e4','偈五十三首  其四三','釋克勤','宋','宋诗','song-poetry','','[]','第一句下薦得，祖佛乞命。',82,'全唐诗/poet.song.72000.json','["第一句下薦得，祖佛乞命。", "第二句下薦得，人天膽落。", "第三句下薦得，虎口橫身。", "不是循途守轍，亦非革轍移途。", "透得則六臂三頭，未透亦人間天上。", "生涯只在絲綸上，明月扁舟泛五湖。"]'),
('4b1a3bb4-3e03-4cbc-a1d4-d5785b12d0b1','偈五十三首  其四四','釋克勤','宋','宋诗','song-poetry','','[]','大道無向背，至理絕言詮。',210,'全唐诗/poet.song.72000.json','["大道無向背，至理絕言詮。", "迥出三乘，高超十地。", "萬法不到處，特地光輝。", "生佛未分時，靈光獨耀。", "不落聞見，不隨色聲。", "直下無一絲毫頭，徧界全彰奇特事。", "直饒棒頭取證，喝下承當，猶是曲爲今時。", "更或光境俱忘，契心平等，畢竟亦非的旨。", "向上一路，千聖不傳。", "學者勞形，如猿捉影。", "理絕，事絕，行絕，照絕，用絕，權絕，實絕，直似倚天長劍，凜凜神威，鐵牛之機，牢籠不住。", "今日幸對明眼人前，不敢被蓋囊藏。", "八字打開去也，耀古騰今活鱍鱍，大千沙界露全身。"]'),
('0c92ec29-ce16-4a6e-b24f-80ca9cef23eb','偈五十三首  其四五','釋克勤','宋','宋诗','song-poetry','','[]','深深處，無物堪比倫。',60,'全唐诗/poet.song.72000.json','["深深處，無物堪比倫。", "淺淺箇，兩手相分付。", "以一統萬，穿衆穴於毫端。", "補短截長，握秤尺於掌內。", "意氣不從天地得，英雄豈藉四時推。"]'),
('d6d38374-d102-4eca-a0a5-2f181df3d7ba','偈五十三首  其四六','釋克勤','宋','宋诗','song-poetry','','[]','葉落知秋，動弦別曲。',60,'全唐诗/poet.song.72000.json','["葉落知秋，動弦別曲。", "定光拈手，智者點頭。", "承當於文彩未彰前，相照向是非得失外。", "不涉廉纖，如何通信。", "萬景徒有象，孤雲本無心。"]'),
('d8c257b5-2a9b-48a6-87b8-0fb0c9aca5fe','偈五十三首  其四七','釋克勤','宋','宋诗','song-poetry','','[]','玄玄玄，太顢頇。',72,'全唐诗/poet.song.72000.json','["玄玄玄，太顢頇。", "了了了，沒邊表。", "有生有滅，特地乖張。", "無去無來，轉見漏逗。", "不起寂滅定，而現諸威儀。", "不捨凡夫法，而修諸勝行。", "隨流認得性，無喜亦無憂。"]'),
('8b8e05f8-f20b-4508-8afb-788adfdb8ba6','偈五十三首  其四八','釋克勤','宋','宋诗','song-poetry','','[]','大人具大見，大智得大用。',72,'全唐诗/poet.song.72000.json','["大人具大見，大智得大用。", "一飛六月息，一諾千金重。", "滔天必江海，崔嵬必山岳。", "先知覺未知，先覺覺後覺。", "打開無盡藏，運出無價珍。", "不依倚一物，顯示本來人。"]'),
('0587c6cc-446f-4c19-b3a7-7d3a1c1b523d','偈五十三首  其四九','釋克勤','宋','宋诗','song-poetry','','[]','突出難辨，久參未免躇躕。',100,'全唐诗/poet.song.72000.json','["突出難辨，久參未免躇躕。", "信手拈來，後學那知端的。", "金風扇物，玉露垂珠。", "雁過長空，蛩吟幽砌。", "一一七穿八穴，明明百匝千重。", "何必棒喝交馳，方論照用。", "直下懸崖撒手，便有恁麽人麽。", "見義不爲非勇士，臨危不變始驚羣。"]'),
('77f874db-8e21-46cb-bb2a-fd589eaad533','偈五十三首  其五○','釋克勤','宋','宋诗','song-poetry','','[]','一切無收攝，觸處圓成。',85,'全唐诗/poet.song.72000.json','["一切無收攝，觸處圓成。", "應用絕參差，莫窮形相。", "向千聖頂𩕳上，有時露出佛祖莫窮底機關。", "於一毫端中，有時演出主賓互換底文彩。", "經天緯地，玉轉珠回。", "海神知貴不知價，留與人間光照夜。"]'),
('16aaf98d-6478-4f59-8b40-f98c048f156e','偈五十三首  其五一','釋克勤','宋','宋诗','song-poetry','','[]','一向孤峰獨宿，目視雲霄。',150,'全唐诗/poet.song.72000.json','["一向孤峰獨宿，目視雲霄。", "雖則不埋沒宗風，無乃太高生。", "一向十字路口，土面灰頭，利物應機。", "雖則埋沒自己，無乃太屈辱生。", "況明悟之士，頂門具眼，肘後有符。", "出沒卷舒，得大自在。", "動若浮雲，止猶谷神。", "或可以孤峰獨宿，不礙土面灰頭。", "或土面灰頭，不礙孤峰獨宿。", "恁麽中有不恁麽，不恁麽中却有恁麽。", "瑞氣逢嘉運，靈苗觸處春。"]'),
('143aebbf-cdbd-4684-a121-010c3c3a1d89','偈五十三首  其五二','釋克勤','宋','宋诗','song-poetry','','[]','古佛有通津，當陽亙古今。',24,'全唐诗/poet.song.72000.json','["古佛有通津，當陽亙古今。", "懸崖能撒手，一語直千金。"]'),
('2150fecd-ee09-40ee-82a5-4546807e1615','偈五十三首  其五三','釋克勤','宋','宋诗','song-poetry','','[]','行棒行喝，拽石搬土。',52,'全唐诗/poet.song.72000.json','["行棒行喝，拽石搬土。", "象骨輥毬，禾山打鼓。", "溈嶺牧牛，玄沙見虎。", "喫茶趙州，面壁魯祖。", "爭似老雲門，臘月二十五。"]'),
('affc24c5-0672-4d6f-825a-4ca54291acfd','偈五十三首  其五四','釋克勤','宋','宋诗','song-poetry','','[]','乾茆近火，理合先燋。',20,'全唐诗/poet.song.72000.json','["乾茆近火，理合先燋。", "滴水生冰，事不相涉。"]'),
('45ea2046-52a9-4855-8073-41bc6e09c322','頌','釋克勤','宋','宋诗','song-poetry','','[]','鼓寂鐘停托鉢回，巖頭一拶語如雷。',32,'全唐诗/poet.song.72000.json','["鼓寂鐘停托鉢回，巖頭一拶語如雷。", "果然只得三年活，莫是遭他受記來。"]'),
('74621623-4fda-4006-ba2d-600c57fa1d21','爲佛眼下火','釋克勤','宋','宋诗','song-poetry','','[]','如來涅槃日，娑羅雙樹間。',24,'全唐诗/poet.song.72000.json','["如來涅槃日，娑羅雙樹間。", "放出三昧火，闍維金色身。"]'),
('df98e846-7be0-4f4f-a0b7-b5a8899c5009','爲亡僧下火','釋克勤','宋','宋诗','song-poetry','','[]','五藴山頭涅槃路，四方八面沒遮攔。',32,'全唐诗/poet.song.72000.json','["五藴山頭涅槃路，四方八面沒遮攔。", "通身盡是金剛眼，一粒靈丹火裏燃。"]'),
('993cbe35-1833-4096-a674-e9e59063fda3','頌古七首 德山小參不答話。','釋克勤','宋','宋诗','song-poetry','','[]','大冶烹金，忽雷驚春。',100,'全唐诗/poet.song.72000.json','["大冶烹金，忽雷驚春。", "草木秀發，光輝日新。", "不費纖毫力，擒下天麒麟。", "全威殺活得自在，千古照耀同冰輪。", "話作兩橛，句中眼活。", "龍頭蛇尾，以指喻指。", "撞著露柱瞎衲僧，塞斷咽喉無出氣。", "擬議尋思隔萬山，咭嘹舌頭三萬里。"]'),
('b7abd2e7-7272-4b14-9780-eedc33ef61db','頌古七首 女子出定。','釋克勤','宋','宋诗','song-poetry','','[]','大定等虛空，廓然誰辨的。',85,'全唐诗/poet.song.72000.json','["大定等虛空，廓然誰辨的。", "女子與瞿曇，據令何調直。", "師子奮迅兮，摇乾蕩坤。", "象王回旋兮，不資餘力。", "孰勝孰負，誰出誰入。", "雨散雲收，青天白日。", "君不見馬駒踏殺天下人，臨濟未是白拈賊。"]'),
('a57cbed8-a60a-4d88-a748-a35f10a12898','頌古七首 須彌山。','釋克勤','宋','宋诗','song-poetry','','[]','石笋抽條，泥牛吼月。',47,'全唐诗/poet.song.72000.json','["石笋抽條，泥牛吼月。", "誰料同舟自胡越，應機涌出須彌盧。", "一念不生，何處雷，無處雪，金剛寶劍當頭截。"]'),
('2a5d4969-d086-4c62-82ce-21bf8ab22638','頌古七首 麻谷持錫到章敬又到南泉。','釋克勤','宋','宋诗','song-poetry','','[]','如是不是，去却藥忌。',36,'全唐诗/poet.song.72000.json','["如是不是，去却藥忌。", "擬犯封疆，全軍失利。", "杖頭突出古菱華，舉世風流出當家。"]'),
('728a6d9b-5eba-4145-b643-b161a87b11df','頌古七首 透網金鱗以何爲食。','釋克勤','宋','宋诗','song-poetry','','[]','百草頭出沒，三界外遨遊。',56,'全唐诗/poet.song.72000.json','["百草頭出沒，三界外遨遊。", "從布漫天網，虛下鈎鼇鈎。", "摇鱗振鬣撼乾坤，兀目昂頭洪浪噴。", "棒雨點，喝雷奔，肯將爭戰定功勳。"]'),
('9e3dff3f-e07a-430b-8fe8-e9ca718a5d2d','頌古七首 麻三斤。','釋克勤','宋','宋诗','song-poetry','','[]','鐘在扣谷受響，池印月鏡含僧。',63,'全唐诗/poet.song.72000.json','["鐘在扣谷受響，池印月鏡含僧。", "曾非展事投機，豈是預搔待癢。", "點鐵成金，舉直措枉。", "一箭鵰一雙，一摑血一掌。", "君不見疏而不漏兮恢恢天網。"]'),
('f3a72a8c-259f-4394-86f7-bd589771f7ea','頌古七首 雲門示衆云：人人盡有光明在。','釋克勤','宋','宋诗','song-poetry','','[]','夜明簾外千峰秀，鸞鏡臺前萬象虛。',52,'全唐诗/poet.song.72000.json','["夜明簾外千峰秀，鸞鏡臺前萬象虛。", "掃蹤滅跡，不立錙銖。", "誰爲佛殿，誰是香厨。", "敲出鳳凰五色髓，擊碎驪龍明月珠。"]'),
('9389871a-a935-4526-9aaf-22e69106a6db','偈三首  其一','釋克勤','宋','宋诗','song-poetry','','[]','金鴨香銷錦繡幃，笙歌叢裏醉扶歸。',32,'全唐诗/poet.song.72000.json','["金鴨香銷錦繡幃，笙歌叢裏醉扶歸。", "少年一段風流事，祇許佳人獨自知。"]'),
('51db2516-1046-4c72-a147-c4930a6d005f','偈三首  其二','釋克勤','宋','宋诗','song-poetry','','[]','本來無形段，那復有唇觜。',24,'全唐诗/poet.song.72000.json','["本來無形段，那復有唇觜。", "特地廣稱揚，替他說道理。"]'),
('8b09bb7f-99b3-4e57-a6e6-83d9f15d70a0','偈三首  其三','釋克勤','宋','宋诗','song-poetry','','[]','十方同聚會，本來身不昧。',48,'全唐诗/poet.song.72000.json','["十方同聚會，本來身不昧。", "箇箇學無爲，頂上用鉗鎚。", "此是選佛場，深廣莫能量。", "心空及第歸，利劍不如錐。"]'),
('5b498148-997b-47fe-93f5-1117071776cc','偈','釋克勤','宋','宋诗','song-poetry','','[]','休誇四分罷楞嚴，按下雲頭徹底參。',64,'全唐诗/poet.song.72000.json','["休誇四分罷楞嚴，按下雲頭徹底參。", "莫學亮公親馬祖，還如德嶠訪龍潭。", "七年往返游昭覺，三載翱翔上碧巖。", "今日煩充第一座，百華叢裏現優曇。"]'),
('d8b0175d-2142-491e-a620-0665c602c08d','示善友','釋克勤','宋','宋诗','song-poetry','','[]','此段本來無向背，要須堅猛力行持。',32,'全唐诗/poet.song.72000.json','["此段本來無向背，要須堅猛力行持。", "金剛正眼通身是，萬境來侵莫管伊。"]'),
('a51dd7b2-f203-4f7b-9a3b-a64013a6a381','頌古聯珠','釋克勤','宋','宋诗','song-poetry','','[]','雪峰騎駿馬，雲門跨馿兒，一踢一踏相奔馳。',36,'全唐诗/poet.song.72000.json','["雪峰騎駿馬，雲門跨馿兒，一踢一踏相奔馳。", "長安有路非無路，夜半行時人不知。"]'),
('178d320c-c346-4083-aa02-80ac391281f4','偈','釋克勤','宋','宋诗','song-poetry','','[]','收光攝彩信尺真，事事圓成物物新。',32,'全唐诗/poet.song.72000.json','["收光攝彩信尺真，事事圓成物物新。", "內若有心還有物，何能移步出通津。"]'),
('b2052705-e6a9-498c-8058-f1656aa2e74d','贈思浄律師','釋克勤','宋','宋诗','song-poetry','','["\u897f\u6e56"]','百萬齋才了正因，大緣倏舉只逡巡。',64,'全唐诗/poet.song.72000.json','["百萬齋才了正因，大緣倏舉只逡巡。", "鑿將瑪瑙一方石，鎸作龍華百尺身。", "天竺江山增秀麗，西湖風月愈清新。", "色聲不動操能事，可是僧中英特人。"]'),
('bfa2d5c0-9616-42b3-89d5-91e7c8f98420','句','釋克勤','宋','宋诗','song-poetry','','[]','庵前永日無狼子，磨下終年絕雀兒。',16,'全唐诗/poet.song.72000.json','["庵前永日無狼子，磨下終年絕雀兒。"]'),
('5f436e67-635d-41da-947b-1cd974f8e251','宿皇恐灘','黄得禮','宋','宋诗','song-poetry','','[]','倦客逢長至，扁舟泊遠灘。',24,'全唐诗/poet.song.72000.json','["倦客逢長至，扁舟泊遠灘。", "居常諳寂寞，童稚笑相歡。"]'),
('740551a4-df9c-4c20-93de-d56585644167','慈雲寺','朱褒','宋','宋诗','song-poetry','','[]','崩崖落雲外，怪石相支撐。',144,'全唐诗/poet.song.72000.json','["崩崖落雲外，怪石相支撐。", "穿林出蒙密，忽有青山橫。", "古寺瞰山腹，飛簷浮太清。", "寒流出其右，㶁㶁沿階鳴。", "我昔作勝遊，芒鞋弄飛徑。", "今來四十年，白首徒自驚。", "高僧延我入，巾冠聳崢嶸。", "假榻寄清夢，飛泉夜澎轟。", "殘燈聞弈棋，勝負時紛爭。", "機心亦何有，戰罷謾虧成。", "鐘聲隨曉風，昴宿西南傾。", "驪駒僕在門，吾亦問歸程。"]'),
('3d4d4b21-bbdd-4bc4-9281-45f0b506e125','和曾密公江樓詩韵','朱褒','宋','宋诗','song-poetry','','[]','太史聲名重，江樓昔有言。',120,'全唐诗/poet.song.72000.json','["太史聲名重，江樓昔有言。", "詩清排屈宋，意古挹羲軒。", "飛棟蒼雲合，窺魚白羽翻。", "臺高縈水府，氣爽返梅魂。", "市遠風埃潔，川腴草木繁。", "滄浪初出日，瓠落可浮樽。", "曲岸疏帆影，枯槎隠燒痕。", "秋容天漠漠，春意雨昏昏。", "地易規模在，碑新典則存。", "溪山重入座，先哲豈虛論。"]'),
('5429b4e8-d88c-46a8-9bc6-a4a7dcd03540','錦屏峰','鄭南','宋','宋诗','song-poetry','','[]','霍童佳境本天成，十里蓮花遍處生。',32,'全唐诗/poet.song.72000.json','["霍童佳境本天成，十里蓮花遍處生。", "山色依然仙不至，月明徒自憶吹笙。"]'),
('9a0d452d-202c-4426-a862-611d360c0a41','浮雲樓','張之才','宋','宋诗','song-poetry','','[]','安州水西寺，李白舊題詩。',24,'全唐诗/poet.song.72000.json','["安州水西寺，李白舊題詩。", "今古已堪嘆，風烟獨昔時。"]'),
('736aed48-3c2f-438b-bcbc-b9b7139850a9','去任辭湯廟','張之才','宋','宋诗','song-poetry','','[]','一官來此四經春，不愧蒼天不愧民。',32,'全唐诗/poet.song.72000.json','["一官來此四經春，不愧蒼天不愧民。", "神道有靈應信我，去時猶似到時貧。"]'),
('ea064515-302a-4970-9676-d13e0f740081','慧聚雜題 乘初遊慧聚到翠屏軒上月華轉上方及翠微閣日已晚矣不容他訪乃歸','李乘','宋','宋诗','song-poetry','','[]','兩月寓崑山，耳目厭煩鬧。',264,'全唐诗/poet.song.72000.json','["兩月寓崑山，耳目厭煩鬧。", "飲啄落樊中，多嚬少嬉笑。", "歲節簿書稀，慧聚富清峭。", "願偷一日閒，進步訪殊調。", "石臺出神功，殿宇自梁詔。", "勝境布高低，雖難亦容造。", "平閣翠屏軒，蒼然插峰嶠。", "滿眼歲寒物，將迎若盟要。", "新閣亦虛明，隠顯入憑眺。", "乾坤指顧閒，孫登一長嘯。", "迤邐上月華，老碧倚烟奧。", "夜半誰有力，負鼇族嵩少。", "層層轉上方，冰巖隠諸妙。", "嵌崆本自然，不鑿混沌竅。", "方寸有泓泉，清徹宛秦照。", "幾次菖蒲風，爲解衆生躁。", "別有古道場，數級下移趠。", "石佛夢中來，天手造容貌。", "於此稍盤桓，平昔恨難到。", "欲擲下山筇，儘作霧中豹。", "奈何苟祿身，未得從吾好。", "他日龍眠山，相期有耕釣。"]'),
('ec588e49-1b5f-4d1c-9b03-bb7342349789','慧聚雜題 依孟東野韵','李乘','宋','宋诗','song-poetry','','[]','千山貯雲房，瓶鉢安空床。',48,'全唐诗/poet.song.72000.json','["千山貯雲房，瓶鉢安空床。", "野籟有真響，天葩無世香。", "巢鸛羽翎老，睡僧眉宇光。", "此外足憂喜，勞勞榮辱場。"]'),
('db9dc2d1-8588-4ed4-b5e3-31fe926d5483','慧聚雜題 依張承吉韵','李乘','宋','宋诗','song-poetry','','[]','一寺皆樓殿，雖雄向此吞。',48,'全唐诗/poet.song.72000.json','["一寺皆樓殿，雖雄向此吞。", "雲霞終日影，檜柏幾年根。", "檻俯水烟國，磬傳鷄犬村。", "倚窗翻貝葉，宴寂屬空門。"]'),
('04bb02a4-b449-40e2-8a82-359834afe344','慧聚雜題 壓雲軒依張朝奉韵','李乘','宋','宋诗','song-poetry','','[]','路峻山窮頂，巖低木露梢。',48,'全唐诗/poet.song.72000.json','["路峻山窮頂，巖低木露梢。", "半天修日觀，一室分枝巢。", "帆去歸漁市，鐘來報寺庖。", "世閒榮悴事，寒暑轉烟郊。"]'),
('fea4cb24-67c5-4641-854d-e3628a741803','慧聚雜題 又依朱秀才韵','李乘','宋','宋诗','song-poetry','','[]','金闕山頭闢一軒，軒閒身世兩超然。',64,'全唐诗/poet.song.72000.json','["金闕山頭闢一軒，軒閒身世兩超然。", "階臨靄靄張公市，簷接青青廣樂天。", "風聒近林容虎嘯，雨腥低洞有龍眠。", "坐看起處分明甚，不羨王維到水邊。"]'),
('1badfcea-a003-4615-ab61-f55531d56f33','慧聚雜題 翠微庵','李乘','宋','宋诗','song-poetry','','[]','勝境增添豈偶然，已前無屋事金僊。',64,'全唐诗/poet.song.72000.json','["勝境增添豈偶然，已前無屋事金僊。", "巨靈擘到三千丈，嚮老基來八百年。", "遠遠別山來白足，重重峻宇出青蓮。", "端嚴石像庵猶在，若箇尋庵復坐禪。"]'),
('4f945324-8d8f-4f92-91bb-14e2a5a3ad7c','慧聚雜題 靈山講堂','李乘','宋','宋诗','song-poetry','','[]','佛度億萬衆，山是說經所。',48,'全唐诗/poet.song.72000.json','["佛度億萬衆，山是說經所。", "今人說猊座，亦作潮音主。", "何必諸比丘，曾見五花雨。", "面壁無說人，家風自一祖。"]'),
('4cde8c3d-4b7b-4287-9ec0-0895eac15617','慧聚雜題 月華閣','李乘','宋','宋诗','song-poetry','','[]','依稀瑶徑通雲隙，蘚石模糊數千尺。',96,'全唐诗/poet.song.72000.json','["依稀瑶徑通雲隙，蘚石模糊數千尺。", "昂者如飛俯者馳，疊疊寒空翠光滴。", "影高中逗日月輝，陰助草靈春不識。", "王屋壺中體淺深，來者增添愛山僻。", "有人隠几每忘饑，姓名自愧樊中客。", "結廬縱擬續琴歌，却憶猿驚舊山側。"]'),
('fb83fd35-0d4f-4716-a5d8-a3f50d28f009','慧聚雜題 東齋','李乘','宋','宋诗','song-poetry','','[]','峭絕山根野水旁，欄干瞰水有山房。',64,'全唐诗/poet.song.72000.json','["峭絕山根野水旁，欄干瞰水有山房。", "魚藏似識秋風冷，僧睡那知世路忙。", "金磬一聲清戀竹，石磯數級碧皴霜。", "恥罍未忍輕歸去，班嗣垂綸此興長。"]'),
('257a0b23-0b51-4483-8a5b-4da576688945','慧聚雜題 又依向主簿韵','李乘','宋','宋诗','song-poetry','','[]','鷺飛萬頃碧光中，楚楚緇廬枕水窮。',64,'全唐诗/poet.song.72000.json','["鷺飛萬頃碧光中，楚楚緇廬枕水窮。", "事外有緣三徑邃，眼前無礙九霄通。", "轉山僧道筇携雨，載月漁歸席挂風。", "一切世間虛幻事，隔堤請看數枝紅。"]'),
('1dfa6235-317d-4a9e-9c27-139840e8abb8','慧聚雜題 巖陰堂','李乘','宋','宋诗','song-poetry','','[]','寒帚高懸絕點埃，貯藏秋色枕山隈。',64,'全唐诗/poet.song.72000.json','["寒帚高懸絕點埃，貯藏秋色枕山隈。", "僧眠石室衣生霧，客步莎庭跡印苔。", "占竹鴛雛容得老，采花蜂蝶枉教來。", "澄懷觀道如癡者，兀坐忘歸忽自咍。"]'),
('a70d76e0-b4c9-42f3-b229-b820f8597146','慧聚雜題 慧照堂','李乘','宋','宋诗','song-poetry','','[]','眼亦不碌碌，耳亦不碌碌。',48,'全唐诗/poet.song.72000.json','["眼亦不碌碌，耳亦不碌碌。", "雲外野鳴幽，霜中歲寒綠。", "何必面南山，真理明明足。", "客問慧照名，僧拈一枝菊。"]'),
('0301f403-c657-45b9-a456-98a4144719fb','慧聚雜題 少林堂','李乘','宋','宋诗','song-poetry','','[]','無欠無餘丈室幽，雞鳴而動晦而休。',64,'全唐诗/poet.song.72000.json','["無欠無餘丈室幽，雞鳴而動晦而休。", "利名涉處塵塵熱，香火緣中日日秋。", "祇解結跏臨竹石，懶將叉手對公侯。", "有人來問禪宗旨，告道明明百草頭。"]'),
('338bbdca-aa95-48f0-820d-1741f5b7569c','慧聚雜題 素琴堂','李乘','宋','宋诗','song-poetry','','[]','長官髮已星，强持牧羊箠。',144,'全唐诗/poet.song.72000.json','["長官髮已星，强持牧羊箠。", "故山荒草堂，爲貧不知恥。", "衮衮敲朴庭，纓裾漬塵滓。", "子賤敬可高，七弦不離指。", "今日到僧房，陰森翠堆几。", "數拳解巑岏，一泓粗清泚。", "瑞草不知名，芬我勝蘭芷。", "天籟更自然，世音亦何俚。", "長官趣如何，依稀琴在此。", "返思子賤琴，未免尚宮徵。", "彈與不彈間，一切聊爾耳。", "兀坐縱無言，湯湯寓流水。"]'),
('4b2f1374-0626-4970-84d7-4d083492d970','慧聚雜題 翠屏軒','李乘','宋','宋诗','song-poetry','','[]','軒對山開晝不扃，山迎軒聳展如屏。',64,'全唐诗/poet.song.72000.json','["軒對山開晝不扃，山迎軒聳展如屏。", "高低樓閣安三寶，向背峰巒荷五丁。", "秋雨松林成水墨，春風花谷具丹青。", "誰人坦腹來高枕，笑傲羲皇任醉醒。"]'),
('6a51eef7-e803-4593-a896-00e7db038170','慧聚雜題 連雲閣','李乘','宋','宋诗','song-poetry','','[]','摇摇曳曳白雲輕，檐外多般弄晦晴。',64,'全唐诗/poet.song.72000.json','["摇摇曳曳白雲輕，檐外多般弄晦晴。", "龍與去來無定影，僧將舒卷伴真情。", "雪留瑩徹層霄在，雲散森羅萬象清。", "試問主僧還解否，毗耶消息甚分明。"]'),
('f0d529b8-a6c3-4fe6-8c7a-e799c9f0f8cb','慧聚雜題 西齋','李乘','宋','宋诗','song-poetry','','[]','老後名山付卧遊，偶携謝屐此尋幽。',64,'全唐诗/poet.song.72000.json','["老後名山付卧遊，偶携謝屐此尋幽。", "每思南岳嘲周子，何暇東林訪惠休。", "苔護出生蒼石老，竹供延客碧雲秋。", "主僧不用貪行脚，祇此林間可白頭。"]'),
('ffabfcaf-185f-4e15-84a0-988ec96e3c3a','慧聚雜題 淩峰閣','李乘','宋','宋诗','song-poetry','','[]','海上飛來據馬鞍，靈鼇獨坐碧孱顔。',64,'全唐诗/poet.song.72000.json','["海上飛來據馬鞍，靈鼇獨坐碧孱顔。", "幾年真宰雕鎸就，盡日高僧指顧間。", "去市紅塵三里遠，供人青眼一軒慳。", "半峰有窟龍爲宅，雲在檐頭恣往還。"]'),
('2f1c37d6-877d-4907-ab0a-3eb803a088ac','慧聚雜題 夕秀軒','李乘','宋','宋诗','song-poetry','','[]','逍遥金地與人疏，山靜風光碧有餘。',64,'全唐诗/poet.song.72000.json','["逍遥金地與人疏，山靜風光碧有餘。", "開築當年看錫卓，焚修今日聽星居。", "靈株瑞草人難識，明月清風室更虛。", "坐久半天瓊珮響，泠泠此理屬真如。"]'),
('b5c9f5a4-f4d6-49e6-82bc-373b07b1cd1f','慧聚雜題 西庵','李乘','宋','宋诗','song-poetry','','[]','野蔓盤青上短檐，客來徑草旋鉏芟。',64,'全唐诗/poet.song.72000.json','["野蔓盤青上短檐，客來徑草旋鉏芟。", "禽饑聞磬來疏砌，僧飽携筇過別巖。", "茶鼎引烟熏紙帳，竹窗漏月射經函。", "西庵門外如何景，杳杳寒涇一葉帆。"]'),
('d5d4b448-e5a1-481d-8925-335255698e14','潯州','蕭刓','宋','宋诗','song-poetry','','[]','自廣直邕分十郡，綿龔引象列三江。',32,'全唐诗/poet.song.72000.json','["自廣直邕分十郡，綿龔引象列三江。", "水歸東海流無盡，山拱西祠勢若降。"]'),
('219f43ec-8b8c-46e6-98a1-d38898ca0c0a','鳳山','謝黻','宋','宋诗','song-poetry','','[]','高臺伊昔來鳳凰，於今鳳去臺亦荒。',64,'全唐诗/poet.song.72000.json','["高臺伊昔來鳳凰，於今鳳去臺亦荒。", "蒼蒼竹實有霜露，颯颯梧葉生秋凉。", "西風斜日開晴色，閒步瑶階訪仙蹟。", "道人誦罷蕊珠經，老鶴一聲山月白。"]'),
('2069c6c2-5fb6-4780-aeab-b5c2bce6b58b','東山','謝黻','宋','宋诗','song-poetry','','[]','東山一何高，他山不足論。',168,'全唐诗/poet.song.72000.json','["東山一何高，他山不足論。", "其間有玖石，乃是世人珍。", "時與我數友，登高看嶙峋。", "悠然嘆黄鵠，飛及下山雲。", "我友今年歸，寂絕車馬塵。", "問言家何許，正與此山鄰。", "想爲携蠟屐，自往窮朝昕。", "斯遊孰可陪，有意徒殷勤。", "門前一溪水，清徹多遊鱗。", "安得尺素書，問訊情所親。", "四時且終窮，明日是青春。", "便作隔歲別，感懷意未伸。", "郊原共遊地，我獨行逡巡。", "重來望東山，晤語焉可聞。"]'),
('8498afbd-d730-44b9-befb-92fb3d2c2dc0','贈林子山','畢漸','宋','宋诗','song-poetry','','[]','兒童聞說子山名，將謂先生是古人。',64,'全唐诗/poet.song.72000.json','["兒童聞說子山名，將謂先生是古人。", "海上偶經仙洞府，巖前猶見玉精神。", "南華久徹逍遥夢，兜率重來自在身。", "携得新詩天上去，不教辜負到全閩。"]'),
('1fa69d58-4b04-42e5-b6b4-4bf0aeb1df89','江樓  其一','王絪','宋','宋诗','song-poetry','','[]','太史常揮醉筆，題詩遍滿江樓。',28,'全唐诗/poet.song.72000.json','["太史常揮醉筆，題詩遍滿江樓。", "勝事盡隨流水，白蘋依舊滄洲。"]'),
('7c830aae-1849-4f2b-96be-113d107c9ed6','江樓  其二','王絪','宋','宋诗','song-poetry','','[]','春晚幽花對浦，夜闌明月當軒。',28,'全唐诗/poet.song.72000.json','["春晚幽花對浦，夜闌明月當軒。", "好在當年勝趣，登臨盡屬諸孫。"]'),
('c60fb176-74d4-40fa-ba24-0b3710e615df','北園載酒和邑宰蔡確韵','徐迪','宋','宋诗','song-poetry','','[]','簷影蔭游魚，江聲顫崖竹。',96,'全唐诗/poet.song.72000.json','["簷影蔭游魚，江聲顫崖竹。", "雲帆天外去，龍剎空中矗。", "霞明晚渡紅，草暖晴沙綠。", "澄波見歸鳥，紛靄迷飛鶩。", "有時雪浪吹，玉馬爭追逐。", "青霄皓月滿，琉璃瑩極目。", "謝傅昔出宰，天葩動驚俗。", "一讀梁間詩，清風感佳木。"]'),
('935448e5-ad1b-4cef-a59f-456615aafcca','句','湛執中','宋','宋诗','song-poetry','','[]','人在蓬壺頹白玉，地連兜率布黄金。',16,'全唐诗/poet.song.72000.json','["人在蓬壺頹白玉，地連兜率布黄金。"]'),
('63608e87-bb5c-4ddd-b94e-b6fcfbe61d1b','建炎丞相成國呂忠穆公退老堂詩  其一','胡邃','宋','宋诗','song-poetry','','[]','名重功高服搢紳，精神圖畫在麒麟。',64,'全唐诗/poet.song.72000.json','["名重功高服搢紳，精神圖畫在麒麟。", "去提黼扆還天子，歸與園林作主人。", "三徑松筠供嘯傲，一堂風月替囂塵。", "時平自有無窮事，誰解如公早退身。"]'),
('85099153-00ee-451e-9e9f-28353d5401b2','建炎丞相成國呂忠穆公退老堂詩  其二','胡邃','宋','宋诗','song-poetry','','[]','戡定兵戈古所難，盛名何啻重於山。',64,'全唐诗/poet.song.72000.json','["戡定兵戈古所難，盛名何啻重於山。", "收身矢石征誅外，放意林泉杳靄間。", "曾是神龍猶解蟄，豈惟飛鳥會知還。", "上方當宁思元老，正恐詢謀未許閑。"]'),
('87c4dee7-7bb4-479f-bd7a-665176fd870a','送李元中','洪朋','宋','宋诗','song-poetry','','[]','夙聞龍眠山，綠蘿隠浄嘯。',132,'全唐诗/poet.song.72000.json','["夙聞龍眠山，綠蘿隠浄嘯。", "中有三李君，若人年獨妙。", "心賞悵若遺，風期可同調。", "如何古豫章，邂逅共一笑。", "佛海穿溟涬，理窟刮奧窔。", "茗椀對濤江，床跗視雲嶠。", "足明青葱樹，合在紅塵表。", "追隨杖屨遨，浩蕩城郭眺。", "觀乎大寧作，頗復近道要。", "凉飆隕疏葉，行子動歸棹。", "願君崇明德，慰我記末照。"]'),
('b25ec6b9-1352-4b3c-adc1-f3f643592a02','送謝無逸還臨川','洪朋','宋','宋诗','song-poetry','','[]','東山謝安石，事業照星斗。',180,'全唐诗/poet.song.72000.json','["東山謝安石，事業照星斗。", "佳人臨川秀，自言乃其後。", "昔我未知子，籍甚大江右。", "邇來識君面，風流故自有。", "早歲翰墨場，揮灑不停手。", "河發崑崙丘，風怒土囊口。", "春來入詩壘，窺杜逮戶牖。", "筆力挾雷霆，句法佩瓊玖。", "起予虞帝韶，和汝秦人缶。", "少年厲鋒氣，鄙夫成老醜。", "人才古所難，吾子定不朽。", "清和四月夏，銷黯一樽酒。", "悠悠西峰雲，闇闇南浦柳。", "平生六藝耕，勿遣生稂莠。", "鼓枻黄花秋，慰此長回首。"]'),
('cfbd9cdc-8a5c-42d5-8b13-bc292288d39f','送潘四十五','洪朋','宋','宋诗','song-poetry','','[]','風邊藥氣濃，烟畔柳枝弱。',48,'全唐诗/poet.song.72000.json','["風邊藥氣濃，烟畔柳枝弱。", "惜許兩春事，潘郎行色作。", "維南有岑嶺，底處端州郭。", "客子何當歸，莫待蕉花落。"]'),
('c464e75a-cb5c-4e43-8273-31ba51785de7','奉諸同人餞潘氏兄弟賦鳳凰鳴矣于彼高岡爲韵得凰字','洪朋','宋','宋诗','song-poetry','','[]','維南斗日月，川嶽上景光。',144,'全唐诗/poet.song.72000.json','["維南斗日月，川嶽上景光。", "何人赤壁下，種此雙截肪。", "故知汝南士，蚤經許子將。", "識君陟釐間，想見頎而長。", "僧夏滕叔國，故床對清揚。", "膜外齊鵬鷃，胸次明冰霜。", "佛界獅子尾，妙處亦難忘。", "西江渺波瀾，索去有底忙。", "挽衣不得留，晨風動餘皇。", "頃投膠在漆，今爲參與商。", "能事鏡中像，此道何足臧。", "古來歸根地，相期未渠央。"]'),
('aa5b551c-0688-462f-95c6-fc8dec322367','游南汰寺','洪朋','宋','宋诗','song-poetry','','[]','南汰舟楫遠，北城阡陌長。',120,'全唐诗/poet.song.72000.json','["南汰舟楫遠，北城阡陌長。", "蓮界劃然開，珍木蔭寬凉。", "暝投上方宿，蝙蝠遶屋梁。", "天風激遠林，秋氣生寒螿。", "喚起曲肱夢，佛寺宣道場。", "像設儼古殿，四角金琅璫。", "夙聞阿羅漢，光怪發清揚。", "有相乃虛妄，此妙不易量。", "勝概令弟俱，茗碗對胡床。", "商略終宇宙，已矣言可忘。"]'),
('de504d22-c0cd-4039-8db7-79a1c5d50de7','賦雙劍峰','洪朋','宋','宋诗','song-poetry','','[]','梅公小齋內，度越幽人占。',96,'全唐诗/poet.song.72000.json','["梅公小齋內，度越幽人占。", "何年孤山下，得此雙石劍。", "純鈎魚腸姿，拔地勢匪漸。", "柙藏不忍窺，往往發光燄。", "丈人夙好奇，領略無一欠。", "晚得此嶙峋，顧盼未云厭。", "此公活國胸，正直天所鑒。", "高堂掛斯圖，令人動深念。"]'),
('32dcf61a-025c-455a-ab83-1208233ea486','雪霽陪諸公登滕王閣分韵得閣字','洪朋','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u6ed5\u738b\u9601"]','醉乘筍輿歸，餘興陟層閣。',156,'全唐诗/poet.song.72000.json','["醉乘筍輿歸，餘興陟層閣。", "其前俯長江，其下壓城郭。", "入眼迭輝映，積雪未銷鑠。", "祲氛茲盪滌，山川一恢廓。", "瓊田認洲渚，璇樹花叢薄。", "明明飛丹霞，往往翔皓鶴。", "俯仰一神界，今我胡不樂。", "滕王已塵埃，大屋舊丹雘。", "人生何自苦，茲游行已昨。", "吾聞水西峰，中有洞宮脚。", "洪崖升天去，僊聖時間作。", "伊予千載裔，未鍊八瓊藥。", "孰能相與游，更議入廬霍。"]'),
('bc488988-a207-449c-9551-d0d8b533e2b5','游天宮寺上方瑜道人出漫題','洪朋','宋','宋诗','song-poetry','','[]','攝衣禪界中，高步上方外。',72,'全唐诗/poet.song.72000.json','["攝衣禪界中，高步上方外。", "乾坤更空闊，川嶽謝埃塊。", "行人杖屨底，地與烟霞會。", "道人遊四衢，行止各無礙。", "竹日弄清影，松風聽寒籟。", "心將萬化冥，始覺斯游最。"]'),
('98b5d781-9fca-45d8-81f4-45242d9cb204','天宮寺','洪朋','宋','宋诗','song-poetry','','[]','昨日頭岑卧，何曾越門限。',120,'全唐诗/poet.song.72000.json','["昨日頭岑卧，何曾越門限。", "徐侯遣行李，邀我伊蒲饌。", "天宮布金地，長者何代建。", "柴門實咫尺，佛事亦儼煥。", "道人呈家風，秋蔬更香飯。", "玉麈對胡床，凉飆颯河漢。", "晚來上方上，千里人縱觀。", "平生蓬蒿底，所適魚鳥願。", "佳人贈我詩，爛若錦繡段。", "聖哲期暮年，撫事一長嘆。"]'),
('e940e374-efe0-45a7-82a1-43ab59bd8702','晚同師川駒父玉父游大梵院小軒','洪朋','宋','宋诗','song-poetry','','[]','山氣夕巃嵷，川光暮澄凝。',96,'全唐诗/poet.song.72000.json','["山氣夕巃嵷，川光暮澄凝。", "櫺軒俯川嶽，拄杖相與登。", "脫屨就閒曠，秉羽居高明。", "盤礴飛鳶上，揮斥蜿虹橫。", "令弟各英妙，舌本淮湖傾。", "朋也老無能，前身雲水僧。", "蕭蕭緣坡竹，凉飆爲我興。", "執熱快一濯，何必踏層冰。"]'),
('3bdec514-7912-4ade-9d96-9918dd70bfb0','陪師川納凉大寧寺得綠字','洪朋','宋','宋诗','song-poetry','','[]','六月維長夏，炎熱不可觸。',120,'全唐诗/poet.song.72000.json','["六月維長夏，炎熱不可觸。", "車馬斷經過，卧痾適所欲。", "欻作城北遊，佛界映空谷。", "方塘荷氣清，層軒竹陰綠。", "徐侯辨食事，意豁忘羈束。", "鳴蜩韵高寒，凉颸盪煩促。", "坐隠者誰子，飛雹下棋局。", "勝負吾不知，靜嘯蔭喬木。", "徙倚失日車，旋歸想雨足。", "可令夜氣清，更使年穀熟。"]'),
('91948f2d-5d39-41e5-9d05-c05aca47ce92','城上','洪朋','宋','宋诗','song-poetry','','[]','杖策城上頭，初日破冥晦。',72,'全唐诗/poet.song.72000.json','["杖策城上頭，初日破冥晦。", "頗知春意還，早覺寒事退。", "風前識西岑，烟處認東匯。", "人如旋磨蟻，舟似覆杯芥。", "鸛鶴掠水涯，簫鼓雜天籟。", "便當杭清淺，底事返闤闠。"]'),
('d562cbfb-8b18-480c-bc65-cf95d495d658','陪諸公步城北分韵得亦字','洪朋','宋','宋诗','song-poetry','','[]','去月霜雪交，咫尺澀如棘。',120,'全唐诗/poet.song.72000.json','["去月霜雪交，咫尺澀如棘。", "今朝雲霧散，春氣恍如昔。", "九衢慰眼新，百草隨意出。", "俯仰亮有觀，茲辰底空擲。", "陶謝何許遨，發興在郭北。", "浄界集兩楹，層閣倚百尺。", "風日已可人，江山亦德色。", "四睇感終古，五字辦即席。", "想見盤礴地，鮮飆生兩亦。", "良游不相待，發函三歎息。"]'),
('bd828dab-2549-47a4-8894-5f06b1ae3094','寄題蔡州魯公祠堂','洪朋','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','魯公巖壑姿，勁氣不可及。',120,'全唐诗/poet.song.72000.json','["魯公巖壑姿，勁氣不可及。", "歲寒萬物盡，松柏當霜立。", "由來邪正間，厥勢不相入。", "公當肅代後，竄斥復相襲。", "嗚呼蔡州殞，義激壯士泣。", "周曾計不淺，希烈竟見執。", "從古皆有歿，忠烈泰山岌。", "使君拊遺跡，丹青辨呼吸。", "壯公臨大節，生氣何當挹。", "高詠兩賢篇，臨風黯於邑。"]'),
('8d478ace-bcee-4bd9-a09b-1eda39093aff','寄題陽居士高節軒','洪朋','宋','宋诗','song-poetry','','[]','中條陽亢宗，高義照千古。',96,'全唐诗/poet.song.72000.json','["中條陽亢宗，高義照千古。", "嬋嫣不無人，聞風吾已許。", "平生知味處，瀟灑送寒暑。", "敏樹印此心，柯葉傲風雨。", "岑夜入天籟，韵作太上語。", "一切得入律，真成衆香樹。", "賢者早求仁，行李徧八宇。", "歸來林丘下，歲寒色如故。"]'),
('ee6215fa-a59c-4364-9966-9b4c2e5658a6','寄題劉山人戰勝軒','洪朋','宋','宋诗','song-poetry','','[]','桃源一臞儒，意氣鬰何壯。',96,'全唐诗/poet.song.72000.json','["桃源一臞儒，意氣鬰何壯。", "削跡紅塵中，築亭白雲上。", "溪聲聽逸響，山色閱殊狀。", "諒是永幽棲，豈伊暫清曠。", "若人有靈氣，戰勝神更王。", "乃知先聖裔，風流標素尚。", "嗟予晚聞道，茲事夙所向。", "得興雪月交，理棹會一訪。"]'),
('00c7711c-4d99-44e1-8b6a-109fb9cacb1d','和元樂教授南軒','洪朋','宋','宋诗','song-poetry','','[]','南紀瘴癘劇，風土異中州。',120,'全唐诗/poet.song.72000.json','["南紀瘴癘劇，風土異中州。", "炎凉倏忽變，仲夏颯如秋。", "丈人東海來，稅駕此遲留。", "氣候感若此，何用寫我憂。", "泮水多時暇，南軒景物幽。", "方塘綠萍亂，佳樹蟬聲稠。", "曲肱梧陰美，玩此日月流。", "觴至聊共傾，此外亦焉求。", "丈夫功名志，天機不我謀。", "願言快心意，身世真悠悠。"]'),
('a66a85cd-9ba4-41b2-8ea3-8cc5930a9f3e','寄題攬結亭','洪朋','宋','宋诗','song-poetry','','[]','杜子數相見，求我攬結詩。',120,'全唐诗/poet.song.72000.json','["杜子數相見，求我攬結詩。", "攬結在何處，云在彭蠡湄。", "彭蠡夙所廬，今猶夢見之。", "一星水中央，衆流浩渺瀰。", "雨瀑下日夜，五老上雲霓。", "佛事儼相望，往往幽人期。", "君今構其下，敞亭覽翠微。", "水聲枕簟俱，山容杖屨隨。", "勝事君所獨，世人那得知。", "爲我謝五老，客子行亦歸。"]'),
('07cd4856-7083-408b-9639-c2b1611bd5f3','邃清閣分韵得洪字','洪朋','宋','宋诗','song-poetry','','[]','曜靈速天機，四序如轉蓬。',156,'全唐诗/poet.song.72000.json','["曜靈速天機，四序如轉蓬。", "行行早求道，咄咄就禿公。", "南紀卧徐穉，丹沙媿葛洪。", "婆娑一宇宙，萬物閱雌雄。", "得興頗賦詩，詩成亦何工。", "跫然張公子，玉山映寒葱。", "軟語啟皓齒，擲麈生清風。", "謫仙爲酒事，瓠壺清若空。", "相視一笑粲，聖處此樂同。", "敞榭細履愜，別墅幽逕通。", "微漪媚清池，輕颸泛寒叢。", "悠然物外賞，未覺人間窮。", "何有於我哉，請館季孟中。"]'),
('242a3392-38fd-49ee-b61c-bd91e206ccab','玉父賦倦殻軒韵得殻字','洪朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','今弟巖壑姿，問道困南朔。',84,'全唐诗/poet.song.72000.json','["今弟巖壑姿，問道困南朔。", "歸來敞蝸牛，真成倦龜殻。", "曲肱梧桐影，日夜洞庭樂。", "誰何藝根本，歲久棲鸑鷟。", "靜言人間世，變化如風雹。", "笑語尊俎同，茲理要商榷。", "時不與人游，安燕正當學。"]'),
('62ecdcd5-a022-4d37-be76-8e51145b01e9','過師川偶行','洪朋','宋','宋诗','song-poetry','','[]','伊昔袁陟居，只今徐郎宅。',96,'全唐诗/poet.song.72000.json','["伊昔袁陟居，只今徐郎宅。", "少作與渠雙，老氣想君隻。", "茲理亦何有，訂之在今昔。", "吾廬城北頭，捷徑實咫尺。", "欻思論五字，聊復訪三益。", "高尋風雅源，洞入屈宋域。", "波瀾到蘇李，光焰及元白。", "自來磊落人，聞見資博極。"]'),
('d4ce1b86-3ff0-4721-85d7-8d16702f86b9','題水陸院矮棕櫚','洪朋','宋','宋诗','song-poetry','','[]','短短一棕櫚，葱蒨聊可悅。',48,'全唐诗/poet.song.72000.json','["短短一棕櫚，葱蒨聊可悅。", "如何後歲寒，生氣未衰歇。", "脫身斤斧中，甘心形影拙。", "况歎風雨姿，拄策日已昳。"]'),
('6085f26c-ff29-4102-bcf5-86578f4ba552','堂下芍藥花盛開而蕪穢不治太夫人課奴芟夷草莽飾以丹檻煥然一新感而成詠','洪朋','宋','宋诗','song-poetry','','[]','江風飄已盡，庭樹但蒼翠。',108,'全唐诗/poet.song.72000.json','["江風飄已盡，庭樹但蒼翠。", "如何欻到眼，餘容殿春事。", "恭惟太夫人，指揮掃蕪穢。", "咄嗟丹檻開，芳蕤生意氣。", "矧乃疊石根，端有塵外致。", "何必風人萱，願言樹之背。", "疇昔雜荆杞，只今照階戺。", "吾人剪拂功，是事亦不細。", "物理庶可推，倚杖一歔欷。"]'),
('0d96d77c-2071-46f7-a738-87bbec8aa44e','師川賦梅花','洪朋','宋','宋诗','song-poetry','','[]','梅花端月繁，梅蘂終冬破。',48,'全唐诗/poet.song.72000.json','["梅花端月繁，梅蘂終冬破。", "正色儼當窗，低枝斜應座。", "分將霜雪侵，不受脂粉涴。", "莫遣朔風吹，飄零成玉唾。"]'),
('b0fa1353-f4c6-4494-8ac2-e010a9e17857','春風','洪朋','宋','宋诗','song-poetry','','[]','春風吹桃李，欻然滿中園。',72,'全唐诗/poet.song.72000.json','["春風吹桃李，欻然滿中園。", "羣動不遑息，蝴蝶紛飛翻。", "我亦感茲時，步屧遶林間。", "容華豈不好，持久良獨難。", "置酒休其下，聊復罄餘歡。", "君看桃與李，成蹊亦無言。"]'),
('71985e51-2dbe-4d1c-a7d0-858fef2f6f98','春颸','洪朋','宋','宋诗','song-poetry','','[]','春颸天上來，吹我中庭樹。',96,'全唐诗/poet.song.72000.json','["春颸天上來，吹我中庭樹。", "爭先兩株桃，照日結紅霧。", "枝枝迭映蔚，葉葉相誇詡。", "光彩奪目精，香氣襲行路。", "風雨不我謀，零落縱橫去。", "西家婉娩姿，見之切情慮。", "蹇修安所營，年芳空擲度。", "意內人莫知，淚下成紅雨。"]'),
('17395adc-62ca-47e8-9e66-7300a02e0f1d','立秋日諸公過敝廬賦詩','洪朋','宋','宋诗','song-poetry','','[]','埃鬰一炎方，何處不庳濕。',120,'全唐诗/poet.song.72000.json','["埃鬰一炎方，何處不庳濕。", "北窗但掃地，所向若維縶。", "及茲澍雨過，信是高秋立。", "便有好事侶，俱來負郭集。", "中庭樹陰滿，燀氣清且急。", "胡床各蕭散，頗覺凉氣入。", "道喪千載餘，世路日險澀。", "朋知得若人，風流有所及。", "西山一牛鳴，時哉先聖集。", "興來浩蕩遊，胡爲若羈馽。"]'),
('366d0ec1-dae7-4d7d-821e-ef571a9c1a83','歲暮','洪朋','宋','宋诗','song-poetry','','[]','黔雷運天機，四氣莽回互。',60,'全唐诗/poet.song.72000.json','["黔雷運天機，四氣莽回互。", "始玩春載陽，欻見歲云暮。", "孰知老境侵，轉覺夙尚誤。", "吾聞崑崙墟，上有不死樹。", "安得攀其條，奇齡儻能度。"]'),
('cbc7a3c1-8f6a-438f-b86f-7f4bb28bfa44','清夜','洪朋','宋','宋诗','song-poetry','','[]','萬籟還無聲，燈光耿清夜。',72,'全唐诗/poet.song.72000.json','["萬籟還無聲，燈光耿清夜。", "跏趺據繩床，夢回蝴蝶化。", "緣氣亦何有，本心浄無塵。", "蚤夜去求道，八荒因問津。", "歸來謝行李，衆妙不遠身。", "誰與商略此，玉麈炷爐芬。"]'),
('77d9eb4f-781b-4dca-9f72-43ab4c076808','夢中所作','洪朋','宋','宋诗','song-poetry','','[]','秋風插羽翰，樓觀天上行。',72,'全唐诗/poet.song.72000.json','["秋風插羽翰，樓觀天上行。", "朝霞带空洞，海日注疏櫺。", "一一琪樹遶，粲粲芝草榮。", "中有一道士，靜嘯無俗情。", "顧我有靈氣，授我以長生。", "咄嗟一世間，擾擾何所營。"]'),
('8bf96636-1532-46f6-a262-d68a5e77bdeb','紹聖二年秋七月乙未夜夢遊一勝處非平生所經行見一道士延余坐飲以醇酒酒酣道舊故恍然不知所以因而賦詩既覺漫不復記憶戲作五言以補之','洪朋','宋','宋诗','song-poetry','','[]','雞鳴深林裏，犬吠幽徑中。',108,'全唐诗/poet.song.72000.json','["雞鳴深林裏，犬吠幽徑中。", "不知誰子宅，乃是僊人宮。", "竹柏蔭清淺，樓觀上虛空。", "芝草隠翳鬰，璇樹翠青葱。", "升堂見僊伯，歡然燕笑同。", "侍立十餘輩，玉女桃李容。", "告我存三一，使我壽無窮。", "吁嗟人間世，局促何所通。", "願言歸白水，更議登閬風。"]'),
('fd096c78-914d-4412-8486-b6ec48a7826d','答友','洪朋','宋','宋诗','song-poetry','','[]','一昨城北遨，得興起我病。',72,'全唐诗/poet.song.72000.json','["一昨城北遨，得興起我病。", "梅嶺識霜林，楓江認烟艇。", "深行憶疇昔，冥搜吝俄頃。", "西矚列仙家，東睇老禪徑。", "不聞遷鶑聲，但見行雁影。", "再讀貽我篇，思與雲路永。"]'),
('27069065-0fc1-4e71-a95d-95a93b9a1d71','述古  其一','洪朋','宋','宋诗','song-poetry','','[]','蠹蝝仆柱梁，蟁蝱走牛羊。',60,'全唐诗/poet.song.72000.json','["蠹蝝仆柱梁，蟁蝱走牛羊。", "風過河水損，鳥噪木葉傷。", "禍福有眹兆，物理乃其常。", "聖人睹未然，休氣未渠央。", "後代監不遠，其在漢與唐。"]'),
('e1eeea0c-a204-44a0-a1e8-a89710d4e20a','述古  其二','洪朋','宋','宋诗','song-poetry','','[]','六龍安可頓，四節一何速。',60,'全唐诗/poet.song.72000.json','["六龍安可頓，四節一何速。", "秋氣下霜露，春事著草木。", "天道有迭代，世故足翻覆。", "塞翁喪良馬，宋氓得白犢。", "由來非今朝，未必不爲福。"]'),
('409ad3cc-7293-4875-abdd-a3c5da39220b','述古  其三','洪朋','宋','宋诗','song-poetry','','[]','木秀風必摧，岸堆流必湍。',60,'全唐诗/poet.song.72000.json','["木秀風必摧，岸堆流必湍。", "人生裨海內，出處甚獨難。", "尼父稱大聖，車轍不得安。", "落落抱正直，鼎鼎見疑患。", "顔前苟無靦，身後亦不刊。"]'),
('aaaeb720-b7cf-4eb6-8f67-51d37494e0f5','送潘端州出殯以風甚渡江中流而不濟有作','洪朋','宋','宋诗','song-poetry','','[]','戒徒事晨征，肅舲逗江滸。',96,'全唐诗/poet.song.72000.json','["戒徒事晨征，肅舲逗江滸。", "屯雲蔽寒岑，衝飆卷秋浦。", "波驚飛櫓妨，景短執引阻。", "垂堂戒曩哲，矧乃將恐懼。", "長年告我還，風力方軒舉。", "恍疑柳車張，猶認鷺縗聚。", "蹙浪鬰飛翻，涌烟迷處所。", "江水日夜流，何由賞心晤。"]'),
('4359453b-ed28-4bdb-840d-f45fffeddba1','寒泉','洪朋','宋','宋诗','song-poetry','','[]','山下出寒泉，千載神所祕。',96,'全唐诗/poet.song.72000.json','["山下出寒泉，千載神所祕。", "故老空傳名，四面但蕪穢。", "觀音欻見夢，咄嗟辨亭砌。", "道人頃杖錫，示現祖師意。", "汲引貫四時，香美可一切。", "遂令雲水僧，悉飲解脫味。", "病夫方中來，酌彼盪塵滓。", "屬詩長松根，北風助奇思。"]'),
('0a63d452-7804-4de0-8d73-c07cd7c27ada','和答陳明信兼簡王立之','洪朋','宋','宋诗','song-poetry','','[]','我如東南雲，風吹西北度。',180,'全唐诗/poet.song.72000.json','["我如東南雲，風吹西北度。", "時不與人謀，飄轉無定處。", "如何紅塵中，欻此君子遇。", "高標鳶戾天，能事豹隠霧。", "暴謔中酒前，了不與物迕。", "吾嘗期若人，胸次貯風露。", "向來賞我詩，但坐日云暮。", "識君已恨晚，見君又不屢。", "今晨眼忽開，貽我河梁句。", "正聲久不嗣，斯文諧韶濩。", "吹噓君過矣，豈不愛我故。", "城南逸少孫，軟語可與晤。", "閉門謝俗子，著書無窘步。", "小園花氣深，客醉不得去。", "尋盟出無輿，風沙莽回互。"]'),
('4e0bc51a-f322-4e15-957d-63f3ba1096c8','題章江院','洪朋','宋','宋诗','song-poetry','','[]','扶藜下城頭，步屧踏禪窟。',48,'全唐诗/poet.song.72000.json','["扶藜下城頭，步屧踏禪窟。", "微徑鬰葱菁，寶殿高突兀。", "層暉注中塘，凝塵滿丈室。", "惜哉古道場，回首思蕭瑟。"]'),
('cc77dc7b-d532-44de-b10d-ab2f896e870d','即事','洪朋','宋','宋诗','song-poetry','','[]','今日慘不樂，念此歲云徂。',60,'全唐诗/poet.song.72000.json','["今日慘不樂，念此歲云徂。", "側聆絲竹音，令我憂思舒。", "壺觴幸未空，斟酌相與娛。", "始玩百草花，今復萬木枯。", "且爲一笑地，千古共丘墟。"]'),
('4e351adb-c52a-4256-9e98-8e96edab6f37','登瀛閣','洪朋','宋','宋诗','song-poetry','','[]','楚東之國饒爲大，程氏之子吾所愛。',194,'全唐诗/poet.song.72000.json','["楚東之國饒爲大，程氏之子吾所愛。", "讀書尚友有能事，夙昔一見即傾蓋。", "平生誅茅崒蕭爽，十頃青銅就空曠。", "朱甍碧瓦俯清流，菱葉荷花映蕩漾。", "春風一吹百花妍，載酒處處開繡筵。", "千株竹柏上參天，白日蕭梢朱夏寒。", "客來枕簟曲肱眠，丈人頗有前賢風。", "藏書萬卷插架同，芝蘭玉樹階庭內。", "道山延閣顧盼中，薄寒中人木葉下。", "久客將歸秣高馬，送君南浦淚盈把。", "臨岐執手求我歌，老矣奈此登瀛何。", "嗚呼何時履聲上君閣，尚能爲公賦濠樂。"]'),
('844d5626-f173-474d-b926-04e358115aaf','北寺小閣戲作呈廣心諸公','洪朋','宋','宋诗','song-poetry','','[]','帝青一色女牆頭，况復龍山影裏游。',64,'全唐诗/poet.song.72000.json','["帝青一色女牆頭，况復龍山影裏游。", "草閣柴扉依佛界，白沙翠竹使人愁。", "可惜可憐空擲度，羅襪凌波渺何處。", "會須桃葉倚春風，判却扁舟入烟霧。"]'),
('825e4688-b7d3-4d69-95d6-7a56a9d70c93','七峰閣作呈廣心從老','洪朋','宋','宋诗','song-poetry','','[]','七峰層疊割人境，寶閣排空春晝靜。',64,'全唐诗/poet.song.72000.json','["七峰層疊割人境，寶閣排空春晝靜。", "朱甍碧瓦勢欲飛，瓊樹瑶林爛相映。", "謫僊對此佳興發，人物山川兩清絕。", "維摩方丈夜闃寥，老人宴坐無言說。"]'),
('f49dc37f-5b08-49d0-a12a-d2d52bf54bea','又示海會老子','洪朋','宋','宋诗','song-poetry','','[]','七峰玉立相排蕩，寶閣翬飛雲雨上。',64,'全唐诗/poet.song.72000.json','["七峰玉立相排蕩，寶閣翬飛雲雨上。", "雪餘璀璨映寒空，雨霽參差入晴望。", "閣中禪老更壁立，下視羣山丈人行。", "蛟龍頭角碧潭寒，江南赤地空惆悵。"]'),
('b6205dbf-8899-43fb-a1df-f6704d781e4a','同鴻父遊南寺','洪朋','宋','宋诗','song-poetry','','[]','薄寒中人暉景晚，江頭蘭若同游衍。',64,'全唐诗/poet.song.72000.json','["薄寒中人暉景晚，江頭蘭若同游衍。", "蛛絲垂戶像設深，蜃氣成樓鐘韵遠。", "機發於踵寶藏俱，神物護持勝事殊。", "更向僧房捉麈尾，令人欻憶聘君湖。"]'),
('4ec358ee-5ebc-4c0b-818a-4b7cc69f57fa','同諸人西寺避暑','洪朋','宋','宋诗','song-poetry','','[]','連廊四注塔中起，五月殿陰作商氣。',64,'全唐诗/poet.song.72000.json','["連廊四注塔中起，五月殿陰作商氣。", "竹床午枕耐睡魔，寶鐸天風吹佛事。", "小冠捧腹遶檀欒，坐隠應迷日下山。", "騎馬歸來還執熱，蚊雷虺虺滿人間。"]'),
('aa7ea133-4790-465e-8a99-7b5ff77252e3','同徐師川登秋屏閣觀雪','洪朋','宋','宋诗','song-poetry','','[]','積雪未虧日還沒，雲氣黯慘愁不釋。',144,'全唐诗/poet.song.72000.json','["積雪未虧日還沒，雲氣黯慘愁不釋。", "徐郎揖我上櫺軒，眼界物物有正色。", "萬株瓊樹爲誰妍，千畝瑶草底空擲。", "可憐雨打或飄零，不分風吹玉攢積。", "向來已撥宜城醅，末至何妨杜陵客。", "鄙夫中聖殊未醒，向人江山恍如昔。", "臺邊好在龍沙黄，臺前俄失鸞岡碧。", "只今雪思未渠央，準擬作花大如席。", "大江之南喜氣多，舊瘴懸知掃無迹。"]'),
('5005142d-b950-4757-8876-04f69db7a82e','奉陪李安上主簿游秋屏閣','洪朋','宋','宋诗','song-poetry','','[]','春風忽然滿天地，籃輿便作城北行。',128,'全唐诗/poet.song.72000.json','["春風忽然滿天地，籃輿便作城北行。", "招提古臺極灑落，况迺萬物皆欣榮。", "梅花萬點真可惜，柳條弄色如含情。", "初筵便飽李侯德，揮犀河漢倒空碧。", "連山向晚更嫵媚，落日澄江青黛色。", "嫦娥冰鏡挂天闕，共照清罇情屢極。", "諸公推轂鍾王間，醉墨淋漓滿僧壁。", "歸與不知所如往，但覺清風生兩腋。"]'),
('ec75ef45-e524-410c-89f3-c36bb8dc5069','南渡鄒大舟中作','洪朋','宋','宋诗','song-poetry','','[]','谷鹿洲前秋風起，淥波亭下小舟裏。',64,'全唐诗/poet.song.72000.json','["谷鹿洲前秋風起，淥波亭下小舟裏。", "鄒子揖我獅子尾，談天舌本傾我耳。", "散髮船篷玩秋水，茗碗盪胸無泥滓。", "牛羊下山催客子，挂席明朝即千里。"]'),
('29809ad3-3b6f-4e46-91e3-d4267c9e52c9','幽尋','洪朋','宋','宋诗','song-poetry','','[]','華鯨喚起曲肱夢，竹蹊幽尋小雨乾。',64,'全唐诗/poet.song.72000.json','["華鯨喚起曲肱夢，竹蹊幽尋小雨乾。", "風吹龍沙江流斷，日下烏塔松陰寒。", "冰雪照人徐孺子，手捉玉麈對西山。", "安得洪崖八瓊藥，令我飛出六合間。"]'),
('6a6f50bc-5fbc-4cdc-97ba-23be9b3f6b91','寄題胡公祠堂','洪朋','宋','宋诗','song-poetry','','[]','胡公祠堂舊聞處，魯公嶺下草樹深。',64,'全唐诗/poet.song.72000.json','["胡公祠堂舊聞處，魯公嶺下草樹深。", "堂後壽宮閟日月，堂前荒草橫古今。", "收拾胸中書萬卷，邂逅眼底梧十尋。", "我思古人不可見，于公可見古人心。"]'),
('a46beb47-2e9e-4d4b-97f6-1403529f8272','樊上丈人歌','洪朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廣文諸生如亂麻，十有八九或起家。',261,'全唐诗/poet.song.72000.json','["廣文諸生如亂麻，十有八九或起家。", "幅巾藜杖最困者，樊上丈人鬚鬢華。", "丈人聞道羲皇上，屈原莊周丈人行。", "聲名籍甚徒爲耳，四海八荒莽跌宕。", "扁舟布帆下赤壁，揚瀾左蠡隨所歷。", "顛風狂雨向昏黑，怒濤掀天奇兀硉，饞蛟駮獸紛騰突。", "一葦無處所，數口僅生活。", "行路難如此，一一爲我說。", "匡山野老坎壈人，讀書空山三十春。", "下澤款段何逡巡，丈夫窮達付造物，委瑣齷齪不足論。", "臭味略相似，邂逅即情親。", "江頭一樽前，執手鼻酸辛。", "秋風吹君唾珠玉，發函伸紙三過讀，惜哉意氣何刺促。", "丈人行李何當來，得意江山醉金罍，富貴崢嶸亦悠哉。", "君不見博陵馬周新豐客，時無貞觀老死無人識。"]'),
('7d68641c-8521-46dc-920c-a5de03b7e05e','讀吳天章詩集歌','洪朋','宋','宋诗','song-poetry','','[]','豫章丈人天章公，夙昔待詔蘂珠宮。',96,'全唐诗/poet.song.72000.json','["豫章丈人天章公，夙昔待詔蘂珠宮。", "謫來黄陂對秋水，歸來白社今春風。", "晚窗許我數相見，高文似我開生面。", "故知沈謝少未工，不覺曹劉名獨擅。", "丈人意氣薄雲霓，細故蒂芥不足疑。", "只今陛下調玉燭，異時事業他人稀。"]'),
('925961cf-39ae-46f6-bada-697896c9c59b','蓬萊仙人歌','洪朋','宋','宋诗','song-poetry','','[]','吾聞三山在海底，貝闕珠宮照天地。',96,'全唐诗/poet.song.72000.json','["吾聞三山在海底，貝闕珠宮照天地。", "誰其尸之玉鍊顔，耕耘五德長不死。", "我欲遐登不憚遥，隔以弱水三萬里。", "向來名字落人間，傳道蓬萊第一仙。", "吐鳳雕龍乃餘事，驚蛇走兔不作難。", "浪憑徐福通消息，寶唾儻與春風還。"]'),
('073f95be-82f1-4a4c-b87c-efa074ab11dc','相從歌呈次元子真師川','洪朋','宋','宋诗','song-poetry','','[]','鬰鬰窈窈城北方，祇園神界遥相望。',128,'全唐诗/poet.song.72000.json','["鬰鬰窈窈城北方，祇園神界遥相望。", "春暉澹蕩詩思長，愁絲挽春百尺强。", "薰人著處風花香，亦有相從天上郎。", "森然玉樹臨青陽，蒹葭無乃倚蒼蒼。", "且置是事敷僧床，劇談一坐故難忘。", "却來倚杖北天王，壁間詩翁五字章。", "句法端在人則亡，人生遇值不合常。", "反路日入下牛羊，願君連騎未渠央。"]'),
('6953639c-b841-467f-a80d-df9edbec718e','戲作公子歌送宣明府','洪朋','宋','宋诗','song-poetry','','[]','人間天上張公子，宰邑彈琴藝桃李。',96,'全唐诗/poet.song.72000.json','["人間天上張公子，宰邑彈琴藝桃李。", "門前五柳卧桁楊，刃無全牛有如此。", "三年墨綬何必遲，萬里青雲從此始。", "壁陰多暇清晝同，生塵羅襪醉春風。", "東飛伯勞西飛燕，南飛烏鵲北飛鴻。", "紅粧倚檝君青驄，但願主人黑頭公。"]'),
('de52d33c-9166-4d72-a3f5-45fb44b27f78','醉中作桐鄉歌別王明府','洪朋','宋','宋诗','song-poetry','','[]','故城疊巘臨高臺，古木到天猿鳥哀。',96,'全唐诗/poet.song.72000.json','["故城疊巘臨高臺，古木到天猿鳥哀。", "桐鄉官寺山水裏，泉聲常疑驟雨來。", "吾祖政成朱邑後，文采風流今未朽。", "王郎游刃無全牛，籍甚能名傳衆口。", "弦歌之聲得故人，車殆馬煩開芳罇。", "明朝更指南斗去，相思目斷江湖春。"]'),
('9fba8f9c-7125-4203-b8bb-9306b0210bcc','小麥青青歌','洪朋','宋','宋诗','song-poetry','','[]','小麥青青大麥枯，新婦城邊守茅蒲。',64,'全唐诗/poet.song.72000.json','["小麥青青大麥枯，新婦城邊守茅蒲。", "不妨執熱餉婦姑，奄觀銍艾相喧呼。", "黄雲好在玄雲起，雨如車輪未渠已。", "繡衣使者問麥秋，今年麥秋又如此。"]'),
('8ebb58fa-b9a5-4545-b2e0-72815b61d558','潘氏園引','洪朋','宋','宋诗','song-poetry','','[]','君不見豫章城南門，中有潘氏之名園。',193,'全唐诗/poet.song.72000.json','["君不見豫章城南門，中有潘氏之名園。", "臺基迺是孺子舊，地勢直與東湖連。", "百常之觀上造天，曲瓊四面珠箔懸。", "春拍綠波南浦外，朝隮爽氣西山巔。", "方塘曲徑洞天遠，萬草千花未曾見。", "春風向暖一披拂，薄人花氣江城徧。", "潘郎吟詩春風裏，拄杖穿花還復倚。", "大名今代龐德公，采藥鹿門終不起。", "潘郎事親愛客同，平生百味罇不空。", "我來休駕嘯竹風，主人閉門語雍容。", "掉頭長歌子潘子，願言三徑相終始。", "或云丈夫不如此，但恐亦復不免耳。"]'),
('c37bf63d-5a5e-40bc-870b-c9bf1913d423','答李廣心見贈','洪朋','宋','宋诗','song-poetry','','[]','龍山四面何蜿蜒，下有黄雲二頃田。',128,'全唐诗/poet.song.72000.json','["龍山四面何蜿蜒，下有黄雲二頃田。", "朝來爽氣入吟思，外家吾叔真才賢。", "十年不見令人瘦，一日相逢開口笑。", "已呼小吏辦酒樽，更遣官奴歌水調。", "燒鐙軟語爲情親，竹葉榴花俱可人。", "客無庸歸此道意，一曲驪駒何足云。", "銀鈎玉唾粲側理，筆端逍遥有能事。", "鼎來富貴更妙年，枳棘栖鸞聊復爾。"]'),
('9a593081-63a9-4540-b517-fe405de7c0ad','和答師川','洪朋','宋','宋诗','song-poetry','','[]','假道羣舒渡江水，解衣盤礴聊復爾。',64,'全唐诗/poet.song.72000.json','["假道羣舒渡江水，解衣盤礴聊復爾。", "三月已破未云邁，政爲故人今在此。", "故人佳句數能來，招我清罇想未開。", "病夫潦倒非多才，如澠之酒胡爲哉。"]'),
('5675d20e-650b-419c-9705-9d4b2bcecd40','和郭子駿見寄','洪朋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','西山南浦鬰相望，中有萬里之長江。',128,'全唐诗/poet.song.72000.json','["西山南浦鬰相望，中有萬里之長江。", "籃輿何許訪有道，江亭垂柳復垂楊。", "道家諸天屹高閣，井冽寒泉亦不惡。", "胡携蒼璧澡雪我，爲我託乘上寥廓。", "晚吟蕭寺攬層軒，龍蛇參天清晝寒。", "炎官火傘吁可畏，清風枕簟不知還。", "歸來惠我唾珠玉，明窗棐几頗三復。", "小人塵埃故無奇，拜命一辱聊報之。"]'),
('2cf3b3dd-0db8-40b2-815d-a3954005349c','和駒父大雨雹','洪朋','宋','宋诗','song-poetry','','[]','紹聖二年端月尾，南州雨雹如雁子。',112,'全唐诗/poet.song.72000.json','["紹聖二年端月尾，南州雨雹如雁子。", "今朝霹靂清泠裏，雜然而下勢未已。", "狡獪變化何壯哉，欬唾珠玉天際來。", "銷毀金石不足道，梢殺林莽今可哀。", "聖人在上調玉燭，縱有此物寧爲災。", "邂逅豐年亦如此，長老相傳又堪記。", "吾今一飽良不易，摩挲枵腹聊自慰。"]'),
('dd420297-9c5e-4b3b-a931-91cc5905f341','春雨戲趙立之','洪朋','宋','宋诗','song-poetry','','[]','花枝欲動濡須塢，無頼春風吹小雨。',64,'全唐诗/poet.song.72000.json','["花枝欲動濡須塢，無頼春風吹小雨。", "如隨蝴蝶夢中翻，愁向垂楊堤上度。", "聞道君家種逸香，婆娑紫艷占年芳。", "何當麗日濃花氣，亂插佳人翡翠梁。"]'),
('4cb94183-dadb-46ab-9be3-23011c0a4bec','戲汪汲','洪朋','宋','宋诗','song-poetry','','[]','汪童軀小膽良大，讀書氣欲吞渤澥。',96,'全唐诗/poet.song.72000.json','["汪童軀小膽良大，讀書氣欲吞渤澥。", "銀鈎玉唾不作難，已向筆端風雨快。", "昔過重湖喙欲鳴，還來南浦羽猶鎩。", "坐窗軟語戒寒秋，陰壑收聲虛萬籟。", "可憐脫身瘧癘餘，槁項黄馘一何憊。", "石脆山中足條草，誰能折來已君疥。"]'),
('fb392130-f82a-4bf2-b1d3-e4a216116b59','燕子虛贈李清墨乞予詩試墨作七言謝之','洪朋','宋','宋诗','song-poetry','','[]','黟川諸李今寂寞，潞州殘圭大不惡。',64,'全唐诗/poet.song.72000.json','["黟川諸李今寂寞，潞州殘圭大不惡。", "燕侯固窮亦好事，探囊持贈意不薄。", "眼明見此陳家玄，徑呼毛穎作七言。", "故知身外俱長物，子墨客卿聊忘年。"]'),
('4628b07a-24a8-488d-8e74-142c09eaa4d2','歲莫','洪朋','宋','宋诗','song-poetry','','[]','歲云莫矣百草枯，楚天欲雪雲模糊。',64,'全唐诗/poet.song.72000.json','["歲云莫矣百草枯，楚天欲雪雲模糊。", "後山入夜風轉急，薄寒中人燈更孤。", "寂寞三更勘文字，銷沈萬籟一跏趺。", "白髮潜生忽不覺，自笑愚夫如許愚。"]'),
('4c4a2758-6d3b-45bc-8381-9303e348f346','記夢','洪朋','宋','宋诗','song-poetry','','[]','疇昔之夢非想因，倏欻遊遨出無垠。',112,'全唐诗/poet.song.72000.json','["疇昔之夢非想因，倏欻遊遨出無垠。", "旁日挾月超崑崙，虛無上下列宿分。", "絳氣鬰靄玄都門，萬靈呵護靜不喧。", "中有蘂珠玉宸君，再拜問道受七言。", "故知要妙可不煩，離宮閣道多往還。", "衆真差池玉鍊顔，雲衣霞裙絳纛幡。", "顧我如舊笑軒軒，問我不歸何由緣。"]'),
('5d65cb40-9973-42ad-88bc-109ec0dff106','得戎州書','洪朋','宋','宋诗','song-poetry','','[]','萬竅怒號天籟作，燈照無眠夜寂寞。',112,'全唐诗/poet.song.72000.json','["萬竅怒號天籟作，燈照無眠夜寂寞。", "發函伸紙數行空，永懷渭陽涕橫落。", "書奉萬里馬胡蠻，人在四禪怖魔閣。", "荔枝灘頭欄楯深，千峰劍攢上寥廓。", "松根更有道人俱，想見龐眉無住著。", "未應老懶廢書眠，許我新詩大不惡。", "何日金鷄放赦迴，拭淚論文恍如昨。"]'),
('54ea05bc-8e8a-4dba-997d-07da8809264e','感興','洪朋','宋','宋诗','song-poetry','','[]','十頃琉瓈下赤日，旦日飆臺排雲出。',64,'全唐诗/poet.song.72000.json','["十頃琉瓈下赤日，旦日飆臺排雲出。", "金宮銀闕遠杳冥，瓊樹瑶林近蒙密。", "右拍洪崖左浮丘，况復綺疏可淹留。", "未能作意駕僊驥，會須得興汎虛舟。"]'),
('c299faaa-e7e1-4f1b-a541-c64e9a4b86f1','杜十歸自海堧別業說夜行一段事令予與徐十長短調書之','洪朋','宋','宋诗','song-poetry','','[]','建寧禪界清如水，杜陵獨夜荒村繞。',114,'全唐诗/poet.song.72000.json','["建寧禪界清如水，杜陵獨夜荒村繞。", "剎幡寂寂走前溪，素沙白水相蕩照。", "只今欲渡叫漁舠，但聞春叢野狐嘷。", "野狐鳴呼不足道，行路難行豺虎驕。", "邂逅舟橫却無檝，向來藜杖撐白月。", "可羨淵魚兩兩游，隨意溪毛短短出。", "嗚呼此時勝事故不惡，杜陵歸來爲予說。"]'),
('5fe631ff-288b-4d86-af67-940566a543d1','寫韵亭','洪朋','宋','宋诗','song-poetry','','[]','紫極宮下春江橫，紫極宮中百尺亭。',64,'全唐诗/poet.song.72000.json','["紫極宮下春江橫，紫極宮中百尺亭。", "水入方洲界玉局，雲映連山羅翠屏。", "小楷四聲餘翰墨，主人一粒盡仙靈。", "文簫采鸞不復返，至今神界花冥冥。"]'),
('e52af512-787f-4e54-995f-9966b6f665a8','李夫人偃竹歌','洪朋','宋','宋诗','song-poetry','','[]','袖中欻忽生絲竹，眼底鮮飈起寒綠。',88,'全唐诗/poet.song.72000.json','["袖中欻忽生絲竹，眼底鮮飈起寒綠。", "把筆誰能寫此真，偃蹇一枝生氣足。", "夫人故有林下風，歲寒落落此君同。", "映窗得意偶揮灑，寫出篔簹谷裏千秋之卧龍。", "夜來風雨吹倒屋，但恐踴躍變化入水渺無蹤。"]'),
('b79b214f-d97a-40c6-bcfc-c0e22ec9aa84','大母生日','洪朋','宋','宋诗','song-poetry','','[]','九日明朝是，初筵此地張。',48,'全唐诗/poet.song.72000.json','["九日明朝是，初筵此地張。", "杯添竹葉酒，缾貯桂枝香。", "晚吹階除浄，高雲戶牖凉。", "綵衣稱壽處，歡樂未渠央。"]'),
('82d43240-1478-4769-83fd-3227f6d95507','示鴻父','洪朋','宋','宋诗','song-poetry','','[]','隠几歲遒盡，鉤簾夜未分。',48,'全唐诗/poet.song.72000.json','["隠几歲遒盡，鉤簾夜未分。", "北風虛地籟，南斗粲天文。", "愁破傾春釀，心清炷夕薰。", "更憐小陸在，無故莫離羣。"]'),
('0b95e6cc-384e-4b6b-a837-095a150ca458','和答駒父見寄二首  其一','洪朋','宋','宋诗','song-poetry','','[]','匡說詩今見，開函一解顔。',48,'全唐诗/poet.song.72000.json','["匡說詩今見，開函一解顔。", "平安問五柳，意氣到三山。", "種秫不妨醉，鳴琴定復閒。", "歲寒儻客授，早買釣舟還。"]'),
('d2fd4497-4c99-452c-9d08-6b978ec426b2','和答駒父見寄二首  其二','洪朋','宋','宋诗','song-poetry','','[]','校官豐暇豫，陋巷小經過。',48,'全唐诗/poet.song.72000.json','["校官豐暇豫，陋巷小經過。", "竹落護松菊，疏村上薜蘿。", "江山入眼界，日月自頭陀。", "忽憶陶彭澤，新詩不廢哦。"]'),
('29cfbcdc-7739-4187-8e06-98e96f64d8f2','代簡答師川','洪朋','宋','宋诗','song-poetry','','[]','不覺日還至，方驚歲已殘。',48,'全唐诗/poet.song.72000.json','["不覺日還至，方驚歲已殘。", "吾徒知寂寞，尺素問平安。", "顛眴復如此，詩成詎可觀。", "尋常邈胡越，祇覺怕風寒。"]'),
('72509ca1-c0aa-4e70-85bb-09eff6a7ce50','題大梵院小軒','洪朋','宋','宋诗','song-poetry','','[]','小軒含法界，萬物眼中齊。',48,'全唐诗/poet.song.72000.json','["小軒含法界，萬物眼中齊。", "江擁龍沙起，天籠鶴嶺低。", "地偏人益少，林迥鳥能啼。", "敗葉隨風盡，登臨思却迷。"]'),
('02efcddc-9dae-45db-9819-d42f9d12ab1c','次韵元樂登南樓','洪朋','宋','宋诗','song-poetry','','[]','詩翁騎馬去，城觀對清氛。',48,'全唐诗/poet.song.72000.json','["詩翁騎馬去，城觀對清氛。", "勝地依依在，真人往往聞。", "天高梅嶺見，水落蓼洲分。", "知有荷鉏者，只今麋鹿羣。"]'),
('e091aa54-1e61-4bfa-9923-0590fe699112','宿范氏水閣','洪朋','宋','宋诗','song-poetry','','[]','枕水鑿疏櫺，雲扉夜不扃。',48,'全唐诗/poet.song.72000.json','["枕水鑿疏櫺，雲扉夜不扃。", "灘聲連地籟，林影亂天星。", "人浄魚頻躍，秋高露欲零。", "何妨呼我友，乘月與揚舲。"]'),
('38965121-2683-4485-bb48-49132a6694e9','報國寺藏經院小閣同師川駒父作二首  其一','洪朋','宋','宋诗','song-poetry','','[]','吾廬通古寺，寶藏此禪房。',48,'全唐诗/poet.song.72000.json','["吾廬通古寺，寶藏此禪房。", "薜荔封寒井，檀欒度短牆。", "蟬聲秋寂寂，山氣夜蒼蒼。", "却怪沙邊雁，歸飛有底忙。"]'),
('1883b3eb-9e2b-49c6-beb9-c3333d6e17f7','報國寺藏經院小閣同師川駒父作二首  其二','洪朋','宋','宋诗','song-poetry','','[]','徙倚只阿閣，周遭見此邦。',48,'全唐诗/poet.song.72000.json','["徙倚只阿閣，周遭見此邦。", "莫鴉翻古木，候雁造秋江。", "風日雙蓬鬢，乾坤一瑣窗。", "真成近僧住，若箇寸心降。"]'),
('4f87bfda-40fe-4abc-bee5-c6e8d9a667fd','上巳南池作','洪朋','宋','宋诗','song-poetry','','[]','塢中元巳日，小雨浥芳菲。',48,'全唐诗/poet.song.72000.json','["塢中元巳日，小雨浥芳菲。", "祓禊歲時共，招尋吾土非。", "竹光迷野徑，花氣襲人衣。", "頼有盈川遇，還同池上歸。"]'),
('51886b11-8532-40d3-a46c-e664b7aa3d83','立秋日諸公過敝廬得秋字','洪朋','宋','宋诗','song-poetry','','[]','是月季朱夏，今辰立素秋。',48,'全唐诗/poet.song.72000.json','["是月季朱夏，今辰立素秋。", "風生庭柏浄，雨過井梧幽。", "南想高鴻度，西看大火流。", "數能文字集，如許歲時遒。"]'),
('86730eea-72c6-46f3-9e9e-15970c6b9d66','大梵寺前對月','洪朋','宋','宋诗','song-poetry','','[]','仙桂月團團，支提獨夜寒。',48,'全唐诗/poet.song.72000.json','["仙桂月團團，支提獨夜寒。", "星稀更雲斂，露下覺衣單。", "須信天宮迥，誰言世界寬。", "三生舊游衍，一見一盤桓。"]'),
('e1396b79-8f02-4400-a2b9-5266e5348da6','八月十六夜對月','洪朋','宋','宋诗','song-poetry','','[]','中秋雲物慘，既望月華鮮。',48,'全唐诗/poet.song.72000.json','["中秋雲物慘，既望月華鮮。", "欻照三千界，應勤八萬僊。", "種榆稀近應，飛鏡儼高懸。", "多病妨杯杓，清愁似去年。"]'),
('19b1d081-a934-4f7c-85b3-bd565ad279a2','次韵徐使君觀刈禾宴集二首  其一','洪朋','宋','宋诗','song-poetry','','[]','聞道秋成好，家家足釜鍾。',48,'全唐诗/poet.song.72000.json','["聞道秋成好，家家足釜鍾。", "玉山禾已刈，石臼粟還舂。", "問俗寧同樂，行厨得屢供。", "使君樓百尺，未許對元龍。"]'),
('0af7e369-2a60-4a87-8259-f9699a8575bf','次韵徐使君觀刈禾宴集二首  其二','洪朋','宋','宋诗','song-poetry','','[]','豐年觀五馬，樂飲耐千鍾。',48,'全唐诗/poet.song.72000.json','["豐年觀五馬，樂飲耐千鍾。", "稻割黄雲盡，粱添白露舂。", "藜羹不但糝，玉饌有餘供。", "堪笑他方旱，紛紛拜土龍。"]'),
('f808c182-a410-4bde-9bd1-7f45e659898e','早發新吳','洪朋','宋','宋诗','song-poetry','','[]','行路柳枝弱，池塘草色齊。',48,'全唐诗/poet.song.72000.json','["行路柳枝弱，池塘草色齊。", "石蘿人共遠，洲蘂意兼迷。", "宿霧籠城郭，春颸入鼓鼙。", "黄鸝花葉底，何事向人啼。"]'),
('dc09025e-c7b3-4f31-b740-94efe9f34654','將曉','洪朋','宋','宋诗','song-poetry','','[]','虛齋愁夢斷，寂寞夜將闌。',48,'全唐诗/poet.song.72000.json','["虛齋愁夢斷，寂寞夜將闌。", "樹與高風亂，窗餘白月寒。", "歲華還向晚，世事只長嘆。", "千古功名外，致身良獨難。"]'),
('9a3a272b-0ad9-400d-bc7b-97b795057aa1','送譚生','洪朋','宋','宋诗','song-poetry','','[]','譚子家何處，傳聞在海東。',48,'全唐诗/poet.song.72000.json','["譚子家何處，傳聞在海東。", "得朋方款款，取別太匆匆。", "曉纜廉纖雨，春帆料峭風。", "明年曲江上，應許故人同。"]'),
('79fe59dd-1b3e-4c92-95d2-2cfe18a1f3a8','卧疾','洪朋','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','卧疾滕王閣，扶藜漢將城。',48,'全唐诗/poet.song.72000.json','["卧疾滕王閣，扶藜漢將城。", "九秋天共老，獨夜月長明。", "遣興詩還賦，禁愁酒細傾。", "如聞斗上柄，未見晏眠兵。"]'),
('3e0babda-0a2d-40ed-9a30-16c93e2df35a','漫游二首  其一','洪朋','宋','宋诗','song-poetry','','[]','繚繞荒蹊密，枝撐古屋橫。',48,'全唐诗/poet.song.72000.json','["繚繞荒蹊密，枝撐古屋橫。", "雲飛賓雁急，水泛浴鳬輕。", "地迥無人跡，山空伐木聲。", "龐公禪窟內，拄杖日閒行。"]'),
('ff5c6905-30e7-4db6-a543-2486fe8ab872','漫游二首  其二','洪朋','宋','宋诗','song-poetry','','[]','欲界浩無窮，天王部落雄。',48,'全唐诗/poet.song.72000.json','["欲界浩無窮，天王部落雄。", "誰知貝葉地，即是水精宮。", "烏塔秋聲裏，鸞岡晚照中。", "先賢多妙句，欄楯入西風。"]'),
('3ff2711f-5143-48e2-b61e-300957153d4e','挽杜議郎二首  其一','洪朋','宋','宋诗','song-poetry','','[]','家世唐公子，風流漢議郎。',48,'全唐诗/poet.song.72000.json','["家世唐公子，風流漢議郎。", "左轓空老大，南紀竟凄凉。", "疇昔數相見，音容耿未忘。", "如何欻窀穸，浩歎使神傷。"]'),
('c4a4df53-b7a5-4064-b5c6-9965f268494d','挽杜議郎二首  其二','洪朋','宋','宋诗','song-poetry','','[]','醖藉鄉評舊，循良士論俱。',48,'全唐诗/poet.song.72000.json','["醖藉鄉評舊，循良士論俱。", "中年摧白玉，改歲隕明珠。", "夜雨荒村寺，秋風古路隅。", "諸郎皆有道，誰復奠生芻。"]'),
('fd9dd9db-4c95-4bdb-bbe4-75f8e1da25bf','挽范夫人','洪朋','宋','宋诗','song-poetry','','[]','淮海令名存，夫人德行尊。',48,'全唐诗/poet.song.72000.json','["淮海令名存，夫人德行尊。", "持經佛事重，教子義方敦。", "欻斷北堂夢，難招西土魂。", "定知餘慶在，可但大于門。"]'),
('3e3bed7f-0c09-458d-9b9d-ce83c112b4d8','挽仁和君胡夫人二首  其一','洪朋','宋','宋诗','song-poetry','','[]','共惟南郡族，來配謫仙家。',48,'全唐诗/poet.song.72000.json','["共惟南郡族，來配謫仙家。", "錫土縻天寵，翻經雨佛花。", "光華他日喜，牢落暮年嗟。", "餘慶知難泯，庭蘭已茁芽。"]'),
('bdd4671e-440b-4d36-be35-4e0732fdb1fa','挽仁和君胡夫人二首  其二','洪朋','宋','宋诗','song-poetry','','[]','王父依諸舅，夫人實外家。',48,'全唐诗/poet.song.72000.json','["王父依諸舅，夫人實外家。", "往時拜顔色，仰德重咨嗟。", "世事如流水，仙游只暮霞。", "可堪衰紼涕，風雨白楊斜。"]'),
('f51aa864-b386-461a-8ac0-fe9397396efe','偶詠','洪朋','宋','宋诗','song-poetry','','[]','汴水日夜去，我心亦東流。',48,'全唐诗/poet.song.72000.json','["汴水日夜去，我心亦東流。", "如何向炎熱，尚復此淹留。", "京塵空擾擾，吾道本悠悠。", "頼得西江舸，今年下鄂州。"]'),
('d304f198-d809-4101-a345-e91fa3821a1a','偶成','洪朋','宋','宋诗','song-poetry','','[]','擺落紅塵想，追隨汗漫游。',48,'全唐诗/poet.song.72000.json','["擺落紅塵想，追隨汗漫游。", "乾坤青瑣闥，雲霧曲瓊鉤。", "月照酒罇夜，風生詩句秋。", "神僊有汲引，隨意上崑丘。"]'),
('14208fb0-b19b-46b5-8acd-5a5a48077b71','獨步懷元中','洪朋','宋','宋诗','song-poetry','','[]','浄盡西山日，深行城北村。',48,'全唐诗/poet.song.72000.json','["浄盡西山日，深行城北村。", "琅璫鳴佛屋，薜荔上僧垣。", "時雨慰枵腹，夕風清病魂。", "所思渺江水，誰與共忘言。"]'),
('6fb20ff4-aeb2-43af-b746-21ea86fb4c7c','景德寺齋罷游吳氏園','洪朋','宋','宋诗','song-poetry','','[]','顧辟疆園北郭邊，伊蒲放箸得盤桓。',64,'全唐诗/poet.song.72000.json','["顧辟疆園北郭邊，伊蒲放箸得盤桓。", "老松拔地三千尺，脩竹參天一萬竿。", "官寺餘基秋草亂，書堂新構暮雲寒。", "南唐臺榭無人識，依舊江聲走急灘。"]'),
('2d46ba0a-db7c-44d8-93b6-368c548851d1','奉同師川游大梵院小軒即事','洪朋','宋','宋诗','song-poetry','','[]','底處扶藜恣意行，僧家欄楯上冥冥。',64,'全唐诗/poet.song.72000.json','["底處扶藜恣意行，僧家欄楯上冥冥。", "市聲不廢西山白，春色先從南浦青。", "晚覺惠風生草徑，坐看遲日上柴扃。", "明朝眼界即漸好，更向韋公湖上亭。"]'),
('93262768-6878-4131-a658-8ec65e9c2592','晚登大梵院小閣','洪朋','宋','宋诗','song-poetry','','[]','倚空欄楯一禪關，衲子幽人得往還。',64,'全唐诗/poet.song.72000.json','["倚空欄楯一禪關，衲子幽人得往還。", "樵徑盤紆秋草裏，僧堂結構野雲間。", "舊穿虎落嬋娟浄，晚泊龍沙舴艋閒。", "如許澄江寫寒鑑，明朝乘興上西山。"]'),
('1d1d25ab-f09b-431a-8345-60e404dacccb','次韵程正輔春日催諸公行樂之什  其一','洪朋','宋','宋诗','song-poetry','','[]','弭節江城何許時，蘭芽桃萼正芳菲。',64,'全唐诗/poet.song.72000.json','["弭節江城何許時，蘭芽桃萼正芳菲。", "孰知南紀物華好，誰謂平生心賞違。", "帝子閣前春盎盎，徵君湖上日暉暉。", "諸君行樂但取醉，車殆馬煩何必歸。"]'),
('c3af6603-1cb8-4dda-adb4-7e11c210c770','次韵程正輔春日催諸公行樂之什  其二','洪朋','宋','宋诗','song-poetry','','[]','桃李無言摘未稀，可憐郁郁復菲菲。',64,'全唐诗/poet.song.72000.json','["桃李無言摘未稀，可憐郁郁復菲菲。", "湖邊况是人皆去，花底由來我不違。", "飛蓋追隨春已晚，題詩準擬日爭暉。", "古人秉燭豈不偉，莫待芳年寂寞歸。"]'),
('e6317cdc-073a-43d2-b522-97be76b3dd05','晚登秋屏閣作示杜氏兄弟','洪朋','宋','宋诗','song-poetry','','[]','病夫湯熨暫時停，漫向秋屏閣上行。',64,'全唐诗/poet.song.72000.json','["病夫湯熨暫時停，漫向秋屏閣上行。", "白日忽隨飛鳥去，青山斷處落霞明。", "林間嘒嘒寒蟬急，江上悠悠烟艇橫。", "富貴功名付公等，嗟予老矣負平生。"]'),
('41a589f0-50a7-4181-b8bf-94b835de9631','夢登滕王閣作','洪朋','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','朱簾翠幕無處所，抖擻凝塵戶牖開。',64,'全唐诗/poet.song.72000.json','["朱簾翠幕無處所，抖擻凝塵戶牖開。", "萬里烟雲渾在眼，九秋風露獨登臺。", "西江波浪連天去，北斗星辰抱棟迴。", "獨佩一瓢供勝事，恨無陶謝與俱來。"]'),
('e833b677-c645-4eb2-9a2a-b8bbaf7db882','上巳日南池作','洪朋','宋','宋诗','song-poetry','','[]','蘂珠宮殿擁羣僊，小檻鉤簾入暝烟。',64,'全唐诗/poet.song.72000.json','["蘂珠宮殿擁羣僊，小檻鉤簾入暝烟。", "在藻流魚還潑刺，采蘋游女亦嬋娟。", "花明柳暗一溪水，日薄雲濃三月天。", "欻憶戎州在何處，停杯放箸一潸然。"]'),
('a0ab4a58-84af-44ca-937f-23538e819c1c','九日同駒父作','洪朋','宋','宋诗','song-poetry','','[]','已約龍沙看江浪，更從寶塔上晴空。',64,'全唐诗/poet.song.72000.json','["已約龍沙看江浪，更從寶塔上晴空。", "蕭蕭雨墮茲游阻，靡靡秋殘吾道窮。", "不見江州竹葉酒，空餘彭澤菊花叢。", "去年此日尤蕭瑟，兩地相思目斷中。"]'),
('85588eed-0e36-47bd-beeb-5545b1a63c19','夜雨','洪朋','宋','宋诗','song-poetry','','[]','歲云秋矣轉炎熱，怪底白日雲飛回。',64,'全唐诗/poet.song.72000.json','["歲云秋矣轉炎熱，怪底白日雲飛回。", "疾雷過耳不及掩，澍雨翻盆何自來。", "對面鐙缸聊屏箑，關心藥裹且停盃。", "更憐天上佳期近，頗覺人間令節催。"]'),
('45659534-f9b8-465f-8faf-29b98b23ad69','夜半對雪作','洪朋','宋','宋诗','song-poetry','','[]','積雪未消驚白夜，欻思小艇釣雲沙。',64,'全唐诗/poet.song.72000.json','["積雪未消驚白夜，欻思小艇釣雲沙。", "排檐故作纖纖筍，著樹還開萬萬花。", "最覺素娥相映發，不應青女妒容華。", "麥如馬尾年年在，枵腹鳴雷莫怨嗟。"]'),
('dc3f5a7c-6ea9-42a1-a18f-f81ff96f79f4','喜雪','洪朋','宋','宋诗','song-poetry','','[]','已囀春風百鳥聲，斬新飛雪滿江城。',64,'全唐诗/poet.song.72000.json','["已囀春風百鳥聲，斬新飛雪滿江城。", "漫天乾雨紛紛闇，到地空花片片明。", "白玉九衢驚曉起，黄雲千畝看秋成。", "更憐洗盡年年瘴，山鬼憂幽不敢行。"]'),
('ba044f18-e0cd-4364-82b5-09105cf168f3','送謝德夫','洪朋','宋','宋诗','song-poetry','','[]','泮宮儒先謝安石，平生笑傲東山游。',64,'全唐诗/poet.song.72000.json','["泮宮儒先謝安石，平生笑傲東山游。", "朅來客授江湖晚，不廢聲延澗壑秋。", "青青子衿惜分索，馥馥芳袖縈離愁。", "丈夫富貴恐不免，富貴應須趁黑頭。"]'),
('1d119cb5-860c-4b33-8462-b3f49486fed4','送師川','洪朋','宋','宋诗','song-poetry','','[]','去年徐郎詩句新，今來徐郎思不羣。',64,'全唐诗/poet.song.72000.json','["去年徐郎詩句新，今來徐郎思不羣。", "帝子樓前閱秋浪，秦人洞口入朝雲。", "忽思赤壁過吾弟，更向舒州迎細君。", "及此瓦盆春酒滿，燒燈夜雨重論文。"]'),
('08323d2a-ff8b-4601-99fc-9e7be7fd45b2','代餞無爲馬使君口號','洪朋','宋','宋诗','song-poetry','','[]','伏波勳業風流遠，皂蓋朱轓尚小州。',64,'全唐诗/poet.song.72000.json','["伏波勳業風流遠，皂蓋朱轓尚小州。", "一曲陽關雙別淚，百壺清酒兩遨頭。", "三年牢落應難借，五馬踟躕更少留。", "珍重促裝歸漢闕，胡床空復庾公樓。"]'),
('d8f13376-cf69-42da-82f8-94d35b2792a1','別桃源山人','洪朋','宋','宋诗','song-poetry','','[]','句履圜冠不乏賢，桃源深處隠癯仙。',64,'全唐诗/poet.song.72000.json','["句履圜冠不乏賢，桃源深處隠癯仙。", "風流未泯劉全一，意氣端如員半千。", "秋浪龍沙陪軟語，雲山鶴嶺訪高眠。", "明朝歌竟乘流去，別後還能憶浩然。"]'),
('4c051339-fdea-4705-9954-fe316c64ba00','陪許令宴集不勝杯杓詩謝不敏兼美祝趙兩紅顔','洪朋','宋','宋诗','song-poetry','','[]','南郭招提逢許令，行厨瀟灑辦逡巡。',64,'全唐诗/poet.song.72000.json','["南郭招提逢許令，行厨瀟灑辦逡巡。", "蟠桃已結千年實，瓊樹元無一點塵。", "酒後顛狂不知夜，燈前笑語自生春。", "不勝杯杓空歸去，腸斷冰肌與絳唇。"]'),
('ba9e28d8-643c-4142-8324-fe683894175f','得黔州消息','洪朋','宋','宋诗','song-poetry','','[]','夜郎西上萬里道，聞說解裝四月時。',64,'全唐诗/poet.song.72000.json','["夜郎西上萬里道，聞說解裝四月時。", "摩圍峰前何所作，谷鹿洲外不勝悲。", "豈有高明爲鬼瞰，真成憔悴被人欺。", "陛下寬仁過文帝，歸來前席亦何遲。"]'),
('87a94b22-1c6f-4773-b22a-00222b07fec9','次韵敘別和答','洪朋','宋','宋诗','song-poetry','','[]','顧曲周郎不姓龐，也尋馬祖到禪窗。',64,'全唐诗/poet.song.72000.json','["顧曲周郎不姓龐，也尋馬祖到禪窗。", "談功不見令人瘦，句法重來受我降。", "今日茶香聊對榻，異時酒泛滿盈缸。", "相期直到無心處，彷彿還須似帝江。"]'),
('98cfa943-be00-4fd8-a4e6-0b7b32b78fa2','次韵答陳孚先見贈','洪朋','宋','宋诗','song-poetry','','[]','陳子陸沉丘壑底，乘槎幾欲問明河。',64,'全唐诗/poet.song.72000.json','["陳子陸沉丘壑底，乘槎幾欲問明河。", "何人傾蓋能如故，無事高軒許數過。", "吟畏舌端多楚調，醉憐耳熱頗秦歌。", "顧予貧病難料理，政使禪齋學按摩。"]'),
('b2a7cb8b-f287-4745-97ac-0f4d0babd1ef','次韵徐十見招','洪朋','宋','宋诗','song-poetry','','[]','徐郎春晚意何如，相見蕭然水竹居。',64,'全唐诗/poet.song.72000.json','["徐郎春晚意何如，相見蕭然水竹居。", "近得柏梁七字句，俱來繭紙數行書。", "賞心不減遠公社，到眼全勝正俗廬。", "首夏清和吾定往，勿令彈鋏食無魚。"]'),
('724398c4-5d53-49e2-ada8-8300c6639e4e','謝李洪州蒞學','洪朋','宋','宋诗','song-poetry','','[]','海內聲名四十年，豫章太守得才賢。',64,'全唐诗/poet.song.72000.json','["海內聲名四十年，豫章太守得才賢。", "鳴鸞噦噦采芹地，出日遲遲祭韭天。", "可但文翁能教化，須知常衮與周旋。", "却慚不及南州士，合使塵埃一榻懸。"]'),
('ee528e1b-10de-4523-a64c-a9e00ffee142','大母誕日賦巖桂','洪朋','宋','宋诗','song-poetry','','[]','飽聞巖桂馨香舊，珍重園翁採折來。',64,'全唐诗/poet.song.72000.json','["飽聞巖桂馨香舊，珍重園翁採折來。", "天上分叢千丈老，人間擢本一枝開。", "西風白酒何勞勸，明日黄花不用催。", "更把玉壺貯秋色，影斜端爲壽觥迴。"]'),
('6968947c-65d4-464d-ac57-76271f8e281f','挽潘端州','洪朋','宋','宋诗','song-poetry','','[]','嶺南底處是端州，使君苦向箇中游。',64,'全唐诗/poet.song.72000.json','["嶺南底處是端州，使君苦向箇中游。", "黄茅千里烟嵐晚，皂蓋三年鬢髮秋。", "欻見崩松萬壑底，遂聞埋玉九原頭。", "不能執引遠郊去，薤露蒿里令人愁。"]'),
('4e8e3255-d14a-4096-b0cc-15db49638ce7','挽劉六咸臨','洪朋','宋','宋诗','song-poetry','','[]','碧梧翠竹聞家子，瓊樹瑶林物外人。',64,'全唐诗/poet.song.72000.json','["碧梧翠竹聞家子，瓊樹瑶林物外人。", "千古文章隨逝水，一生氣義屬飄塵。", "匡生左里人何在，南浦東湖迹已陳。", "想見九原託體處，白楊荒草不能春。"]'),
('3be25329-14d1-4c98-89bc-678b07d3125c','懷黄太史','洪朋','宋','宋诗','song-poetry','','[]','詩家今獨步，舅氏大名稀。',72,'全唐诗/poet.song.72000.json','["詩家今獨步，舅氏大名稀。", "屈宋堪奴僕，曹劉在指揮。", "禪心元詣絕，世事更忘機。", "最喜熊兒去，遥憐雁羽飛。", "九秋悲偃月，萬里寄摩圍。", "昭代新周典，明年歸未歸。"]'),
('e6a89450-a360-406a-9bea-e4d05bfdd091','題劉真君祠','洪朋','宋','宋诗','song-poetry','','[]','冠挂謝埃霧，雲乘上杳冥。',72,'全唐诗/poet.song.72000.json','["冠挂謝埃霧，雲乘上杳冥。", "棠陰空五馬，榆彩雜繁星。", "圜葉餘神界，華林隠翠屏。", "錦幃渺經緯，寶舄絕儀形。", "舊井金丹閟，層壇玉露零。", "千秋想靈氣，何許仰天庭。"]'),
('2d9c3423-27f1-44f3-a40d-c755f7281b02','題藏春谷壁','洪朋','宋','宋诗','song-poetry','','[]','林外鳥聲歡，江南尚小寒。',24,'全唐诗/poet.song.72000.json','["林外鳥聲歡，江南尚小寒。", "回頭又春色，早晚谷中看。"]'),
('e130cbc6-096d-4e92-9ca7-b257b1586649','排悶','洪朋','宋','宋诗','song-poetry','','[]','凍雨漲中庭，微風淪止水。',24,'全唐诗/poet.song.72000.json','["凍雨漲中庭，微風淪止水。", "泛泛藕花飄，眇眇僊茅靡。"]'),
('f58ff10c-0ac1-4be0-b18e-195cadb7df69','跋徐白魚蝦','洪朋','宋','宋诗','song-poetry','','[]','江湖各相忘，魚蝦同一波。',24,'全唐诗/poet.song.72000.json','["江湖各相忘，魚蝦同一波。", "誰能寫此妙，徐白名不磨。"]'),
('c51cdc5b-45ca-4dc0-be07-a7765c2d83b8','漫興','洪朋','宋','宋诗','song-poetry','','[]','莫愁愁不至，排悶悶還來。',24,'全唐诗/poet.song.72000.json','["莫愁愁不至，排悶悶還來。", "誰會登臨意，東風莫見猜。"]'),
('fb141d43-8750-4945-9b7d-9f5e3f794a2a','歸自潘氏園途中遇雨有感','洪朋','宋','宋诗','song-poetry','','[]','漸愧日暉暉，依人好鳥飛。',24,'全唐诗/poet.song.72000.json','["漸愧日暉暉，依人好鳥飛。", "歸來湖上路，小雨却霑衣。"]'),
('3aa24a57-5c94-47de-961e-522f81ce85cc','戲效吳語','洪朋','宋','宋诗','song-poetry','','[]','風絮鵝毛亂，春疇鮮血肥。',24,'全唐诗/poet.song.72000.json','["風絮鵝毛亂，春疇鮮血肥。", "惱儂故鄉夢，鳥勸不如歸。"]'),
('b5c159ad-734c-41a7-b827-cc95f26e4472','戲贈彈箏小妓','洪朋','宋','宋诗','song-poetry','','[]','小鬟彈啄木，寫出林間曲。',24,'全唐诗/poet.song.72000.json','["小鬟彈啄木，寫出林間曲。", "空聞剝啄聲，虛堂耿華燭。"]'),
('6887a11f-1361-4500-bbf4-a73cdfe24f6c','偶詠','洪朋','宋','宋诗','song-poetry','','[]','黄鳥餘秋聲，紅菊作秋艷。',24,'全唐诗/poet.song.72000.json','["黄鳥餘秋聲，紅菊作秋艷。", "一室得自娛，四時本無念。"]'),
('60290982-931e-4343-bf57-c20b60bd3db5','題胡潜風雨山水圖','洪朋','宋','宋诗','song-poetry','','[]','胡生好山水，烟雨山更好。',24,'全唐诗/poet.song.72000.json','["胡生好山水，烟雨山更好。", "鴻雁書遠空，馬牛風塞草。"]'),
('7c1f2063-59ba-40d7-8277-3b66b56fc3a2','廬山','洪朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山瀑兩道瀉，木葉四時春。',24,'全唐诗/poet.song.72000.json','["山瀑兩道瀉，木葉四時春。", "日暝不知去，魚鳥會留人。"]'),
('ac12d4ad-fda5-4d44-8d87-4065ae878b30','跋山谷帖用其韵  其一','洪朋','宋','宋诗','song-poetry','','[]','學書右軍盡善，下筆少陵有神。',28,'全唐诗/poet.song.72000.json','["學書右軍盡善，下筆少陵有神。", "無復向來金馬，可惜埋此玉人。"]'),
('efca8d55-3c1f-497e-acb3-5ff5028dbb3b','跋山谷帖用其韵  其二','洪朋','宋','宋诗','song-poetry','','[]','壓倒詩中宰相，鼓行文苑宗公。',28,'全唐诗/poet.song.72000.json','["壓倒詩中宰相，鼓行文苑宗公。", "毒霧瘴氛作祟，英姿爽氣成空。"]'),
('11ac2101-c4d7-4041-9ddc-8f95077ff14d','正月十八日登報國寺小閣絕句','洪朋','宋','宋诗','song-poetry','','[]','夕陽端解知人意，故照僧房閣倍明。',32,'全唐诗/poet.song.72000.json','["夕陽端解知人意，故照僧房閣倍明。", "雨雪一番今浄盡，候禽無數喚春聲。"]'),
('7f0154c3-f488-4129-9d20-f3e44006ea37','遊太寧院林英預焉','洪朋','宋','宋诗','song-poetry','','[]','松行盡處是招提，殿閣參差柏樹齊。',32,'全唐诗/poet.song.72000.json','["松行盡處是招提，殿閣參差柏樹齊。", "更與阿戎過浄院，劇談一座日還西。"]'),
('24e28836-389d-470b-bbd1-152f2241a642','題總持院','洪朋','宋','宋诗','song-poetry','','[]','后土祠邊柏造天，雷公堂下鎖嬋娟。',32,'全唐诗/poet.song.72000.json','["后土祠邊柏造天，雷公堂下鎖嬋娟。", "韋郎去後無消息，空復秋風入管弦。"]'),
('1cfb22b9-35be-4507-b01d-8873c312a829','題清凉寺','洪朋','宋','宋诗','song-poetry','','[]','萬古清凉一掬泉，十分隨量得輕安。',32,'全唐诗/poet.song.72000.json','["萬古清凉一掬泉，十分隨量得輕安。", "要知徹底無塵滓，照破天魔骨尚寒。"]'),
