('aff5f804-7f6d-400a-b6c8-133a913f631d','絕句五首  其四','洪朋','宋','宋诗','song-poetry','','[]','南窗棐几凈隠，北園藤杖閒携。',28,'全唐诗/poet.song.72000.json','["南窗棐几凈隠，北園藤杖閒携。", "在野秋風蟋蟀，界天暮雨虹蜺。"]'),
('41e9291d-1e17-4414-a37b-f07119eff8d2','絕句五首  其五','洪朋','宋','宋诗','song-poetry','','[]','窣堵坡臨南戶，給孤園映北窗。',28,'全唐诗/poet.song.72000.json','["窣堵坡臨南戶，給孤園映北窗。", "未能掌擎千界，會須口吸西江。"]'),
('0603811e-be62-4f81-90a1-82317c45f7ec','奉陪方從教泛東湖','洪朋','宋','宋诗','song-poetry','','[]','可人一宇宙，十頃降魔鏡。',96,'全唐诗/poet.song.72000.json','["可人一宇宙，十頃降魔鏡。", "彼美撰清明，令我賞茲勝。", "荷芰相因依，投壺入魚艇。", "龍蛇上崢嶸，兩滸靜相映。", "木末隠蘭若，風中度鐘磬。", "夏蟲語交加，此中有真靜。", "對此亦何言，妙處心已領。", "聊復歸去來，日入西峰暝。"]'),
('d82eea46-8c17-4a1a-bfeb-5c251f77e154','與吳迪吉劉夷季饒次守同集酒酣題壁先歸','洪朋','宋','宋诗','song-poetry','','[]','再爲城南遊，百花已狂飛。',24,'全唐诗/poet.song.72000.json','["再爲城南遊，百花已狂飛。", "更堪逢惡客，騎馬風中歸。"]'),
('610fbd54-f385-4ec1-a259-f03092a129b3','梅仙觀','洪朋','宋','宋诗','song-poetry','','[]','炎靈失其御，四海無安稅。',108,'全唐诗/poet.song.72000.json','["炎靈失其御，四海無安稅。", "嗚乎梅南昌，脫屣元始歲。", "小臣披肝膽，宮掖事嚴祕。", "上書竟渺茫，棄擲江湖外。", "一朝厭蝸角，萬里騎鵬背。", "向來殺青士，此事美無對。", "到今瑶池地，風露翔孔翠。", "仰瞻神界遊，千載想生氣。", "願爲龍鱗嬰，勿學蟬骨蛻。"]'),
('e5ac5303-5927-420e-9487-4aadd57cb261','句  其一','洪朋','宋','宋诗','song-poetry','','[]','好在龍沙黄，俄入鸞江碧。',12,'全唐诗/poet.song.72000.json','["好在龍沙黄，俄入鸞江碧。"]'),
('fdddfe15-dbca-4a27-a768-0fd3cd3d199e','句  其二','洪朋','宋','宋诗','song-poetry','','[]','盱母江頭喚渡人，遥指麻源第三谷。',16,'全唐诗/poet.song.72000.json','["盱母江頭喚渡人，遥指麻源第三谷。"]'),
('4b83b1c0-eec5-4a0d-b644-8dbde65bf85c','句  其三','洪朋','宋','宋诗','song-poetry','','[]','繭收松上雪，麥刈隴頭雲。',12,'全唐诗/poet.song.72000.json','["繭收松上雪，麥刈隴頭雲。"]'),
('19e6df8e-51e5-41de-b7e3-cb819645e756','句  其四','洪朋','宋','宋诗','song-poetry','','[]','蒲根水滿雁初下，梅徑香寒蝶不知。',16,'全唐诗/poet.song.72000.json','["蒲根水滿雁初下，梅徑香寒蝶不知。"]'),
('8e1b68aa-9991-4b9b-a144-602f35887dd1','句  其五','洪朋','宋','宋诗','song-poetry','','[]','花明柳暗一溪水，日薄雲濃三月天。',16,'全唐诗/poet.song.72000.json','["花明柳暗一溪水，日薄雲濃三月天。"]'),
('f8119889-aa40-418d-9d37-de880282b81f','句  其六','洪朋','宋','宋诗','song-poetry','','[]','海棠照日倚垂楊，萬縷千絲影零亂。',16,'全唐诗/poet.song.72000.json','["海棠照日倚垂楊，萬縷千絲影零亂。"]'),
('3758eac3-ba2a-4efa-9ac8-0e632785978a','句  其七','洪朋','宋','宋诗','song-poetry','','[]','綠竹可供公子釣。',8,'全唐诗/poet.song.72000.json','["綠竹可供公子釣。"]'),
('26ecd08c-0b1b-4224-affb-ef164adc47be','句  其八','洪朋','宋','宋诗','song-poetry','','[]','青鞋黄帽飽經過。',8,'全唐诗/poet.song.72000.json','["青鞋黄帽飽經過。"]'),
('aa5d437e-04e8-4181-84eb-88628756813e','句  其九','洪朋','宋','宋诗','song-poetry','','[]','碧瓦朱甍占蕭爽。',8,'全唐诗/poet.song.72000.json','["碧瓦朱甍占蕭爽。"]'),
('9f1b8a2d-effa-4c54-9e24-ecc05191d3f9','句  其一○','洪朋','宋','宋诗','song-poetry','','[]','官梅一樹小池頭。',8,'全唐诗/poet.song.72000.json','["官梅一樹小池頭。"]'),
('d57bb592-97ca-4a91-b75f-d07999f78322','句  其一一','洪朋','宋','宋诗','song-poetry','','[]','蘂珠宮殿擁神仙。',8,'全唐诗/poet.song.72000.json','["蘂珠宮殿擁神仙。"]'),
('aaccc2d0-4847-4aca-a50a-5eeac2dc9948','句  其一二','洪朋','宋','宋诗','song-poetry','','[]','贈我麝煤如黑玉，爲君龍尾濯清秋。',16,'全唐诗/poet.song.72000.json','["贈我麝煤如黑玉，爲君龍尾濯清秋。"]'),
('a3403f73-29c4-49f7-98de-63b8bf82b7cd','句  其一三','洪朋','宋','宋诗','song-poetry','','[]','櫂歌縹緲城西路，烟樹參差埭北村。',16,'全唐诗/poet.song.72000.json','["櫂歌縹緲城西路，烟樹參差埭北村。"]'),
('540bd496-6ab5-47a6-9b91-0abb93d3797c','蓮華洞答友人','洪芻','宋','宋诗','song-poetry','','[]','蓮峰聳崔巍，在眼昔未到。',96,'全唐诗/poet.song.72000.json','["蓮峰聳崔巍，在眼昔未到。", "發興空盤紆，舒寫屬吟嘯。", "五老如有情，遥岑動清眺。", "新篇下紫霄，語我遊歷妙。", "物景會相忘，烟霞領其要。", "坐石掬清流，緣雲睨奔峭。", "悠然俛仰間，無心乃同調。", "偕遊會有期，山靈勿騰笑。"]'),
('5a6975c3-9bd9-4ca9-a3b6-fd18c536eab6','遊泐潭寺','洪芻','宋','宋诗','song-poetry','','[]','吾聞石門山，對峙儼天闢。',240,'全唐诗/poet.song.72000.json','["吾聞石門山，對峙儼天闢。", "林茂山自青，草香澗長碧。", "中有古招提，柱栱煥青赤。", "惟昔馬大士，方墳聳遺迹。", "龍象仰慈顔，馬駒讖前識。", "香火有因緣，窗戶坐幽闃。", "瓶錫想異時，雲水飽遊歷。", "飲波浥曹溪，法雨被江國。", "大闡選佛場，法戰無兼敵。", "我非山中人，蹔著登山屐。", "東閣嘲書淫，凈境酬詩癖。", "朝涉潺湲溪，暮陟崔嵬石。", "敷床聽犍椎，鉢飯分香積。", "山高日易斜，夢短夜分寂。", "神心頗靈明，俗慮詎充斥。", "歸歟得短章，投筆疥其壁。", "政如抱布鼓，豈能飛霹靂。", "徑須倩阿香，轟然聽霆擊。", "忽傳湯休篇，風騷共推激。", "何當從君遊，願飛恨無翼。"]'),
('0f1d520e-2ae8-4a35-9430-f8b9e7720255','次子字韵呈鄭太玉','洪芻','宋','宋诗','song-poetry','','[]','斯文不可見，猶欣識之子。',96,'全唐诗/poet.song.72000.json','["斯文不可見，猶欣識之子。", "端如逃虛空，而聞跫音喜。", "歷歷海南事，細話傾我耳。", "悠悠世上情，毀譽私彼己。", "是事姑置之，斯文長已矣。", "風味契淵明，流落逾子美。", "從來直如弦，多作道邊死。", "寄聲柳柳州，未用斬曲几。"]'),
('45178cc2-5bde-4654-8535-6afa257aa894','孤鶴行贈楊君','洪芻','宋','宋诗','song-poetry','','[]','翩翩雲中鶴，來自華亭濱。',120,'全唐诗/poet.song.72000.json','["翩翩雲中鶴，來自華亭濱。", "徘回久乃集，佇立江之濆。", "高步整霜羽，隻影翔秋旻。", "豈無鴻鵠侶，俛仰鷄鶩羣。", "啄腥細流中，汝食得無貧。", "況有繒繳虞，驚顧何逡巡。", "珠庭響清唳，胎仙舞祥雲。", "胡不矯翮去，來儀瑞吾君。", "饑食玉山禾，渴飲瑶池津。", "無言九皋遠，鳴陰誰不聞。"]'),
('08b0daf5-0e27-4f65-894f-261f02d4427d','寄題貫時軒詩','洪芻','宋','宋诗','song-poetry','','[]','古人憩息地，不種凡草木。',96,'全唐诗/poet.song.72000.json','["古人憩息地，不種凡草木。", "數竿何必多，可以慰幽獨。", "忘憂玩芳草，怡顔眄庭柯。", "豈無艷陽節，摇落將如何。", "彼美軒中人，澹然對浮雲。", "此君有佳處，心期暗相親。", "蕭蕭四時色，目擊道逾妙。", "君看竹得風，天然向人笑。"]'),
('57be09c1-2378-43b3-baeb-7890f110a46d','因讀梅聖俞六鶴詩或令余別賦之 警露','洪芻','宋','宋诗','song-poetry','','[]','皎皎蟾桂明，耿耿星斗爛。',36,'全唐诗/poet.song.72000.json','["皎皎蟾桂明，耿耿星斗爛。", "清夢時時驚，零露滴霄漢。", "偉哉仙人騎，從來知夜半。"]'),
('fdb2ee1e-8a88-43e5-9b9b-aa11d2d638d3','因讀梅聖俞六鶴詩或令余別賦之 顧步','洪芻','宋','宋诗','song-poetry','','[]','舉趾一何高，脩頸宛回顧。',36,'全唐诗/poet.song.72000.json','["舉趾一何高，脩頸宛回顧。", "隻影踉蹡行，眷然慕儔侶。", "豈忘赤霄上，盤桓此池籞。"]'),
('25fafa3e-ae72-4a91-a452-00f0baf1b0dd','因讀梅聖俞六鶴詩或令余別賦之 理毛','洪芻','宋','宋诗','song-poetry','','[]','飄飄青田質，斂翼在亭皋。',36,'全唐诗/poet.song.72000.json','["飄飄青田質，斂翼在亭皋。", "回此碧玉喙，刷我白雪毛。", "顧影矜羽儀，孔翠非其曹。"]'),
('de794824-2a1d-495f-b319-aa9624fc6554','因讀梅聖俞六鶴詩或令余別賦之 唳天','洪芻','宋','宋诗','song-poetry','','[]','清唳九皋內，抗音薄層雲。',36,'全唐诗/poet.song.72000.json','["清唳九皋內，抗音薄層雲。", "戛然時一鳴，流響驚人羣。", "嗟哉陸內史，華亭無復聞。"]'),
('50172db9-1a61-4083-8690-3056c7779e2d','因讀梅聖俞六鶴詩或令余別賦之 舞風','洪芻','宋','宋诗','song-poetry','','[]','歸來丁令威，暫別已千年。',36,'全唐诗/poet.song.72000.json','["歸來丁令威，暫別已千年。", "抽琴奏清角，婆娑舞胎仙。", "何必拊節和，御風自泠然。"]'),
('19188bac-69fe-4f3b-8e93-f38b83089a35','因讀梅聖俞六鶴詩或令余別賦之 啄食','洪芻','宋','宋诗','song-poetry','','[]','昂昂兀兀姿，朱冠垂素翎。',36,'全唐诗/poet.song.72000.json','["昂昂兀兀姿，朱冠垂素翎。", "首下尻益高，徘回我中庭。", "俯仰鷄鶩羣，啄腐復吞腥。"]'),
('a0923d9f-55ff-49ae-a187-b36b841f5057','同師川過李三十九湖上宅用師川韵','洪芻','宋','宋诗','song-poetry','','[]','多書唐鄴侯，藹藹盛雲來。',96,'全唐诗/poet.song.72000.json','["多書唐鄴侯，藹藹盛雲來。", "髯公頗好事，相過必遲回。", "結構平湖陰，清絕無纖埃。", "數到不知遠，君家寬酒盃。", "遶水信杖屨，披靡蓬蒿開。", "遺基訪孺子，荒墳弔澹臺。", "誅茅卜鄰並，茲願何當諧。", "七松未暇種，五柳徑須栽。"]'),
('e6e233d7-bab7-445a-b56a-3bb450ffb941','同陳虛中勸農出郊因遊明水山寺','洪芻','宋','宋诗','song-poetry','','[]','深樹鳴鷤䳏，紅紫春事休。',204,'全唐诗/poet.song.72000.json','["深樹鳴鷤䳏，紅紫春事休。", "臨川賢假守，只今陳太丘。", "駕言出遠郊，班春臨道周。", "亦招素冠士，來從朱轓遊。", "晨興愜勝引，適此夜雨收。", "原隰亂高下，意行逐前儔。", "荒荒白水滿，鬰鬰稻秧抽。", "舊聞明水寺，宛在巖之幽。", "石門本無關，鳴禽自相求。", "不有省耕役，俗駕來何由。", "老屋隠喬木，野僧事良疇。", "松徑深窈窕，軒車紛少留。", "遲回動歸興，衝雨戒摧輈。", "危情極冰淵，細路遵塍溝。", "深泥艱涉足，竹鷄爲我愁。", "豈憚來往頻，清與耳目謀。", "回首謝青山，尋盟亦悠悠。"]'),
('705a9a6c-4265-4f88-8da6-703ea2a7e8ec','贈倪濤少府','洪芻','宋','宋诗','song-poetry','','[]','君從淮上來，手持阿髯詩。',96,'全唐诗/poet.song.72000.json','["君從淮上來，手持阿髯詩。", "塵埃欣拂拭，得此带經倪。", "珠璧豈投暗，按劍有餘悲。", "願保青雲姿，勿歎黄綬卑。", "太山駐翠輦，行草封禪儀。", "漢皇儻借問，潤色非君誰。", "我非國僑賢，慚負延陵知。", "縞带敢虛辱，贈言當紵衣。"]'),
('fccc0fc4-4472-4fda-bcb9-c4d3e774d0a2','次韵和鄭太玉新居','洪芻','宋','宋诗','song-poetry','','[]','荒塗負崇岡，君居在其麓。',84,'全唐诗/poet.song.72000.json','["荒塗負崇岡，君居在其麓。", "下與佛界連，一徑通芻牧。", "高情慕天隨，枵腹茹杞菊。", "數椽負郭居，窈窕鑿空谷。", "憶昨步過君，窘步侵兩足。", "聽君亹亹談，霏屑落鋸木。", "相依方在茲，凉飆蕩煩燠。"]'),
('82a48ef9-45ab-439e-800b-60e1552b5daf','宴李氏園亭得慶字韵','洪芻','宋','宋诗','song-poetry','','[]','我來北斗南，兩見回東柄。',168,'全唐诗/poet.song.72000.json','["我來北斗南，兩見回東柄。", "萬斛開府愁，四壁文園病。", "誰知深巷中，卉木頗幽夐。", "大梁賢公子，携酒賓亦命。", "紅蕤已飄零，綠綺方輝映。", "豈惟追尋遲，亦苦風雨橫。", "主賓混誰何，談笑雜嘲評。", "詎知時雨靈，但覺中酒聖。", "年豐樂崇寧，詩敵躡長慶。", "況有雷陳交，何必宛洛盛。", "律管承飛灰，羲和駐春令。", "日月曾幾何，佳辰我所竟。", "芍藥殿餘春，想見晨粧靚。", "一醉歡有餘，此集君其更。"]'),
('afc53297-c5d1-433b-b817-52b1be66ac63','題黄稚川雲巢','洪芻','宋','宋诗','song-poetry','','[]','雲巢一上十五里，中有今世巢居子。',128,'全唐诗/poet.song.72000.json','["雲巢一上十五里，中有今世巢居子。", "鷄鳴犬吠白雲裏，不知天際去此幾。", "平生深契鳥巢禪，翦茅蓋頭萬事已。", "宴坐經行飛鳥上，人間榮辱不到耳。", "蝸牛兩角竟何爲，鷦鷯一枝端自喜。", "我有一廛落城市，章服裹狙聊復爾。", "武溪未訪桃花源，脩江儻問桃花水。", "會取櫻桃洞前路，藜杖扶衰從此始。"]'),
('af4b6030-2f4e-4f39-a521-a699b8ea6a8f','戲用荆公體呈黄張二君','洪芻','宋','宋诗','song-poetry','','[]','金華牧羊兒，穩坐思悠哉。',136,'全唐诗/poet.song.72000.json','["金華牧羊兒，穩坐思悠哉。", "誰人得似張公子，鞭笞鸞鳳終日相追陪。", "長夏無所爲，壘麴便築糟邱臺。", "古今同一體，吾人甘作心似灰。", "南方瘴癘地，鬰蒸何由開。", "永日不可暮，渴心歸去生塵埃。", "人生會合安可常，如何不飲令心哀。", "張公子，時相見，我能拔爾抑塞磊落之奇才。", "只願無事常相見，有底忙時不肯來。"]'),
('70f0714b-489a-4abd-a877-0ffb12a5eb5b','松棚','洪芻','宋','宋诗','song-poetry','','[]','南山落落千尺松，干雲蔽日摇青葱。',192,'全唐诗/poet.song.72000.json','["南山落落千尺松，干雲蔽日摇青葱。", "盤根錯節歲月古，龍吟虎嘯號悲風。", "北山文杏中梁棟，我材臃腫非世用。", "脩枝細葉幸有餘，頳肩大束那辭送。", "承以高竹青扶疏，置君寬閑之玉除。", "倏如亂雲駐車蓋，怳似廣庭張拂廬。", "垂頭塌翼下孔翠，張鱗擺鬣來鯨魚。", "穿空入隙清飆吹，疑有萬壑哀聲隨。", "羲和按轡不馳騁，炎官火傘將安施。", "朅來投荒近循海，日坐板屋如蒸炊。", "南山蒼官憐我熱，遺我七鬣千孫枝。", "但令脩幹青青多，溫風烈日如予何。"]'),
('f175a450-d9d3-409a-85f3-e56a7c350636','再次洪上人雲巢韵','洪芻','宋','宋诗','song-poetry','','["\u897f\u6e56"]','黄子厭喧求避俗，直上孤峰結茅屋。',128,'全唐诗/poet.song.72000.json','["黄子厭喧求避俗，直上孤峰結茅屋。", "欲期汗漫游九垓，俯視塵寰戰蠻觸。", "小山招隠喚不回，舊時從事有邊幅。", "不能投筆學文鴛，底用决科似張鷟。", "自賦雲巢自高唱，手握靈蛇嗤魚目。", "由來江夏多可人，藍田片片生美玉。", "要須青山頂上行，去伴白雲簷下宿。", "西湖窟穴對華榱，肯把蘭亭比金谷。"]'),
('57412bcc-cfcf-4829-a1cc-2e3053192253','板屋','洪芻','宋','宋诗','song-poetry','','[]','西戎板屋詩所錄，甌閩萬里同風俗，風吟日暴雨所沐。',222,'全唐诗/poet.song.72000.json','["西戎板屋詩所錄，甌閩萬里同風俗，風吟日暴雨所沐。", "巧匠引繩如解玉，谿民得之亟乘屋。", "既輕且堅尺度足，可憐童我南山木。", "君不見曹瞞鄴下銅雀臺，陶土作瓦何壯哉。", "臺傾基平瓦尚在，鑿爲大研奇且瑰。", "君不見黄州使君誇竹樓，剖竹俛仰相綢繆。", "琮琤最宜雨中聽，擊考有類鳴琳球。", "銅雀幺麽何足摹，籜龍燥輕易焚如。", "不如杉屋壽且姝，風雨不動何渠渠。", "嗟予抱釁謫蠻夷，如人體瓌欣解衣。", "數椽破屋亦不惡，仰見星宿相參差。", "鴟鴞作室庇風雨，鷦鷯巢林安一枝。", "凌雲大厦鬼所窺，衡門之下可棲遲。"]'),
('36ba153e-b8e4-476b-af32-1376e04e0713','次陳州','洪芻','宋','宋诗','song-poetry','','[]','一水縈回橐駝項，百丈遥牽如簸掌。',64,'全唐诗/poet.song.72000.json','["一水縈回橐駝項，百丈遥牽如簸掌。", "鸕鷀捕魚沒復出，鷺鷥行沙俯還仰。", "白雲思我白頭親，雙足未到心先往。", "黄昏繫纜危臺邊，飯糗羹藜莫惆悵。"]'),
('e6f87748-0f39-4b9e-a5a3-56a3e2593bbc','次李少微韵','洪芻','宋','宋诗','song-poetry','','[]','春風楊柳岸，寒食杏花村。',48,'全唐诗/poet.song.72000.json','["春風楊柳岸，寒食杏花村。", "對月驚生魄，思人暗斷魂。", "我閑無吏考，君治有司存。", "又作匆匆別，相逢席未溫。"]'),
('7dad094f-4dc1-4ec5-8908-d6a0afcfb3f2','次韵和王張贈別之作','洪芻','宋','宋诗','song-poetry','','[]','五言聊贈別，二妙送將歸。',48,'全唐诗/poet.song.72000.json','["五言聊贈別，二妙送將歸。", "立馬然萁敏，爭鋒嚙鏃機。", "日將秋共晚，人與雁俱飛。", "去住加餐飯，新霜點客衣。"]'),
('e6fbc92d-0199-4612-83ac-2d5e1f0163a6','次師川韵  其一','洪芻','宋','宋诗','song-poetry','','[]','與君城北寺，取次對床眠。',48,'全唐诗/poet.song.72000.json','["與君城北寺，取次對床眠。", "坐即棋中隠，時逃醉裏禪。", "相招從白社，不擬問青天。", "但有加餐飯，無田亦願年。"]'),
('4dde48c3-d4a9-46da-8339-af0798fc5c01','次師川韵  其二','洪芻','宋','宋诗','song-poetry','','[]','卧疴非傲世，背俗信畸人。',48,'全唐诗/poet.song.72000.json','["卧疴非傲世，背俗信畸人。", "無復少年事，偶隨肥馬塵。", "靜便門掃軌，懶任草如茵。", "迹滯江山勝，心將魚鳥親。"]'),
('6fca7d1f-64d4-4ce3-83ed-901d37b32238','次瑛上人懷汪彥章韵','洪芻','宋','宋诗','song-poetry','','[]','君雖四禪侶，自是一詩家。',48,'全唐诗/poet.song.72000.json','["君雖四禪侶，自是一詩家。", "白足濯蛟井，清風振龍沙。", "虛室無長物，多文富生涯。", "懷人有新作，粲粲菖蒲花。"]'),
('47fb2e03-fc72-4ffe-afbf-f0bc25743071','次韵師川題余荀龍壁間三首  其一','洪芻','宋','宋诗','song-poetry','','[]','青鏡磨秋水，紅衣退藕花。',48,'全唐诗/poet.song.72000.json','["青鏡磨秋水，紅衣退藕花。", "朅來尋五柳，端欲問三車。", "濁酒休論限，浮生定有涯。", "比封千戶竹，鼓吹一湖蛙。"]'),
('d485c5e1-1162-49f8-9d02-5cb86cbcf988','次韵師川題余荀龍壁間三首  其二','洪芻','宋','宋诗','song-poetry','','[]','高文腸是錦，妙句筆生花。',48,'全唐诗/poet.song.72000.json','["高文腸是錦，妙句筆生花。", "松菊開三徑，詩書載五車。", "曲湖鄰賀監，複壁笑王涯。", "海若應憐我，貽書問井蛙。"]'),
('fc6b1384-d6e0-4d7a-b5c6-a3c97e70dbc7','次韵師川題余荀龍壁間三首  其三','洪芻','宋','宋诗','song-poetry','','[]','我來占食指，客至卜燈花。',48,'全唐诗/poet.song.72000.json','["我來占食指，客至卜燈花。", "但祝加餐飯，何勞問頰車。", "交情真莫逆，秋興浩無涯。", "姑置人間事，紛紛祇鬭蛙。"]'),
('017c5b7b-08f3-4a54-8b18-efd3c5a2c0a5','喜雨詩','洪芻','宋','宋诗','song-poetry','','[]','日日望南山，朝隮解我顔。',48,'全唐诗/poet.song.72000.json','["日日望南山，朝隮解我顔。", "雲垂四天外，雨灑一林間。", "枯沼微瀾動，旱苗生意還。", "慇懃祝屏翳，莫爲遠人慳。"]'),
('db95943b-cd26-49ec-886c-165a60e27494','次師川韵喜雨呈彥章  其一','洪芻','宋','宋诗','song-poetry','','[]','綠塘深漲雨，紅芰靜舒花。',48,'全唐诗/poet.song.72000.json','["綠塘深漲雨，紅芰靜舒花。", "卧上三竿日，晴喧兩部蛙。", "老饕猶善飯，水厄怯逢茶。", "擬到新池畔，來尋謝客家。"]'),
('8f7b04bb-b9ab-427d-800e-da0e8ca2b9f9','次師川韵喜雨呈彥章  其二','洪芻','宋','宋诗','song-poetry','','[]','登高能共賦，好雨故催詩。',48,'全唐诗/poet.song.72000.json','["登高能共賦，好雨故催詩。", "階草卧青軟，畦苗垂綠滋。", "夏深飛燕靜，秋近候蟲知。", "寄語耽吟客，可無新句爲。"]'),
('37e530e4-748a-4c33-818b-a70af70ff5af','次韵和彥章池上之作二首  其一','洪芻','宋','宋诗','song-poetry','','[]','官閑發興清，水遠覺空明。',48,'全唐诗/poet.song.72000.json','["官閑發興清，水遠覺空明。", "玉局思無限，青蘋風自生。", "魚荷翻暮色，蟬樹带秋聲。", "雲黑斜陽外，遥知雨又晴。"]'),
('8f71acd7-3bfb-4ea9-bac3-47de13890db3','次韵和彥章池上之作二首  其二','洪芻','宋','宋诗','song-poetry','','[]','水檻凉秋好，風林初日明。',48,'全唐诗/poet.song.72000.json','["水檻凉秋好，風林初日明。", "屏間青嶂合，鏡裏白雲生。", "茶試旗槍色，蛙添鼓吹聲。", "瘦筇聊復倚，遶水步新晴。"]'),
('39ecaed4-b638-4093-9baf-9bedbbc6d66b','題雙林寺','洪芻','宋','宋诗','song-poetry','','[]','幽谷雙林寺，荒郊得遠尋。',48,'全唐诗/poet.song.72000.json','["幽谷雙林寺，荒郊得遠尋。", "銀鈎遺墨在，筆諫慕賢深。", "徙倚千山晚，坐愁三日霖。", "枯棋圍白黑，聊復費光陰。"]'),
('c21cb528-e501-4e3a-9e36-b3df6d37a715','潘延之挽詞','洪芻','宋','宋诗','song-poetry','','[]','肥遁攀巢許，幽光燭斗牛。',48,'全唐诗/poet.song.72000.json','["肥遁攀巢許，幽光燭斗牛。", "長公辭漢世，孺子隠南州。", "閉戶荒三徑，紬書綜九流。", "欲尋高士傳，端向古人求。"]'),
('400864c1-20ac-47f7-89e8-139f154abdde','次韵和元禮','洪芻','宋','宋诗','song-poetry','','[]','湖海沙鷗性，山林霧豹文。',48,'全唐诗/poet.song.72000.json','["湖海沙鷗性，山林霧豹文。", "龍蛇爭起陸，羔雁看成羣。", "玉石無緇磷，芝蘭自苾芬。", "韓康不二價，女子會知君。"]'),
('64bd7798-105d-4c2e-be69-0a41f21676f2','容膝軒','洪芻','宋','宋诗','song-poetry','','[]','烏隼經行處，蝸牛窈窕深。',48,'全唐诗/poet.song.72000.json','["烏隼經行處，蝸牛窈窕深。", "會稽雖奉計，彭澤自無心。", "禪寄跏趺坐，風披徙倚襟。", "莫言容膝地，不廢掉頭吟。"]'),
('fe4ccfb2-a202-4c01-90ef-39f098470410','送張元幹','洪芻','宋','宋诗','song-poetry','','[]','自昔張平子，愁來賦四愁。',48,'全唐诗/poet.song.72000.json','["自昔張平子，愁來賦四愁。", "行看車馬客，坐覺歲時流。", "明月江山夜，候蟲天地秋。", "怪君有底急，不肯少遲留。"]'),
('1aed528b-91f4-4740-9713-c95cc754bb6f','嘲偷兒','洪芻','宋','宋诗','song-poetry','','[]','長卿惟有壁，囊橐自無錢。',48,'全唐诗/poet.song.72000.json','["長卿惟有壁，囊橐自無錢。", "金盡何勞攫，墉疏豈待穿。", "未能拋鼎祿，猶復戀青氈。", "梁上休驚墜，饑寒亦可憐。"]'),
('57fb91df-4e9b-4342-8cba-05e61faa8a04','書懷','洪芻','宋','宋诗','song-poetry','','[]','北闕書休上，南窗膝易安。',48,'全唐诗/poet.song.72000.json','["北闕書休上，南窗膝易安。", "道肥知戰勝，歸約已盟寒。", "委吏無麟筆，迂儒置蝨官。", "所須升斗水，肯沃鮒魚乾。"]'),
('43958c1c-6bff-41a8-87fe-4feb19135639','又和師川同集章江寺二首  其一','洪芻','宋','宋诗','song-poetry','','[]','鹿苑江南寺，龍沙城北遊。',48,'全唐诗/poet.song.72000.json','["鹿苑江南寺，龍沙城北遊。", "脩椽雲自宿，返照雨還收。", "禪麈尋支遁，棋枰對弈秋。", "還家真復樂，何必遠封侯。"]'),
('459c8f2a-fd84-49df-a114-6c03acd19aa9','又和師川同集章江寺二首  其二','洪芻','宋','宋诗','song-poetry','','[]','興發尋荒徑，途窮見寶坊。',48,'全唐诗/poet.song.72000.json','["興發尋荒徑，途窮見寶坊。", "隨宜聊復飽，觸處得追凉。", "取友真濠上，懷人向渭陽。", "不嫌茶七碗，殊勝酒千觴。"]'),
('c9b9a2ff-28ab-4919-bebb-61e5178d2729','口占贈何秀才','洪芻','宋','宋诗','song-poetry','','[]','何郎閩越英，疇昔昧平生。',48,'全唐诗/poet.song.72000.json','["何郎閩越英，疇昔昧平生。", "邂逅同衾宿，夷猶共舸行。", "繁臺半床夢，潁水一篙清。", "俄頃膠投漆，難忘此日情。"]'),
('2bbc09c1-8803-4d5f-9cfc-f680d391cd8f','次韵李商老贈李少魏','洪芻','宋','宋诗','song-poetry','','[]','誅茅遲竹君，拂匣見桐孫。',48,'全唐诗/poet.song.72000.json','["誅茅遲竹君，拂匣見桐孫。", "囊篋深傾倒，鐘彝細討論。", "只今仙李後，好事阿髯存。", "不厭敲門客，時開炙背軒。"]'),
('f46eabb5-960c-48a1-8edc-4a4e317b4b6e','題泐潭院','洪芻','宋','宋诗','song-poetry','','[]','平生麋鹿性，名山恣幽尋。',48,'全唐诗/poet.song.72000.json','["平生麋鹿性，名山恣幽尋。", "歷盡巖壑奧，始聞鐘梵音。", "中多不凋木，上有自呼禽。", "許稅俗士駕，茲焉聊洗心。"]'),
('721b4eeb-d892-427f-8c5f-fec1e92fcaea','再遊泐潭院用前韵','洪芻','宋','宋诗','song-poetry','','[]','石門久寒盟，茲遊得重尋。',48,'全唐诗/poet.song.72000.json','["石門久寒盟，茲遊得重尋。", "靜契祖師妙，清聞山水音。", "長閑羨老衲，幽思愧鳴禽。", "可怕移文劾，沙鷗知我心。"]'),
('3d015a13-c186-4cb5-b5c0-f85ffb30c389','次韵陳使君詠霰雪三首  其一','洪芻','宋','宋诗','song-poetry','','[]','天幙垂雲合，山屏擁雪飛。',48,'全唐诗/poet.song.72000.json','["天幙垂雲合，山屏擁雪飛。", "楊公田種玉，淵客淚成璣。", "點綴添梅萼，飄零亂羽衣。", "清溪橫一葉，併載月明歸。"]'),
('e2bdf4ea-a377-4730-89ad-3ad28958e226','次韵陳使君詠霰雪三首  其二','洪芻','宋','宋诗','song-poetry','','[]','蕭灑宣城守，揮毫雪共飛。',48,'全唐诗/poet.song.72000.json','["蕭灑宣城守，揮毫雪共飛。", "山川映重璧，咳唾鬭明璣。", "佳氣籠寒谷，歡聲抵襲衣。", "霜臺如不踐，粉省定須歸。"]'),
('b1a62d51-d996-4a93-aa01-e9879d82ca0b','次韵陳使君詠霰雪三首  其三','洪芻','宋','宋诗','song-poetry','','[]','敷床初屑屑，入夜故飛飛。',48,'全唐诗/poet.song.72000.json','["敷床初屑屑，入夜故飛飛。", "拭處渾拋粉，揉來亂擲璣。", "銀蟾分玉照，雲絮借天衣。", "地席橫陳處，晨曦未得歸。"]'),
('0220b422-bd87-40e4-a4fc-e19f3625575f','和郭功甫題客館韵','洪芻','宋','宋诗','song-poetry','','[]','容膝柴門覺易安，數椽喜枕寺東山。',64,'全唐诗/poet.song.72000.json','["容膝柴門覺易安，數椽喜枕寺東山。", "雁飛不到吾來此，燕亦知歸客未還。", "夢斷霜鐘年欲晏，愁聽蠻鼓鬢先班。", "自公退食門長掩，未必鄰僧似我閑。"]'),
('3b4c53d2-8f74-4f54-b18b-a14ec6ac06d5','翠巖道人蒔貓頭竹生大筍十餘調護甚謹爲予從者髠盜殆盡戲作長句解嘲','洪芻','宋','宋诗','song-poetry','','[]','觸藩大筍闖貓頭，竊屨真成從者廋。',64,'全唐诗/poet.song.72000.json','["觸藩大筍闖貓頭，竊屨真成從者廋。", "山鹿恰看逢角解，籜龍端有剖胎憂。", "因供蒲塞桑門饌，殊勝渭川千戶侯。", "翻恐癡兒癡黠半，爲君浄盡破除休。"]'),
('418e374b-041a-4122-b9c7-524273247edd','歸自西山至黄梔港口','洪芻','宋','宋诗','song-poetry','','[]','衝雨穿雲愁去路，歸雲閣雨路還通。',64,'全唐诗/poet.song.72000.json','["衝雨穿雲愁去路，歸雲閣雨路還通。", "七層涌塔瞻天際，三徑吾廬在眼中。", "港轉黄梔橫野艇，里空白社漫春風。", "青山送我寧辭遠，流水隨人亦欲東。"]'),
('1e18644e-cf20-4baa-9303-c3a5dba3a97b','次山谷韵  其一','洪芻','宋','宋诗','song-poetry','','[]','妙峰宛在水中央，上有莊嚴清浄坊。',64,'全唐诗/poet.song.72000.json','["妙峰宛在水中央，上有莊嚴清浄坊。", "壞衣盤礴蝸牛角，法窟窈冥師子床。", "萬象森羅一拳石，千頃汪洋百谷王。", "不減乘槎到牛女，擬取支機問下方。"]'),
('b703fb90-1a2e-4a6f-ae5b-93c2843689b7','次山谷韵  其二','洪芻','宋','宋诗','song-poetry','','[]','寶石崢嶸佛所廬，經宿何年下清都。',64,'全唐诗/poet.song.72000.json','["寶石崢嶸佛所廬，經宿何年下清都。", "海市樓臺湧金碧，木落牖戶明江湖。", "千波舂撞有崩態，萬棟凌壓無完膚。", "巨鼇冠山勿驚走，欲尋高處垂明珠。"]'),
('76ef81b7-91cf-48af-a6a9-f1bf7228c8be','陪陳使君宴南山亭','洪芻','宋','宋诗','song-poetry','','[]','曉露無塵夜雨收，日光穿漏趁公遊。',64,'全唐诗/poet.song.72000.json','["曉露無塵夜雨收，日光穿漏趁公遊。", "烟花淡蕩連三里，雲樹低迷羃一州。", "岡轉卧龍春色老，氣橫野馬夕陽愁。", "林間新火明雙炬，歌舞南山最上頭。"]'),
('421fee6c-e42d-4274-84ab-d2ef8729a636','次杜公韵','洪芻','宋','宋诗','song-poetry','','[]','杜郎得飽肥如瓠，怪我秋來太瘦生。',64,'全唐诗/poet.song.72000.json','["杜郎得飽肥如瓠，怪我秋來太瘦生。", "時輩不應推翰墨，論文時許過柴荆。", "朋交結綬非能事，身世靈丹豈易成。", "幽徑新凉約微步，晚風含樹有蟬聲。"]'),
('b8ba2274-3fb0-4937-82af-945399d37da1','次韵李商老見懷之什','洪芻','宋','宋诗','song-poetry','','[]','一日思君劇九秋，平生問事賈長頭。',64,'全唐诗/poet.song.72000.json','["一日思君劇九秋，平生問事賈長頭。", "郵傳頗怪詩來晚，技癢遥憐筆不休。", "王孫莫問投書渚，芳草空迷谷鹿洲。", "望斷西山山盡處，雲居何處只空愁。"]'),
('9630e632-fd41-4354-a15e-bff18645ccd0','次韵閱道見貽之句','洪芻','宋','宋诗','song-poetry','','[]','獨來深樹初啼鳥，幾處高枝已嘒蟬。',64,'全唐诗/poet.song.72000.json','["獨來深樹初啼鳥，幾處高枝已嘒蟬。", "坐久每將棋作隠，晝長還覺日如年。", "醉鄉彭澤陶元亮，句法襄陽孟浩然。", "聚散悲歡皆夢幻，南柯同寄曲肱眠。"]'),
('ea9eda40-70bb-4581-9866-78e6eff1241b','次李元亮韵','洪芻','宋','宋诗','song-poetry','','[]','邂逅何曾十日飲，乖離細數七年遲。',64,'全唐诗/poet.song.72000.json','["邂逅何曾十日飲，乖離細數七年遲。", "酇侯廟下相逢處，揚子橋頭握別時。", "猶喜夫君誦新作，自憐衰病豈能詩。", "平生流水高山意，綠綺朱弦付子期。"]'),
('d51b962a-1095-4e5c-af11-2ffb2cb4a1e4','次李少微韵','洪芻','宋','宋诗','song-poetry','','[]','紫芝眉宇久不見，朅來老眼快雙明。',64,'全唐诗/poet.song.72000.json','["紫芝眉宇久不見，朅來老眼快雙明。", "春光駘蕩遽如許，詩骨崢嶸太瘦生。", "書蠹研埃無復理，鳥啼花落亦關情。", "客兒起我風騷興，敢與羊何並得名。"]'),
('d5d345c9-e96d-4465-8ba0-92dbde9f18db','次顧子美韵','洪芻','宋','宋诗','song-poetry','','[]','幕府優游兼吏隠，華陽真逸詎應慚。',64,'全唐诗/poet.song.72000.json','["幕府優游兼吏隠，華陽真逸詎應慚。", "定知爽氣供行路，怪有新詩成立談。", "晚日碧雲人未至，西風紅樹我何堪。", "幽懷疏豁憑佳詠，飫德餐和飽且酣。"]'),
('a1b11ffe-5fe3-4c97-93a2-af5d54e807f0','次韵謝無逸送謝幼槃','洪芻','宋','宋诗','song-poetry','','[]','康樂風流鴻雁行，眼中文物敢雌黄。',64,'全唐诗/poet.song.72000.json','["康樂風流鴻雁行，眼中文物敢雌黄。", "相逢草草來何暮，索去匆匆作底忙。", "尚卧東山高謝傅，亦憐白首老馮唐。", "只應飲酒稱名士，不用離騷詠九章。"]'),
('e4b443fa-8cb9-4bd2-9f19-7c6ba5203716','題雙桂亭','洪芻','宋','宋诗','song-poetry','','[]','燕賀翬飛稱虎符，銀鈎蠆尾映金鋪。',64,'全唐诗/poet.song.72000.json','["燕賀翬飛稱虎符，銀鈎蠆尾映金鋪。", "訟亭留得棠陰在，月窟遥憐桂影孤。", "故郡每懸高士榻，新居兼愛丈人烏。", "雕磨才思無佳語，可許江山借助無。"]'),
('8e37e08e-6942-4160-b232-fef8f35b7883','將至潁上','洪芻','宋','宋诗','song-poetry','','[]','賣馬得錢買舟去，拋擲紅塵泛綠波。',64,'全唐诗/poet.song.72000.json','["賣馬得錢買舟去，拋擲紅塵泛綠波。", "梨栗登盤黄菊晚，江淮放艇白鷗多。", "霜飛鴻雁有底急，月明烏鵲奈愁何。", "女兒浦口渺何處，且向女郎臺下過。"]'),
('fd00179e-63d0-42ce-a09a-f11bf9365c83','次韵和成道人山中即事二首  其一','洪芻','宋','宋诗','song-poetry','','[]','香城高絕剩春寒，桃李青青一破顔。',64,'全唐诗/poet.song.72000.json','["香城高絕剩春寒，桃李青青一破顔。", "俗子車塵隨水遠，野僧心事與雲閑。", "花從風雨飄零去，寺在烟霄縹緲間。", "往日尋源到幽處，至今猶復夢潺潺。"]'),
('57f6a1ae-8108-4c46-9549-92e63aeeaec6','次韵和成道人山中即事二首  其二','洪芻','宋','宋诗','song-poetry','','[]','沙白澄江江上山，带青百里染層巒。',64,'全唐诗/poet.song.72000.json','["沙白澄江江上山，带青百里染層巒。", "欲尋邱壑何當往，擬掛塵冠不復彈。", "邂逅三春還徑去，軒渠一笑有餘歡。", "郢人妙質應猶在，政爾揮斤斲鼻端。"]'),
('ccac41dd-88c2-4204-ba26-7524699f4c8d','同蘇伯固遊東山寺','洪芻','宋','宋诗','song-poetry','','[]','五里來尋祇樹園，寒蟬嘒嘒葉紛紛。',64,'全唐诗/poet.song.72000.json','["五里來尋祇樹園，寒蟬嘒嘒葉紛紛。", "田間壞衲僧收稻，天外奇峰山作雲。", "半榻華胥聊共寄，一盂香積許同分。", "迎人返照不無意，送客殘鐘猶自聞。"]'),
('0b810be8-01e0-46a6-8849-517c280378f2','遊東禪寺  其一','洪芻','宋','宋诗','song-poetry','','[]','聞說巖隈閟寶坊，後車無客自徜徉。',64,'全唐诗/poet.song.72000.json','["聞說巖隈閟寶坊，後車無客自徜徉。", "人如冬日熏肌暖，句與官梅觸鼻香。", "隨蝶未容尋枕上，觀魚且喜得濠梁。", "夢魂飛過水東去，落日寒山一带長。"]'),
('45f87bbd-47b4-4df0-9ac6-d0e9fddc0057','遊東禪寺  其二','洪芻','宋','宋诗','song-poetry','','[]','野迥亭高眼倍明，悠悠芳草古今情。',64,'全唐诗/poet.song.72000.json','["野迥亭高眼倍明，悠悠芳草古今情。", "酒兼賢聖醒還醉，風有雌雄雨復晴。", "嫩綠連天誰與染，殘紅擲地自無聲。", "岡回溪轉藏巖寺，歸路蕭蕭聽馬鳴。"]'),
('1c4ebf41-a69f-4efa-8879-0022190fc41c','又陪陳使君遊東禪寺  其一','洪芻','宋','宋诗','song-poetry','','[]','暉暉麗日旆悠悠，千騎班春古寺幽。',64,'全唐诗/poet.song.72000.json','["暉暉麗日旆悠悠，千騎班春古寺幽。", "篆破高青知野火，點殘橫綠掠沙鷗。", "微行曲折如羊坂，亂石崢嶸似虎丘。", "暮靄餘霞趣歸興，溪魚林鳥自遲留。"]'),
('54778c8b-728e-44ce-9406-73806c1822bf','又陪陳使君遊東禪寺  其二','洪芻','宋','宋诗','song-poetry','','[]','城裏芳菲盡破除，更携賓從出東郛。',64,'全唐诗/poet.song.72000.json','["城裏芳菲盡破除，更携賓從出東郛。", "桃憑苦雨收紅糝，李借風光耀雪珠。", "碧水橫隄春澹沲，石門弭蓋步踟躕。", "細看名字蒼崖畔，點檢而今半在無。"]'),
('70cf5410-145b-443a-8f75-f4a6e25792c7','雪','洪芻','宋','宋诗','song-poetry','','[]','越犬舊聞冬吠雪，閩天今見雪中梅。',64,'全唐诗/poet.song.72000.json','["越犬舊聞冬吠雪，閩天今見雪中梅。", "朔風掃蕩宿霾盡，苦霧驅除霽色開。", "情共酒盃渾欲淺，心隨爐炭欲成灰。", "我來正落黄茅後，茅未黄時儻得回。"]'),
('ca0e6c9b-fda5-4617-be8f-b3c489b05542','何君挽詞','洪芻','宋','宋诗','song-poetry','','[]','萬里空悲赤壁秋，九原遽有白楊愁。',64,'全唐诗/poet.song.72000.json','["萬里空悲赤壁秋，九原遽有白楊愁。", "鳳毛並作人間瑞，玉潤俱從地下游。", "已躍龍津隨化劍，難憑夜壑覓藏舟。", "遥知會葬車千兩，苦雨蕭蕭迸淚流。"]'),
('10a7521b-fc13-4408-8a8e-4398477e4f94','宴城上亭呈閱道','洪芻','宋','宋诗','song-poetry','','[]','山圍水遶思悠哉，蹔向登臨勝處來。',64,'全唐诗/poet.song.72000.json','["山圍水遶思悠哉，蹔向登臨勝處來。", "密坐已霑神女雨，歸軒更借阿香雷。", "笙歌入耳眉還舞，鄉縣牽情首重回。", "敏捷隨時豈無興，君賢揚子我慚枚。"]'),
('2d93435e-1838-4e53-99d4-3e2a9496c57d','晚宴南禪寺呈使君疊前韵','洪芻','宋','宋诗','song-poetry','','[]','隔年蹔到鶑將老，此日重陪燕始來。',64,'全唐诗/poet.song.72000.json','["隔年蹔到鶑將老，此日重陪燕始來。", "雲傍熊軒飛好雨，山移鼉鼓作輕雷。", "踏青女伴春衫濕，浮白賓筵舞袖回。", "可是玄暉方在郡，尊前能賦愧鄒枚。"]'),
('46b941f7-7864-4e6c-aa5a-0ee53b0ce99f','七夕前二夕同二僧追凉寺門','洪芻','宋','宋诗','song-poetry','','[]','高樓傑閣對岧嶢，滴露流螢夜寂寥。',64,'全唐诗/poet.song.72000.json','["高樓傑閣對岧嶢，滴露流螢夜寂寥。", "剝啄叩門知有興，從容拂榻慰無聊。", "殿藏北斗惟看柄，松礙南山不見椒。", "乘月儻能同步履，杖藜逐我莫辭遥。"]'),
('fae6dbe3-e986-4405-98f2-ed2babc96b82','同師川商老追凉徐賢亭','洪芻','宋','宋诗','song-poetry','','[]','抖擻三年異域塵，還將衰鬢照湖淪。',64,'全唐诗/poet.song.72000.json','["抖擻三年異域塵，還將衰鬢照湖淪。", "田田亂葉如迎客，潑潑跳魚似畏人。", "機事已忘來白鳥，雄風蹔起在青蘋。", "九原埋玉雖千載，追想高懷迹未陳。"]'),
('5e6f866a-00e9-4472-87c2-d13a96b2214d','送師川還龍舒','洪芻','宋','宋诗','song-poetry','','[]','灊嶽西山各滯留，江頭相遇話神州。',64,'全唐诗/poet.song.72000.json','["灊嶽西山各滯留，江頭相遇話神州。", "送君歸去還爲客，破涕成歡轉復愁。", "明日東湖人已散，朝雲南浦水空流。", "郎官好在能乘興，準擬歸驄踏素秋。"]'),
('66b898d8-6625-4bda-9949-2528de620a6d','送李仲特','洪芻','宋','宋诗','song-poetry','','[]','賓客願見韓荆州，部曲猶思郭細侯。',64,'全唐诗/poet.song.72000.json','["賓客願見韓荆州，部曲猶思郭細侯。", "可是孔鸞垂塌翼，行看騏驥踏長楸。", "謝公已蠟登山屐，范蠡難維泛海舟。", "當復睽離還惜別，山中猶得從公遊。"]'),
('b6b25f8a-cafd-4b2c-a52b-02e822edefcb','冬日遊宣巖','洪芻','宋','宋诗','song-poetry','','[]','殺雞爲黍見交情，步屨扶藜向此行。',64,'全唐诗/poet.song.72000.json','["殺雞爲黍見交情，步屨扶藜向此行。", "剖竹取泉來滴瀝，疏巖剔藪到崢嶸。", "一綸涵碧磻溪釣，千穗垂黄谷口耕。", "白水青山應笑我，抗塵走俗媿平生。"]'),
('c57b393a-710c-4e6b-bf2b-199c4daf40c3','次友遊宣巖韵','洪芻','宋','宋诗','song-poetry','','[]','攀躋來借一枝筇，幽討深行極半峰。',64,'全唐诗/poet.song.72000.json','["攀躋來借一枝筇，幽討深行極半峰。", "路側似逢居士屩，歲寒空老大夫松。", "林間突兀森蹲虎，門外坡陀偃卧龍。", "引水作簾真酷似，涓涓初不異秋冬。"]'),
('dcf44d3c-dcb3-403d-874b-1b57fd060605','謝楊崇送酒并口味','洪芻','宋','宋诗','song-poetry','','[]','剝啄扣門驚晝夢，逕知酒客寄新詩。',64,'全唐诗/poet.song.72000.json','["剝啄扣門驚晝夢，逕知酒客寄新詩。", "官醅濃潑鴨頭綠，雕俎香蒸牛尾狸。", "黄雀披綿爲誰好，青州從事與君期。", "真成爛醉頹然卧，兔走烏飛了不知。"]'),
('3aa22616-3717-4b4f-a88a-64ff1cbaaf40','再用前韵答李商老','洪芻','宋','宋诗','song-poetry','','[]','江南暮春鶑亂飛，平章風物憶丘遲。',64,'全唐诗/poet.song.72000.json','["江南暮春鶑亂飛，平章風物憶丘遲。", "蒼苔寂歷荒三徑，綠樹扶疏又一時。", "漢陰丈人少機事，草堂先生能寄詩。", "交親咫尺不相見，汗漫九垓那可期。"]'),
('94f4c3a0-7fac-4f29-92c3-6b69a24f7e87','新樓','洪芻','宋','宋诗','song-poetry','','[]','聞說新樓冠舊名，國人縱觀一城傾。',64,'全唐诗/poet.song.72000.json','["聞說新樓冠舊名，國人縱觀一城傾。", "層甍迥出晴空外，美景還將樂事并。", "潭底魚龍驚倒影，梁間燕雀賀前楹。", "他年秋夜堪乘興，小坐匡床待月生。"]'),
('7def434f-97d9-4fe2-8fa2-1416628493f1','次元禮題余詩卷後韵','洪芻','宋','宋诗','song-poetry','','[]','異域三秋百感生，愁腸一日九回縈。',64,'全唐诗/poet.song.72000.json','["異域三秋百感生，愁腸一日九回縈。", "每聽足音聊粲笑，蹔教覓句解憂酲。", "從來魯衛如兄弟，頗覺何劉謾舅甥。", "勝處欣然真得計，文窮詩瘦祇空名。"]'),
('424789b9-a45f-4ac8-9cd8-c4b1d3cf27e9','次韵徐師川喜余來還之作','洪芻','宋','宋诗','song-poetry','','[]','謫去蹔經牛斗分，歸來重賦豫章行。',64,'全唐诗/poet.song.72000.json','["謫去蹔經牛斗分，歸來重賦豫章行。", "鴒原悽斷手足戚，隴水悲傷甥舅情。", "半世問津今老大，一丘散髮得生平。", "長卿句法鋒難犯，隠若蒙公萬里城。"]'),
('f5f076c4-796e-4c9b-9a2b-b46dec290b85','次曾元禮韵','洪芻','宋','宋诗','song-poetry','','[]','卧龍山下阿蘭若，漠漠烟城楚水西。',64,'全唐诗/poet.song.72000.json','["卧龍山下阿蘭若，漠漠烟城楚水西。", "肯共扶筇同散步，來尋負郭慰卑棲。", "曲肱睡穩門常掩，促膝談深日已低。", "他日相過如卜晝，南窗就我共羹藜。"]'),
('f67bf62e-a4b3-4dc2-8a59-bb6116a40c43','席上次張法曹韵','洪芻','宋','宋诗','song-poetry','','[]','山城臈月盛江梅，底用花奴羯鼓催。',64,'全唐诗/poet.song.72000.json','["山城臈月盛江梅，底用花奴羯鼓催。", "密炬暗隨殘漏盡，冰肌巧鬭一枝開。", "已聞珠貫停檀板，未許葱根近玉盃。", "多謝主人能卜晝，幽花未落更重來。"]'),
('45a6ed0c-f9f6-4dad-9ece-3384983ee274','寄楊崇索酒','洪芻','宋','宋诗','song-poetry','','[]','重九遥思楊執戟，菊花滿地漫龍沙。',64,'全唐诗/poet.song.72000.json','["重九遥思楊執戟，菊花滿地漫龍沙。", "欲作山中醉千日，不送蒲州酒一車。", "秋至苦吟如促織，書成滿紙似昏鴉。", "蜀江儻有南來鯉，莫寄盧仝七椀茶。"]'),
('7d3f9393-f055-43fb-a24d-5bbc9ae61916','宿翠巖寺呈馬彥若徐師川','洪芻','宋','宋诗','song-poetry','','[]','不到翠巖如許久，朅來聊復破春愁。',64,'全唐诗/poet.song.72000.json','["不到翠巖如許久，朅來聊復破春愁。", "已聞高士徐孺子，更約平生馬少游。", "夢裏鐘聲驚客枕，靜中玉子落紋楸。", "非關風雨留連我，要作山間十日留。"]'),
('4523fc09-bd82-449e-9528-00b10c5f3ed0','萬松亭用蘇黄舊韵','洪芻','宋','宋诗','song-poetry','','[]','夾道蒼官似異時，峨峨冠劍想秦儀。',64,'全唐诗/poet.song.72000.json','["夾道蒼官似異時，峨峨冠劍想秦儀。", "雲垂車蓋尋前路，風作濤聲入舊枝。", "故作虬龍驚俗眼，不妨霜雪弄妍姿。", "難追急景遼天鶴，無復當年校尉詩。"]'),
('fa9b582e-235a-4b14-ad28-fd14737b037b','聞東湖上荷花盛開畏觸熱未得往','洪芻','宋','宋诗','song-poetry','','[]','五賢祠下古城隅，一昔來遊儼畫圖。',64,'全唐诗/poet.song.72000.json','["五賢祠下古城隅，一昔來遊儼畫圖。", "傳道荷花映荷葉，只今東湖連北湖。", "想見波間浮屬玉，誰撐艇子入菰蒲。", "欲將鼻觀偷香去，火傘炎官不貸吾。"]'),
('cf5462ab-c081-4631-b94c-ed8bb476fa06','示子','洪芻','宋','宋诗','song-poetry','','[]','太學何蕃久不歸，十年甘旨誤庭闈。',64,'全唐诗/poet.song.72000.json','["太學何蕃久不歸，十年甘旨誤庭闈。", "休辭客路三千遠，須念人生七十稀。", "腰下雖無蘇子印，篋中幸有老萊衣。", "歸期定約春前後，免使高堂賦式微。"]'),
('87b87eb1-8e33-483d-b121-7ed05d8757b7','還張閱道文編','洪芻','宋','宋诗','song-poetry','','[]','只今天下張公子，邂逅論文得琢磨。',64,'全唐诗/poet.song.72000.json','["只今天下張公子，邂逅論文得琢磨。", "顧我筆端無綺麗，愛君胸次粲星羅。", "囁嚅元白何勞壓，卓犖曹劉不啻過。", "魚目碔砆空自愧，敢將光價敵隋和。"]'),
('1f9b20a7-f14f-4cc5-976d-1c02029a0d29','題雲居寺詩','洪芻','宋','宋诗','song-poetry','','[]','雙澗遠輸功德水，四山深閟法王家。',64,'全唐诗/poet.song.72000.json','["雙澗遠輸功德水，四山深閟法王家。", "曲肱聊寄吉祥卧，緩带來嘗安樂茶。", "亦有同行木上座，初無引路鹿銜花。", "孤峰頂上却歸去，回首冥冥雲霧遮。"]'),
('557fc1b0-b05a-45cc-ba3d-82fb4f14bfcc','寄贈王允歎','洪芻','宋','宋诗','song-poetry','','[]','楚俗禨祥古所尤，迎神簫鼓沸香湫。',64,'全唐诗/poet.song.72000.json','["楚俗禨祥古所尤，迎神簫鼓沸香湫。", "真成娶婦諛河伯，亦有韓生笑沐猴。", "毀校可無東里子，斬巫誰是左黄州。", "詎知恤緯非嫠事，白屋何妨肉食謀。"]'),
('afe023ad-32d3-435a-9258-c4cd3322c898','潘子真用慳字韵勸香城人葺陳陶書堂因和之  其一','洪芻','宋','宋诗','song-poetry','','[]','一宿層城飯香積，六年清鏡改朱顔。',64,'全唐诗/poet.song.72000.json','["一宿層城飯香積，六年清鏡改朱顔。", "陳陶仙去書堂壞，羅幙塵生春晝閑。", "每向山頭望城裏，直疑天上非人間。", "可能分我尋常地，抹月批風想不慳。"]'),
('e8b752d8-f697-4399-8352-18a7e6bb512b','潘子真用慳字韵勸香城人葺陳陶書堂因和之  其二','洪芻','宋','宋诗','song-poetry','','[]','泠泠野水翛翛寺，矗矗高峰疊疊巒。',64,'全唐诗/poet.song.72000.json','["泠泠野水翛翛寺，矗矗高峰疊疊巒。", "閑伴禽魚宜石友，靜聞山水奏清彈。", "難招靈觀追陳跡，好在湯休接古歡。", "開士未應文士後，病夫端欲避三端。"]'),
('f6261857-f163-4589-81af-0f4f336dbf89','呈潘延之丈','洪芻','宋','宋诗','song-poetry','','[]','黑頭異日掛冠歸，親植杉松見百圍。',64,'全唐诗/poet.song.72000.json','["黑頭異日掛冠歸，親植杉松見百圍。", "閑過一生從古少，兼全五福似公稀。", "手抄萬卷筆猶健，身倚孤筇行若飛。", "寄語輕鷗莫驚顧，南州高士已忘機。"]'),
('827a0c44-d98c-4187-b90e-ab96e48977f1','呈彥章','洪芻','宋','宋诗','song-poetry','','[]','塞翁失馬吾何有，濠上觀魚每自慚。',64,'全唐诗/poet.song.72000.json','["塞翁失馬吾何有，濠上觀魚每自慚。", "探袖空漫禰衡刺，叩門徑就阿戎談。", "但思濁酒同元亮，底用清談學仲堪。", "回首世間皆苦累，蟻封蝸角戰方酣。"]'),
('1b4d297b-b364-444f-b013-145e83a52927','次韵和南山即事呈使君','洪芻','宋','宋诗','song-poetry','','[]','鳥啼花落奈春何，謾道春光特地多。',64,'全唐诗/poet.song.72000.json','["鳥啼花落奈春何，謾道春光特地多。", "不見餳簫寒食後，暫陪觴詠惠風和。", "竹衫爭醉豐年日，瓦鼓仍聞載路歌。", "五馬來嘶莫愁雨，滿堂冠弁共峨峨。"]'),
('7b8eaca6-1f9e-43ab-bb73-a4fd31c80c04','再用前韵呈閱道','洪芻','宋','宋诗','song-poetry','','[]','抱關擊柝何爲哉，田園將蕪歸去來。',64,'全唐诗/poet.song.72000.json','["抱關擊柝何爲哉，田園將蕪歸去來。", "雄辯接公如豁霧，清狂誚我作顛雷。", "朋歡已許膠投漆，光價無容賜望回。", "欲整羸師聊一戰，知君豈復事鄒枚。"]'),
('c57c9ccd-a79e-496e-b50b-e79dc99903be','次韵和人詠雙葉蓮','洪芻','宋','宋诗','song-poetry','','[]','花盡紅銷子結房，並垂荷葉是何祥。',64,'全唐诗/poet.song.72000.json','["花盡紅銷子結房，並垂荷葉是何祥。", "風吹嫋嫋能浮蓋，雨打田田更發香。", "盪槳可無雙舴艋，照波不羨兩鴛鴦。", "怪來下客詩濤涌，知有騷人爲濫觴。"]'),
('aa73d498-d9ea-4753-953d-8df6d48d83be','飲汪彥章池閣見龍掛','洪芻','宋','宋诗','song-poetry','','[]','避暑追凉許近尋，君家池閣爽煩襟。',64,'全唐诗/poet.song.72000.json','["避暑追凉許近尋，君家池閣爽煩襟。", "密雲不雨龍掛尾，落葉辭風蟬噪林。", "許遠清灣浄如拭，沒多紅芰意能深。", "圍棋爭道未得去，遮莫城頭西日沉。"]'),
('08f36bb1-bb6f-483f-8b5e-73964b4f5f6f','次韵閱道見貽','洪芻','宋','宋诗','song-poetry','','[]','地偏袖舞長沙窄，心遠胸通夢澤寬。',64,'全唐诗/poet.song.72000.json','["地偏袖舞長沙窄，心遠胸通夢澤寬。", "遽失比鄰秋屋靜，稍親燈火夜窗寒。", "乘雲妙在思黄鶴，寫韵遥知有彩鸞。", "四海弟兄傾意氣，鴻妻萊婦有餘歡。"]'),
('37c592eb-6a76-433d-a4af-eb03e2d9c1e5','贈張道聖','洪芻','宋','宋诗','song-poetry','','[]','曲江忠藎藹前修，晚歲差池恨未休。',64,'全唐诗/poet.song.72000.json','["曲江忠藎藹前修，晚歲差池恨未休。", "鼻祖聲名高嶺海，耳孫詩禮尚風流。", "眼中韶石還家夢，客裏西山脫葉秋。", "示我開元餘翰墨，懷賢撫事却成愁。"]'),
('8cc556a5-40f3-4e92-9335-6b68b850f687','同師川至李氏涵虛閣','洪芻','宋','宋诗','song-poetry','','[]','闌暑追凉得佳處，筍輿乘興入蒿蓬。',64,'全唐诗/poet.song.72000.json','["闌暑追凉得佳處，筍輿乘興入蒿蓬。", "乍停西嶺三秋雨，得借東湖一曲風。", "江上帆檣來雉堞，波間荷芰沒鳬翁。", "後車孺子賢孫在，弔古徘徊返照紅。"]'),
('2ab1d3c4-bab2-4a7a-b4a8-2e5d8afa24ff','人日','洪芻','宋','宋诗','song-poetry','','[]','偶逢人日强裁詩，身在異鄉多所思。',64,'全唐诗/poet.song.72000.json','["偶逢人日强裁詩，身在異鄉多所思。", "天氣暖如寒食後，桃花酷似暮春時。", "溪毛入饌光浮筯，雲子新炊滑溜匙。", "斗酒百錢能得醉，儻尋佳處一伸眉。"]'),
('2196976e-efc9-4a3a-9e87-1abae5b35bb6','悠然齋','洪芻','宋','宋诗','song-poetry','','[]','可到羲皇上，不離方丈間。',24,'全唐诗/poet.song.72000.json','["可到羲皇上，不離方丈間。", "初無盈把菊，盡日對南山。"]'),
('4ab5d037-c974-4347-8314-d227e75aeb53','臨川即事  其一','洪芻','宋','宋诗','song-poetry','','[]','峴臺著色山水，南湖罨畫池塘。',28,'全唐诗/poet.song.72000.json','["峴臺著色山水，南湖罨畫池塘。", "欲買浮家泛宅，箇中端坐迷藏。"]'),
('5426c194-cf53-4f33-9f82-4c42fd7e2d45','臨川即事  其二','洪芻','宋','宋诗','song-poetry','','[]','覓句翻經靈運，臨池學書右軍。',28,'全唐诗/poet.song.72000.json','["覓句翻經靈運，臨池學書右軍。", "誰知麻源三谷，頓有一雙玉人。"]'),
('ee4ef6bc-8a77-49cb-a693-7d22036429fc','臨川即事  其三','洪芻','宋','宋诗','song-poetry','','[]','廟有魯公遺像，堂餘玉茗高華。',28,'全唐诗/poet.song.72000.json','["廟有魯公遺像，堂餘玉茗高華。", "零落銀鈎欲折，摩挲螭首興嗟。"]'),
('54796ddc-8a91-41a6-a2ed-b6b2a1900d20','次陳使君韵三首  其一','洪芻','宋','宋诗','song-poetry','','[]','釀雨濃雲鬰不開，絳英素蘂半蒼苔。',32,'全唐诗/poet.song.72000.json','["釀雨濃雲鬰不開，絳英素蘂半蒼苔。", "不因皂蓋班春去，誰喚青衫老吏來。"]'),
('09f8b3c4-ef4e-4028-afce-e38b7103c5a8','次陳使君韵三首  其二','洪芻','宋','宋诗','song-poetry','','[]','循吏三年借寇君，賓筵春事一番新。',32,'全唐诗/poet.song.72000.json','["循吏三年借寇君，賓筵春事一番新。", "中山自可銷千日，河朔寧須泥十旬。"]'),
('c1413951-f1f5-4269-a364-2299f6d8a23f','次陳使君韵三首  其三','洪芻','宋','宋诗','song-poetry','','[]','暖日和風似酒醺，提壺鳥語苦淹人。',32,'全唐诗/poet.song.72000.json','["暖日和風似酒醺，提壺鳥語苦淹人。", "傳聞已有瓜時代，誰與東山管轄春。"]'),
('b0626b4e-43fe-46c9-bd4b-78f20906ff53','道中即事八首  其一','洪芻','宋','宋诗','song-poetry','','[]','五日塵沙十日泥，杜鵑苦勸不如歸。',32,'全唐诗/poet.song.72000.json','["五日塵沙十日泥，杜鵑苦勸不如歸。", "蹔來還去雲相似，我亦無心出岫飛。"]'),
