('ddbbdc24-1854-4685-bddb-b9aab0d27aad','芍藥','洪芻','宋','宋诗','song-poetry','','[]','蠶老桑柔戴勝鳴，翻階芍藥占春榮。',32,'全唐诗/poet.song.72000.json','["蠶老桑柔戴勝鳴，翻階芍藥占春榮。", "牽風孫壽愁眉破，带雨驪姬淚眼橫。"]'),
('fc730169-aded-48ba-ba78-7526ea309999','荔枝','洪芻','宋','宋诗','song-poetry','','[]','仙果移從海上山，露華供夜鶴分丹。',48,'全唐诗/poet.song.72000.json','["仙果移從海上山，露華供夜鶴分丹。", "光射腰金陵寶印，影回殿砌拂猗蘭。", "硃砂芒刺羞紅顆，龍目團圓避赤丸。"]'),
('e6aca422-41b5-4882-8945-6a5a7d35a5da','異蠶吐絲成段','洪芻','宋','宋诗','song-poetry','','[]','公子青衫得意朝，閨門異事喜成謠。',64,'全唐诗/poet.song.72000.json','["公子青衫得意朝，閨門異事喜成謠。", "星河牛女支機石，泉室鮫人暗織綃。", "園客憑虛誇獨繭，冰蠶志怪豈同條。", "細看霞綺驚羣眼，詎減雲裳下九霄。"]'),
('a00c2690-e199-416c-b1a7-8c19230d3074','蝦蟆','洪芻','宋','宋诗','song-poetry','','[]','動物類含血，蝦蟆獨無之。',144,'全唐诗/poet.song.72000.json','["動物類含血，蝦蟆獨無之。", "雙目但瞠也，一腹亦皤其。", "龍變或托體，魚腹睹幽姿。", "罕見三足蟾，詎減六眸龜。", "向來奏贋瑞，背負輪囷芝。", "坐謾皆下吏，膠車等兒嬉。", "雖蒙黄金擲，荆卿空爾爲。", "或以白玉琢，形模妙工倕。", "咄爾百醜質，詎辱五鼎脂。", "浪號土底犧，雄誇水中雞。", "何足汙帝箸，但可充蛇饑。", "作意一池鳴，和我五字詩。"]'),
('559691c4-a035-472c-9153-d910a36bfdcc','上墨工','洪芻','宋','宋诗','song-poetry','','[]','子墨客卿妙一世，懷玉山中五大夫。',32,'全唐诗/poet.song.72000.json','["子墨客卿妙一世，懷玉山中五大夫。", "峨眉老仙與推轂，谷量牛馬斗量珠。"]'),
('7a6629d3-108f-4e2d-bca4-25ae6baf1d37','田家謠','洪芻','宋','宋诗','song-poetry','','[]','鳩婦勃谿農荷鋤，身披襏襫頭茅蒲。',64,'全唐诗/poet.song.72000.json','["鳩婦勃谿農荷鋤，身披襏襫頭茅蒲。", "雨不破塊田坼圖，稊稗青青佳穀枯。", "大婦碓舂頭鬢疏，小婦拾穗行餉姑。", "四時作苦無袴襦，門前叫嗔官索租。"]'),
('fbb607c1-4cf1-4ea3-8e5f-5dbe79ee0906','闕題二首  其一','洪芻','宋','宋诗','song-poetry','','[]','槐下棗花纂纂，麥秋葚子離離。',28,'全唐诗/poet.song.72000.json','["槐下棗花纂纂，麥秋葚子離離。", "不沽十千美酒，難消三百枯棋。"]'),
('d3dd92ef-b5e7-4667-a5b2-fb22ffe434a3','闕題二首  其二','洪芻','宋','宋诗','song-poetry','','[]','兩部池蛙當妓，千山飛鳥催沽。',28,'全唐诗/poet.song.72000.json','["兩部池蛙當妓，千山飛鳥催沽。", "引睡直須黄妳，曲肱正要青奴。"]'),
('8af82598-1c76-442d-b1bd-05842451097d','金陵作','洪芻','宋','宋诗','song-poetry','','[]','沙觜彎環轉柁牙，一衣带水遶城斜。',32,'全唐诗/poet.song.72000.json','["沙觜彎環轉柁牙，一衣带水遶城斜。", "飛廉解使馮夷怒，渡口風吹蕎麥花。"]'),
('da7e99a6-efe3-4408-b9de-ee1cf9daef59','高宗皇帝挽詞  其一','洪芻','宋','宋诗','song-poetry','','[]','寶歷中興業，於今六十年。',48,'全唐诗/poet.song.72000.json','["寶歷中興業，於今六十年。", "洗光暘谷日，鍊補女媧天。", "大業超東漢，皇恩暢北燕。", "聖謨誰可頌，會有筆如椽。"]'),
('fbb29a52-9df6-498e-9fac-9fd849ea296a','高宗皇帝挽詞  其二','洪芻','宋','宋诗','song-poetry','','[]','往在艱難際，乾坤震擾中。',48,'全唐诗/poet.song.72000.json','["往在艱難際，乾坤震擾中。", "京華原有主，趙魏翦爲戎。", "整頓須神武，扶持立雋功。", "配天還祀夏，真與少康同。"]'),
('900a7a41-8718-46c9-a42c-06906b16b1d8','高宗皇帝挽詞  其三','洪芻','宋','宋诗','song-poetry','','[]','紫塞連沙漠，天親墮杳冥。',48,'全唐诗/poet.song.72000.json','["紫塞連沙漠，天親墮杳冥。", "竟能襄水祏，復見養慈寧。", "孝道光千古，精神格上靈。", "典謨垂不盡，赫赫照丹青。"]'),
('17e7f941-5c92-459d-aa5f-0bf2fcb8baf0','高宗皇帝挽詞  其四','洪芻','宋','宋诗','song-poetry','','[]','盛德如何說，由來只是仁。',48,'全唐诗/poet.song.72000.json','["盛德如何說，由來只是仁。", "推心無爾界，摩手爲吾民。", "廣大天同道，高明聖與鄰。", "欲知恩普處，海岳但微塵。"]'),
('f83b37c1-183b-4d51-9b77-1090281a72de','高宗皇帝挽詞  其五','洪芻','宋','宋诗','song-poetry','','[]','禍轉妖氛滅，天催五鼎烹。',48,'全唐诗/poet.song.72000.json','["禍轉妖氛滅，天催五鼎烹。", "只知江飲馬，豈料觀封鯨。", "士感親征詔，神扶義戰兵。", "干戈俄載戢，遺恨不收京。"]'),
('42319496-a69d-496e-855f-42d1481331ec','高宗皇帝挽詞  其六','洪芻','宋','宋诗','song-poetry','','[]','翼善能傳聖，巍巍又見堯。',48,'全唐诗/poet.song.72000.json','["翼善能傳聖，巍巍又見堯。", "纔逾知命歲，已禪拱辰朝。", "玉冊三加峻，瓊宮十閏超。", "大章傳懿鑠，稽古耀宗祧。"]'),
('0cb33d57-18b9-47b8-b775-116c85c253cf','高宗皇帝挽詞  其七','洪芻','宋','宋诗','song-poetry','','[]','聖學由天縱，煌煌翰墨場。',48,'全唐诗/poet.song.72000.json','["聖學由天縱，煌煌翰墨場。", "臣中羞瓘靖，戶外立鍾王。", "飛動鸞窺藻，昭回斗避芒。", "煥文瞻仰處，傑閣在西廂。"]'),
('67724aa0-5787-4310-8ad3-2fe5ee29342f','高宗皇帝挽詞  其八','洪芻','宋','宋诗','song-poetry','','[]','北內神靈地，期期億萬年。',48,'全唐诗/poet.song.72000.json','["北內神靈地，期期億萬年。", "巖廊明聖日，宇宙戴堯天。", "樂事湖山在，英徽雅頌傳。", "那知開玉鎖，不戀地行仙。"]'),
('d9f7502c-bf4c-4b9b-b1b9-80d0fdb99a13','高宗皇帝挽詞  其九','洪芻','宋','宋诗','song-poetry','','[]','鶴馭臨丹極，龍髯墮玉宸。',48,'全唐诗/poet.song.72000.json','["鶴馭臨丹極，龍髯墮玉宸。", "爐烟猶泛夜，宮蕊已迷春。", "夢斷無尋處，神遊不見人。", "傷心天壤內，血淚染車塵。"]'),
('3a136d61-af8f-47af-aad4-58c0ba28f68a','高宗皇帝挽詞  其一○','洪芻','宋','宋诗','song-poetry','','[]','仙仗葳蕤去，行行浙水東。',48,'全唐诗/poet.song.72000.json','["仙仗葳蕤去，行行浙水東。", "稽山元禹穴，吳岫見堯宮。", "帳殿凄寒露，笳城起暝風。", "霓旌不可望，應在彩毫中。"]'),
('6be6e1b5-d815-4bcc-b563-e186ab514d2a','廬山紫霄峰有禹刻石室','洪芻','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','塊視落星石，杯觀彭蠡湖。',36,'全唐诗/poet.song.72000.json','["塊視落星石，杯觀彭蠡湖。", "荒哉秦漢君，抗旌上崎嶇。", "永懷太史公，九江觀禹摹。"]'),
('929bfcf4-e84b-496b-9864-d68c0f11749a','學韓退之體賦蝦蟆一篇','洪芻','宋','宋诗','song-poetry','','[]','吾廬逼沮洳，蛙蛤宗生之。',192,'全唐诗/poet.song.72000.json','["吾廬逼沮洳，蛙蛤宗生之。", "委委見蝌蚪，閣閣已在茲。", "夜聲一何喧，達旦乃寖微。", "月令紀螻蟈，語默亦有時。", "豈伊不平鳴，沓沓竟何爲。", "那復當鼓吹，安能問官私。", "吾聞崑崙下，厥大數十圍。", "蟾蜍窟望舒，色勝金褭蹄。", "癡騃反食月，吞吐誰能知。", "坎井我自足，跳梁而持頤。", "鼈笑色無慍，鶉化理莫推。", "疥體不自惜，或以調鹽醯。", "柳州味南烹，下筯甘若飴。", "在昔薦宗廟，乃與羔兔齊。", "擅減幾被坐，巨細不可遺。", "莫以腥臊棄，終將瑚璉期。"]'),
('3e5a6309-a604-422a-9cc3-0b1017c40fc6','藏之和予蝦蟆短調再作之因以策事','洪芻','宋','宋诗','song-poetry','','[]','蝦蟆何爲者，痱磊盎於背。',156,'全唐诗/poet.song.72000.json','["蝦蟆何爲者，痱磊盎於背。", "人言懷土蟲，棄去俄復在。", "昔有係青繒，酉陽志其怪。", "嘗觀三物圖，副以蝍蛆带。", "相持莫先動，含毒相屠膾。", "端欲兄龜龍，未肯弟孔翠。", "俳語解人頤，子陽妄尊大。", "慎勿離窟穴，旁午元五輩。", "東行犯日忌，束縛非其罪。", "倘有切玉刀，甘心脂鼎鼐。", "平生不下筯，實憚背脊疥。", "何必食馬肝，前修有明戒。", "願君勿嘲誚，微命其可貸。"]'),
('d5b765c0-325d-4eec-983e-ed971fa80f93','雪','洪芻','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','撩人縢六索題詩，頼有支郎爲解圍。',64,'全唐诗/poet.song.72000.json','["撩人縢六索題詩，頼有支郎爲解圍。", "永夜祇宜燋兔好，彤雲不見織烏飛。", "少林未許齊腰立，青女無端接手歸。", "想得廬山幽絕處，洒林壓竹更增輝。"]'),
('ecfe074e-9857-4674-8754-cf3ffec3a46f','田家謠','洪芻','宋','宋诗','song-poetry','','["\u5fe7\u56fd\u5fe7\u6c11", "\u8bbd\u523a"]','父耕原上田，子斸山下荒。',24,'全唐诗/poet.song.72000.json','["父耕原上田，子斸山下荒。", "六月一禾生，官家一開倉。"]'),
('b3b1a1a5-0abf-48a0-924d-4f50b0d84307','登文殊臺','洪芻','宋','宋诗','song-poetry','','[]','壯哉文殊臺，俯瞰落星灣。',36,'全唐诗/poet.song.72000.json','["壯哉文殊臺，俯瞰落星灣。", "雙劍倚天外，一柱切雲端。", "未窮黄石巖，但逢赤眼禪。"]'),
('ac46a085-a102-41af-89f0-ce4995d0b8c0','泊女兒浦','洪芻','宋','宋诗','song-poetry','','[]','大孤山下兩牛鳴，女兒浦口一葦橫。',32,'全唐诗/poet.song.72000.json','["大孤山下兩牛鳴，女兒浦口一葦橫。", "已隔雲烟五老面，猶夢雷霆三峽聲。"]'),
('837028a8-a4c4-464a-926e-1ab0fe575000','青原臺','洪芻','宋','宋诗','song-poetry','','[]','高臺梯空上雲烟，宴坐城郭窺山川。',40,'全唐诗/poet.song.72000.json','["高臺梯空上雲烟，宴坐城郭窺山川。", "鳬汀鶴渚江在前，青原入望山蒼然，驀波輕泛一葉船。"]'),
('dbf45f8b-25a7-4ed9-ab46-6e9eabac1311','詠河豚西施乳','洪芻','宋','宋诗','song-poetry','','[]','蔞蒿短短狄芽肥，正是河豚欲上時。',32,'全唐诗/poet.song.72000.json','["蔞蒿短短狄芽肥，正是河豚欲上時。", "甘美遠勝西子乳，吳王當日未曾知。"]'),
('72f9cc18-ee73-4e2a-bb8a-0f3c0067e02e','句  其一','洪芻','宋','宋诗','song-poetry','','[]','眼中人物東西盡，肺病京華故倦遊。',16,'全唐诗/poet.song.72000.json','["眼中人物東西盡，肺病京華故倦遊。"]'),
('cdbb72df-89bd-4477-b168-51719b9fcff8','句  其二','洪芻','宋','宋诗','song-poetry','','[]','鹿場兔徑白晝靜，稻壟松竹青嶂深。',16,'全唐诗/poet.song.72000.json','["鹿場兔徑白晝靜，稻壟松竹青嶂深。"]'),
('6b3654f3-6c5c-45e1-ac39-19f88482223d','句  其三','洪芻','宋','宋诗','song-poetry','','[]','關山不隔還鄉夢，風月猶隨過海身。',16,'全唐诗/poet.song.72000.json','["關山不隔還鄉夢，風月猶隨過海身。"]'),
('c915a37f-93df-488f-abed-adc0f73da599','句  其四','洪芻','宋','宋诗','song-poetry','','[]','何如喚取陸鴻漸，石鼎風爐來試茶。',16,'全唐诗/poet.song.72000.json','["何如喚取陸鴻漸，石鼎風爐來試茶。"]'),
('21ac9a05-2a0a-42c9-805d-5157fc181dfd','句  其五','洪芻','宋','宋诗','song-poetry','','[]','誰折可憐花，置我經行處。',12,'全唐诗/poet.song.72000.json','["誰折可憐花，置我經行處。"]'),
('6a8a95a3-200f-4617-9893-062b545c3366','句  其六','洪芻','宋','宋诗','song-poetry','','[]','但使添丁長，終興謝客家。',12,'全唐诗/poet.song.72000.json','["但使添丁長，終興謝客家。"]'),
('a6c523d8-0307-4003-a0ac-34f2eec52f40','句  其七','洪芻','宋','宋诗','song-poetry','','[]','爰有福地直斗牛，厥名閤皁形色收。',16,'全唐诗/poet.song.72000.json','["爰有福地直斗牛，厥名閤皁形色收。"]'),
('b84b15da-0907-4e7b-81e9-10c9af2b178b','句  其八','洪芻','宋','宋诗','song-poetry','','[]','清都瓊葉霏霏下，凈界空花種種開。',16,'全唐诗/poet.song.72000.json','["清都瓊葉霏霏下，凈界空花種種開。"]'),
('2a4e9155-888f-4e45-92cc-951a2e2b752f','句  其九','洪芻','宋','宋诗','song-poetry','','[]','偏隨江月橫陳夜，未放官梅獨自春。',16,'全唐诗/poet.song.72000.json','["偏隨江月橫陳夜，未放官梅獨自春。"]'),
('dcbb8637-8bd9-48b9-bb0b-392413e1ed8a','句  其一○','洪芻','宋','宋诗','song-poetry','','[]','霜後木奴香噀手，秋來雲子滑流匙。',16,'全唐诗/poet.song.72000.json','["霜後木奴香噀手，秋來雲子滑流匙。"]'),
('9416166a-8d0d-4ce3-8271-76c86d9edc00','句  其一一','洪芻','宋','宋诗','song-poetry','','[]','題詩未有隨州句，敢喚阮郎爲老兵。',16,'全唐诗/poet.song.72000.json','["題詩未有隨州句，敢喚阮郎爲老兵。"]'),
('12fed4d6-72e2-4db1-b4d7-4ecbc6980781','句  其一二','洪芻','宋','宋诗','song-poetry','','[]','龍沙依舊抱城流。',8,'全唐诗/poet.song.72000.json','["龍沙依舊抱城流。"]'),
('0c1ae4a2-5990-474d-9b13-b455de60658e','句  其一三','洪芻','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山排闥參差見，湓水縈城屈曲來。',16,'全唐诗/poet.song.72000.json','["廬山排闥參差見，湓水縈城屈曲來。"]'),
('4dce9b80-4e4c-42f2-a0cd-f5e1550273ab','句  其一四','洪芻','宋','宋诗','song-poetry','','[]','晉代衣冠復誰在，虎溪長有白蓮風。',16,'全唐诗/poet.song.72000.json','["晉代衣冠復誰在，虎溪長有白蓮風。"]'),
('7b5c78e5-4fb7-40cc-8cb7-2efe92f604b6','句  其一五','洪芻','宋','宋诗','song-poetry','','[]','摩挲道傍醉石，定是天邊酒星。',14,'全唐诗/poet.song.72000.json','["摩挲道傍醉石，定是天邊酒星。"]'),
('8c6c9253-557e-4af6-8a29-5e9eb36eb520','句  其一六','洪芻','宋','宋诗','song-poetry','','[]','秀水一篙通。',6,'全唐诗/poet.song.72000.json','["秀水一篙通。"]'),
