('ff09a0f7-c416-4875-88af-1b2781d87c40','句  其一八','洪芻','宋','宋诗','song-poetry','','[]','深秋轉覺山形瘦，新雨能添水面肥。',16,'全唐诗/poet.song.72000.json','["深秋轉覺山形瘦，新雨能添水面肥。"]'),
('80444631-a41f-4531-a03c-691b8778c3e3','梧州','蕭磐','宋','宋诗','song-poetry','','[]','吟拾江邊金翠羽，醉騎海上玉麟腰。',32,'全唐诗/poet.song.72000.json','["吟拾江邊金翠羽，醉騎海上玉麟腰。", "清談試茗遊冰井，至樂觀魚坐鑑橋。"]'),
('c7f259ff-1b45-4a67-b934-32469310362d','冰井','蕭磐','宋','宋诗','song-poetry','','[]','冰井曷無水，爲與火山對。',288,'全唐诗/poet.song.72000.json','["冰井曷無水，爲與火山對。", "真宰福梧人，命名適相配。", "炎炎火之性，所至能爲害。", "冰焉壓其氣，轉否還高泰。", "祥光每發時，州人同福賚。", "乃至井若冰，其義故有在。", "我來酌冰井，其美同沆瀣。", "初疑蓬島脈，又雅林泉派。", "井竇倘依然，古基盡亡昧。", "半爲土烟沒，半爲石缺壞。", "于時初下車，未暇整頹潰。", "州城百舍敝，締創豈容怠。", "舊者爲之新，露者爲之蓋。", "卑污易以高，狹小易以大。", "於公無所侵，於私無所貸。", "一誠與規畫，黽勉及三載。", "始來想井基，指示經數輩。", "引繩取其直，立標正其界。", "開鑿三尺餘，適與古基會。", "西偏甃堅完，界不差井怪。", "三隅彷彿見，磚師且徐綴。", "此井信有神，州人亦嗟怪。", "井前爲開池，引水成溝澮。", "所防三伏天，飲者成羣隊。"]'),
('fdd4eff0-b7be-4efb-99c2-780c13bee477','黄華姑巖','黄符','宋','宋诗','song-poetry','','[]','鐵色陰崖積石屯，玉顔窈窕鎮崑崙。',64,'全唐诗/poet.song.72000.json','["鐵色陰崖積石屯，玉顔窈窕鎮崑崙。", "上池降液行靈響，左角承雲出曉暾。", "手抉風雷穿月窟，坐當星斗直天門。", "昔人政有懷仙地，爲挹清泉注一尊。"]'),
('9fb73d82-28d3-440b-80ae-a6cc780573c1','句','蔡居厚','宋','宋诗','song-poetry','','[]','先生萬古有何用，博士三年冗不治。',16,'全唐诗/poet.song.72000.json','["先生萬古有何用，博士三年冗不治。"]'),
('b54e450a-3ef8-498a-a2bb-06f891eabb04','聞伯育承事結綵舟作樂遊東湖戲寄四韵','林迪','宋','宋诗','song-poetry','','[]','湖波測測浸殘春，東郭開筵迥不群。',64,'全唐诗/poet.song.72000.json','["湖波測測浸殘春，東郭開筵迥不群。", "聞結綵舟撐碧落，更携簫鼓度青雲。", "自憐玉海終無敵，却憶瓊漿意未分。", "珠履難陪空悵望，且憑詩句張吾軍。"]'),
('5a22d08f-3f02-4b71-a36f-d3f6ab212a52','次前韵','林迪','宋','宋诗','song-poetry','','[]','東陳君義欲傳聞，雕鶚鸞凰果逸群。',64,'全唐诗/poet.song.72000.json','["東陳君義欲傳聞，雕鶚鸞凰果逸群。", "青竹題詩才倚馬，畫船槌鼓氣凌雲。", "賞心自向明時得，樂事應容下客分。", "敵飲會須翻玉海，背河决勝看齊軍。"]'),
('4a815237-156e-44b5-ac5d-03e9f6683da1','東湖  其一','林迪','宋','宋诗','song-poetry','','[]','門巷深深過客稀，杖藜閑坐釣魚磯。',32,'全唐诗/poet.song.72000.json','["門巷深深過客稀，杖藜閑坐釣魚磯。", "醉來一枕華胥夢，肯校人間是與非。"]'),
('d58fe5ad-3ca6-4f36-bd57-4403f5885612','東湖  其二','林迪','宋','宋诗','song-poetry','','[]','崎嶇世路苦風波，物外逍遥得趣多。',32,'全唐诗/poet.song.72000.json','["崎嶇世路苦風波，物外逍遥得趣多。", "門掩夕陽新睡覺，數聲時度采菱歌。"]'),
('24e5f904-1797-4845-8173-068040263ad8','東湖  其三','林迪','宋','宋诗','song-poetry','','[]','林梢乍過黄梅雨，湖面閑來白晝風。',32,'全唐诗/poet.song.72000.json','["林梢乍過黄梅雨，湖面閑來白晝風。", "六月遊人不知暑，恍驚身在水晶宮。"]'),
('105efb0d-48f8-44b3-82ec-3cce2187aeaa','東湖  其四','林迪','宋','宋诗','song-poetry','','[]','一曲清歌酒一觴，幅巾林下興何長。',32,'全唐诗/poet.song.72000.json','["一曲清歌酒一觴，幅巾林下興何長。", "沙鷗似覺忘機久，時引新雛過短牆。"]'),
('094b113a-eb6a-4212-b887-7f9d790bbbe3','東湖  其五','林迪','宋','宋诗','song-poetry','','[]','高下人家繞郡城，隔湖遥認笑談聲。',32,'全唐诗/poet.song.72000.json','["高下人家繞郡城，隔湖遥認笑談聲。", "黄庭閱罷無餘事，却倚朱欄看月生。"]'),
('a6edbe2b-a00f-4d60-b6e4-defc27c8bf6b','東湖  其六','林迪','宋','宋诗','song-poetry','','[]','採蓮遊女愜輕衣，爭弄蘭舟一葉飛。',32,'全唐诗/poet.song.72000.json','["採蓮遊女愜輕衣，爭弄蘭舟一葉飛。", "過盡綠荷人不見，夜深時带月明歸。"]'),
('19d8e9ae-48c4-48a7-8d10-a11acb28ed61','東湖  其七','林迪','宋','宋诗','song-poetry','','[]','詩壇棋戰兩無雙，分得壺中日月長。',32,'全唐诗/poet.song.72000.json','["詩壇棋戰兩無雙，分得壺中日月長。", "只恐明時搜隠逸，不容高蹈老滄浪。"]'),
('363d15bc-61c2-438a-ac44-79c655ff8e90','又題阮希聖東湖十絕  其一','林迪','宋','宋诗','song-poetry','','[]','群山高下浸湖溽，暝靄朝霞物物新。',32,'全唐诗/poet.song.72000.json','["群山高下浸湖溽，暝靄朝霞物物新。", "驛道更穿東北去，青銅影裏看行人。"]'),
('1c8f92b7-5274-4787-adf5-2ae2b3f5bf05','又題阮希聖東湖十絕  其二','林迪','宋','宋诗','song-poetry','','[]','東湖水似鑑湖明，紅白蓮花自在生。',32,'全唐诗/poet.song.72000.json','["東湖水似鑑湖明，紅白蓮花自在生。", "祇有香風吹客坐，更無煩暑到簷楹。"]'),
('f1b45ea7-0a8c-4c25-8851-3b86ee61f103','又題阮希聖東湖十絕  其三','林迪','宋','宋诗','song-poetry','','[]','軒窗特地向湖開，要客登臨共一杯。',32,'全唐诗/poet.song.72000.json','["軒窗特地向湖開，要客登臨共一杯。", "白鳥探魚常不去，清風吹水等閑來。"]'),
('407e4d82-b280-4e56-bd9b-ffd56bcd8a87','又題阮希聖東湖十絕  其四','林迪','宋','宋诗','song-poetry','','[]','一軒正在碧湖傍，蓮子枯時荇菜香。',32,'全唐诗/poet.song.72000.json','["一軒正在碧湖傍，蓮子枯時荇菜香。", "最愛夜深鷗鷺散，釣船明月似瀟湘。"]'),
('77010656-fc25-4e7a-9985-cc496d02f872','又題阮希聖東湖十絕  其五','林迪','宋','宋诗','song-poetry','','[]','門外青山几案橫，卷簾幽坐少逢迎。',32,'全唐诗/poet.song.72000.json','["門外青山几案橫，卷簾幽坐少逢迎。", "一鈎香餌看魚上，萬頃金波待月生。"]'),
('8de0cc34-9a04-4305-9454-fb54598f30da','又題阮希聖東湖十絕  其六','林迪','宋','宋诗','song-poetry','','[]','一湖綠水當窗靜，百里青山卷箔開。',32,'全唐诗/poet.song.72000.json','["一湖綠水當窗靜，百里青山卷箔開。", "只恐夕陽催客去，不妨幽鳥趁人來。"]'),
('43bcd517-0577-401c-bfa6-647d8659cbcd','又題阮希聖東湖十絕  其七','林迪','宋','宋诗','song-poetry','','[]','一炷沉烟一案書，憐君重葺紫雲居。',32,'全唐诗/poet.song.72000.json','["一炷沉烟一案書，憐君重葺紫雲居。", "溪山朝暮能新美，世事塵緣併掃除。"]'),
('3477d829-ad79-46b0-bc55-64ab16c369ec','又題阮希聖東湖十絕  其八','林迪','宋','宋诗','song-poetry','','[]','鋤去蒿萊地勢平，開軒瀟洒瞰東城。',32,'全唐诗/poet.song.72000.json','["鋤去蒿萊地勢平，開軒瀟洒瞰東城。", "湖山變盡朝昏景，只欠青猿一兩聲。"]'),
('2e7a8984-df1b-46fc-bc02-a886da170c8b','又題阮希聖東湖十絕  其九','林迪','宋','宋诗','song-poetry','','[]','誰知城郭有山林，選勝營居遣壯心。',32,'全唐诗/poet.song.72000.json','["誰知城郭有山林，選勝營居遣壯心。", "一片遠烟添暮色，數聲歸鳥變春音。"]'),
('3b411070-18e0-4c89-87f3-10401d3a3342','又題阮希聖東湖十絕  其一○','林迪','宋','宋诗','song-poetry','','[]','仙亭射的鬭崔嵬，紫翠飄飄落酒杯。',32,'全唐诗/poet.song.72000.json','["仙亭射的鬭崔嵬，紫翠飄飄落酒杯。", "更待春陰須一往，要看雷雨過湖來。"]'),
('91a6df15-a280-4a07-b9a6-3a9bc1e25441','句  其一','林迪','宋','宋诗','song-poetry','','[]','爲種不同攢核李，過牆便作小陳紫。',16,'全唐诗/poet.song.72000.json','["爲種不同攢核李，過牆便作小陳紫。"]'),
('55128f4d-dbbf-4993-aa98-1582058a6f35','句  其二','林迪','宋','宋诗','song-poetry','','[]','寂寂峰巒千古意，溶溶花木一家春。',16,'全唐诗/poet.song.72000.json','["寂寂峰巒千古意，溶溶花木一家春。"]'),
('b2e1fe48-281c-4ade-b06a-1189dca62fdc','和（于巽）祗謁真祠詩','何賁','宋','宋诗','song-poetry','','[]','清晨雪霽出東城，躬款靈祠致克誠。',64,'全唐诗/poet.song.72000.json','["清晨雪霽出東城，躬款靈祠致克誠。", "百品果蔬供薦獻，萬人簫鼓賀昇平。", "暉暉曉日明臺殿，獵獵霜風滿旆旌。", "碧瓦脩廊盡宏麗，亦從民欲落新成。"]'),
('a78fb21b-ab03-417f-a111-6a6e10d4ceb7','題劉資仁韓幹飲馬圖','趙暘','宋','宋诗','song-poetry','','[]','韓幹所畫天閑圖，縣官日給三品芻。',96,'全唐诗/poet.song.72000.json','["韓幹所畫天閑圖，縣官日給三品芻。", "不嘶不鳴肥如鳬，時時步作康莊衢。", "飲之曲江戲短蕪，沙軟風輕樂于于。", "豈知渥洼真龍駒，垂頭戢耳困鹽車。", "圉人太僕反歔歈，瘦骨硉矹甘爲駑。", "不須驤首顧長途，局促驥足何時無。"]'),
('077aa780-92a3-40a7-b43c-def3a8016d0b','奉和姚仲美臘梅','趙暘','宋','宋诗','song-poetry','','[]','陽和都未見芳菲，初喜寒苞發故枝。',64,'全唐诗/poet.song.72000.json','["陽和都未見芳菲，初喜寒苞發故枝。", "絕色夐無朱粉態，真香寧許燕鶑知。", "凝愁金谷登樓日，斂黛溫泉賜浴時。", "寫作新聲傳玉笛，誰人持向月中吹。"]'),
('381a7fab-93a4-4319-9888-537ec2dca3f6','句','趙暘','宋','宋诗','song-poetry','','[]','至尊仄席思耆舊。',8,'全唐诗/poet.song.72000.json','["至尊仄席思耆舊。"]'),
('e77d9e4c-8e4b-4403-8878-609ff1ca58c8','芝山梅仙洞','劉綰','宋','宋诗','song-poetry','','[]','傳聞梅子真，入山歌采芝。',72,'全唐诗/poet.song.72000.json','["傳聞梅子真，入山歌采芝。", "蟬蛻升紫霧，靈蹤使人思。", "驂鸞不復返，蔓草空離披。", "高風自百世，非假神仙師。", "人生不朽業，大節在無虧。", "服食求沖舉，虛無恐難期。"]'),
('6a823466-b606-4c4c-b476-7726854e8c69','寒食','陳元老','宋','宋诗','song-poetry','','[]','至後百五日，春光無火晨。',48,'全唐诗/poet.song.72000.json','["至後百五日，春光無火晨。", "金鈿沽酒妾，羅襪弄毬人。", "鶑語如留意，花枝不賣貧。", "東園舊桃李，紅白盡成塵。"]'),
('5f56acde-1068-4598-92a8-145df5ad4052','登科','陳元老','宋','宋诗','song-poetry','','[]','引領羣仙上紫微，雲間相逐步相隨。',64,'全唐诗/poet.song.72000.json','["引領羣仙上紫微，雲間相逐步相隨。", "桃花直透三層浪，桂子高攀第一枝。", "閬苑更無前驟馬，杏園都是後題詩。", "男兒顯達當如此，滿袖馨香天下知。"]'),
('c5daefef-d454-42eb-81cd-b6251a052f89','道士','陳元老','宋','宋诗','song-poetry','','[]','頭戴鹿胎皮，身披鶴氅衣。',24,'全唐诗/poet.song.72000.json','["頭戴鹿胎皮，身披鶴氅衣。", "月寒丹井立，霜白醮壇歸。"]'),
('fffab2a5-b011-4700-b997-6982f64ec469','徐真君祠堂東西二室次許將韵','陳暘','宋','宋诗','song-poetry','','[]','六題曾徹九重門，暫阻堯階奏萬言。',32,'全唐诗/poet.song.72000.json','["六題曾徹九重門，暫阻堯階奏萬言。", "今日又蒙師許我，漢廷當沛異常恩。"]'),
('247d0ca1-a8e9-43be-95af-0ccc94e1beec','趙真君巖','陳暘','宋','宋诗','song-poetry','','[]','巖頂風雲常不散，洞門日日吐烟霞。',32,'全唐诗/poet.song.72000.json','["巖頂風雲常不散，洞門日日吐烟霞。", "濟時偏解爲霖雨，信是神仙第一家。"]'),
('e86b40a8-bd32-4fe3-8eb0-284337ba0eac','南臺沙合亭','陳暘','宋','宋诗','song-poetry','','[]','閩州勝概是南臺，沙合相傳有自來。',32,'全唐诗/poet.song.72000.json','["閩州勝概是南臺，沙合相傳有自來。", "一道三橋橫渡處，分明平步揖天台。"]'),
('78f75fc8-743a-4d73-a40f-5cd9d7613140','缺題','陳暘','宋','宋诗','song-poetry','','[]','行藝當年帝所聞，聲名久矣動簪紳。',64,'全唐诗/poet.song.72000.json','["行藝當年帝所聞，聲名久矣動簪紳。", "文場秉筆淵源厚，詩席談經業履醇。", "白髮忽驚蒿里暮，青衫難問箬溪春。", "兩京模範垂芳遠，多少生徒淚滿巾。"]'),
('82f3af85-4e6f-4d5b-a93a-884c301ad39d','句  其一','陳暘','宋','宋诗','song-poetry','','[]','地噴飛泉成雨露，根盤喬木列旌麾。',16,'全唐诗/poet.song.72000.json','["地噴飛泉成雨露，根盤喬木列旌麾。"]'),
('50a9d848-bea2-4b01-8561-3597dea35040','句  其二','陳暘','宋','宋诗','song-poetry','','[]','南臺沙合半成洲，千尺虹橋橄欖舟。',16,'全唐诗/poet.song.72000.json','["南臺沙合半成洲，千尺虹橋橄欖舟。"]'),
('7c827ba5-2f19-47c5-ba15-1984d7718f8b','題靈巖寺','蔡安持','宋','宋诗','song-poetry','','[]','四絕之中劇最先，山圍宮殿鎖雲烟。',32,'全唐诗/poet.song.72000.json','["四絕之中劇最先，山圍宮殿鎖雲烟。", "當年鶴馭歸何處，世上猶傳錫杖泉。"]'),
('ad311c51-cd43-46c8-b1d4-695f4582a7d3','靈巖','蔡安持','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','岱宗分秀萃靈巖，殿閣崢嶸疊嶂間。',64,'全唐诗/poet.song.72000.json','["岱宗分秀萃靈巖，殿閣崢嶸疊嶂間。", "師感青蛇尋勝地，泉因白鶴貢禪關。", "松梯十里藏歸路，僧梵千聲響夜山。", "暫脫塵纓聊息駕，未容心逐片雲閒。"]'),
('9c181554-a626-4dc3-a9dc-17781cf1c6f1','和洪朋','饒次守','宋','宋诗','song-poetry','','[]','當時爲舉首，滿意望龍飛。',21,'全唐诗/poet.song.72000.json','["當時爲舉首，滿意望龍飛。", "而今已報罷，且歸。"]'),
('4db2b59f-14ed-40b9-ae66-67a5a36f510a','八百石洞','胡僧孺','宋','宋诗','song-poetry','','[]','八百遺蹤石室存，神仙杳邈事難論。',64,'全唐诗/poet.song.72000.json','["八百遺蹤石室存，神仙杳邈事難論。", "雲浮絕頂人常見，龍起深潭晝亦昏。", "信有林泉閒日月，好將名利付乾坤。", "他年棲隠山疇下，咫尺烟蘿再可捫。"]'),
('c192a415-d990-4faf-9739-f66f6ffe1e00','和邑宰韵','江贄','宋','宋诗','song-poetry','','[]','一室蕭然傍水灣，自知窮達不相關。',64,'全唐诗/poet.song.72000.json','["一室蕭然傍水灣，自知窮達不相關。", "釣魚溪遶黄沙路，種粟原通白馬山。", "有命幸逢天子詔，無才休望嗇夫輪。", "佳篇勸奬非吾事，已許巢由厠有班。"]'),
('8d6d7250-30ab-4125-9126-ce58c28ef4a3','植竹吏隠堂後因題  其一','許安仁','宋','宋诗','song-poetry','','[]','斸破中庭一畝苔，主人髮白手親栽。',32,'全唐诗/poet.song.72000.json','["斸破中庭一畝苔，主人髮白手親栽。", "即今誰識清真節，須向三冬雪後來。"]'),
('e4c250eb-32fb-498a-88da-410397fffd1a','植竹吏隠堂後因題  其二','許安仁','宋','宋诗','song-poetry','','[]','珍重勞君慰遠遊，繁聲疏影一堂秋。',32,'全唐诗/poet.song.72000.json','["珍重勞君慰遠遊，繁聲疏影一堂秋。", "主人看即官期滿，分付風烟與子猷。"]'),
('2e0e2211-bacf-4f04-92e8-b995482d65b4','和御製宮詞','許安仁','宋','宋诗','song-poetry','','[]','輕寒慘慘透衾羅，玉箭銅壺漏水多。',32,'全唐诗/poet.song.72000.json','["輕寒慘慘透衾羅，玉箭銅壺漏水多。", "常是未明供御服，夢回頻問夜如何。"]'),
('6c9caa93-5792-4c1c-b9f2-8a6136bc7f4a','夢中作','許安仁','宋','宋诗','song-poetry','','[]','山色濃如滴，湖光平如席。',24,'全唐诗/poet.song.72000.json','["山色濃如滴，湖光平如席。", "風月不相識，相逢便相得。"]'),
('412729fc-c956-441b-a9b5-d6c54a3cf4a3','題善山院','許安仁','宋','宋诗','song-poetry','','[]','瓦爐柏子裊殘烟，午夢醒時一暢然。',32,'全唐诗/poet.song.72000.json','["瓦爐柏子裊殘烟，午夢醒時一暢然。", "不悟功名負終老，荒山饑走又三年。"]'),
('8d48bb8b-255c-4885-93ef-ef08106e3185','和郡守劉巨濟重開石門洞','朱筠','宋','宋诗','song-poetry','','[]','謝公箕潁流，特擬耽幽棲。',120,'全唐诗/poet.song.72000.json','["謝公箕潁流，特擬耽幽棲。", "蠟屐得洞天，雙鶴頫清溪。", "擬追玄圃遊，對此爲階基。", "披榛剪蘿蔦，宿霧暝欲迷。", "方當誇高標，焉能分徑蹊。", "鬼物諒奪氣，幽禽亦驚啼。", "卓哉曠世懷，心與境不携。", "俯視囂塵中，榮枯猶稗夷。", "孰知東海偏，秦鞭預排驅。", "付與破荒手，從此凌丹梯。"]'),
('2a3c186b-2350-47dd-b12a-b2c127edc197','答琅琊問無位真人偈','俞道婆','宋','宋诗','song-poetry','','[]','有一無位人，六臂三頭努力嗔。',30,'全唐诗/poet.song.72000.json','["有一無位人，六臂三頭努力嗔。", "一擘華山分兩路，萬年流水不知春。"]'),
('b0b200ce-a96d-48bd-a1ed-ed613bb545ce','馬祖不安因緣頌','俞道婆','宋','宋诗','song-poetry','','[]','日面月面，虛空閃電。',29,'全唐诗/poet.song.72000.json','["日面月面，虛空閃電。", "雖然截斷天下衲僧舌頭，分明祇道得一半。"]'),
('38be2007-8676-4c04-b982-0327e7ceff4d','婆子偷趙州筍因緣頌','俞道婆','宋','宋诗','song-poetry','','[]','虎穴魔宮到者稀，老婆失脚又懷疑。',32,'全唐诗/poet.song.72000.json','["虎穴魔宮到者稀，老婆失脚又懷疑。", "趙州喫掌無人會，直至如今成是非。"]'),
